window.ADRIVE_THEME_DATA=window.ADRIVE_THEME_DATA||{};window.ADRIVE_THEME_DATA[2]=[{"id":200100101,"themeId":2,"group":2001001,"chapter":76,"chapters":[76],"q":"Как должен поступить водитель, если на участке дороги значения дорожных знаков противоречат друг другу?","a":["Не обращать внимания на требования таких знаков.","Сообщить об этом в ближайшее отделение ГАИ или дорожную службу.","Определить, какие из дорожных знаков являются временными, и руководствоваться временными знаками."],"c":2,"e":"<p>Когда значения временных и постоянных дорожных знаков противоречат друг другу, участники дорожного движения должны руководствоваться временными знаками.</p>","image":"assets/adrive-questions/q200100101.webp"},{"id":200100102,"themeId":2,"group":2001001,"chapter":76,"chapters":[76],"q":"Как должен поступить водитель, если на участке дороги значения временных и постоянных дорожных знаков противоречат друг другу?","a":["Руководствоваться требованиями постоянных знаков.","Руководствоваться требованиями временных знаков.","Руководствоваться только горизонтальной и вертикальной дорожной разметкой."],"c":1,"e":"<p>Когда значения временных и постоянных дорожных знаков противоречат друг другу, участники дорожного движения должны руководствоваться временными знаками.</p>","image":"assets/adrive-questions/q200100102.webp"},{"id":200100201,"themeId":2,"group":2001002,"chapter":76,"chapters":[76],"q":"Какой из показанных дорожных знаков информирует водителя о приближении к железнодорожному переезду, не оборудованному шлагбаумом?","a":["Знак 1.","Знак 2.","Знак 3.","Знак 4.","Знак 5."],"c":3,"e":"<p>Дорожный знак 1.2 «Железнодорожный переезд без шлагбаума» предупреждает водителя о том, что впереди находится железнодорожный переезд, не оборудованный шлагбаумом.</p>","image":"assets/adrive-questions/q200100201.webp"},{"id":200100202,"themeId":2,"group":2001002,"chapter":76,"chapters":[76],"q":"Какой из показанных дорожных знаков информирует водителя о приближении к железнодорожному переезду, не оборудованному шлагбаумом?","a":["Знак 1.","Знак 2.","Знак 3.","Знак 4.","Знак 5."],"c":2,"e":"<p>Дорожный знак 1.2 «Железнодорожный переезд без шлагбаума» предупреждает водителя о том, что впереди находится железнодорожный переезд, не оборудованный шлагбаумом.</p>","image":"assets/adrive-questions/q200100202.webp"},{"id":200100203,"themeId":2,"group":2001002,"chapter":76,"chapters":[76],"q":"О чём информирует дорожный знак, установленный справа от дороги?","a":["О приближении к железнодорожному вокзалу.","О приближении к железнодорожному переезду, оборудованному шлагбаумом.","О приближении к железнодорожному переезду, не оборудованному шлагбаумом."],"c":2,"e":"<p>Дорожный знак 1.2 «Железнодорожный переезд без шлагбаума» предупреждает водителя о том, что впереди находится железнодорожный переезд, не оборудованный шлагбаумом.</p>","image":"assets/adrive-questions/q200100203.webp"},{"id":200100301,"themeId":2,"group":2001003,"chapter":76,"chapters":[76],"q":"О чём информирует водителей этот дорожный знак?","a":["О приближении к перекрёстку равнозначных дорог.","О приближении к пересечению с трамвайной линией.","О выезде на железнодорожный переезд с одним путём.","О выезде на железнодорожный переезд, оборудованный шлагбаумом, с двумя и более путями."],"c":2,"e":"<p>Дорожный знак 1.3.1 «Однопутная железная дорога» предупреждает о переезде через железную дорогу с одним путём.</p>","image":"assets/adrive-questions/q200100301.webp"},{"id":200100302,"themeId":2,"group":2001003,"chapter":76,"chapters":[76],"q":"О чём информирует водителей этот дорожный знак?","a":["О приближении к перекрёстку равнозначных дорог.","О выезде на железнодорожный переезд с двумя и более путями.","О приближении к пересечению с трамвайной линией с двумя путями.","О выезде на железнодорожный переезд, оборудованный шлагбаумом, с одним путём."],"c":1,"e":"<p>Дорожный знак 1.3.2 «Многопутная железная дорога» указывает на наличие двух и более железнодорожных путей.</p>","image":"assets/adrive-questions/q200100302.webp"},{"id":200100303,"themeId":2,"group":2001003,"chapter":76,"chapters":[76],"q":"О чём информирует водителя дорожный знак, изображённый на фоне жёлтого экрана (щита) с надписью «Внимание!»?","a":["О выезде на железнодорожный переезд с одним путём.","О выезде на железнодорожный переезд с двумя и более путями.","О том, что движение через железнодорожный переезд запрещено."],"c":1,"e":"<p>Дорожный знак 1.3.2 «Многопутная железная дорога» указывает на наличие двух и более железнодорожных путей.</p> <p>Допускается наносить изображения дорожных знаков на фоновый щит жёлтого цвета без внешней каймы белого цвета.</p>","image":"assets/adrive-questions/q200100303.webp"},{"id":200100401,"themeId":2,"group":2001004,"chapter":76,"chapters":[76],"q":"Какой из показанных дорожных знаков устанавливается вне населённых пунктов для дополнительного предупреждения о приближении к железнодорожному переезду?","a":["Знак 1.","Знак 2.","Знак 3.","Знак 4.","Знак 5."],"c":1,"e":"<p>Дорожный знак 1.4.2 «Приближение к железнодорожному переезду» устанавливается только вне населённых пунктов для дополнительного предупреждения о приближении к железнодорожному переезду.</p>","image":"assets/adrive-questions/q200100401.webp"},{"id":200100402,"themeId":2,"group":2001004,"chapter":76,"chapters":[76],"q":"Какой из показанных дорожных знаков устанавливается только на левой стороне дороги?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":3,"e":"<p>Дорожный знак 1.4.5 «Приближение к железнодорожному переезду» устанавливается только на левой стороне дороги.</p>","image":"assets/adrive-questions/q200100402.webp"},{"id":200100502,"themeId":2,"group":2001005,"chapter":76,"chapters":[76],"q":"О чём информирует водителя показанный на рисунке дорожный знак?","a":["О приближении к участку сужения дороги.","О приближении к участку дороги с покрытием повышенной скользкости.","О приближении к участку дороги, на котором не нанесена горизонтальная дорожная разметка.","О приближении к переходу дороги с усовершенствованным покрытием в гравийную или грунтовую дорогу."],"c":3,"e":"<p>Дорожный знак 1.6 «Конец дороги с усовершенствованным покрытием» предупреждает о переходе дороги с усовершенствованным покрытием в гравийную или грунтовую дорогу.</p>","image":"assets/adrive-questions/q200100502.webp"},{"id":200100601,"themeId":2,"group":2001006,"chapter":76,"chapters":[76],"q":"Какие из показанных дорожных знаков информируют водителей о приближении к опасному участку дороги, движение по которому требует принятия мер, соответствующих дорожной обстановке?","a":["Только дорожный знак 4.","Дорожные знаки 3 и 4.","Дорожные знаки 3, 4 и 5.","Все показанные дорожные знаки."],"c":3,"e":"<p>Предупреждающие дорожные знаки информируют водителей о приближении к опасному участку дороги, движение по которому требует принятия мер, соответствующих дорожной обстановке.</p> <p>Все показанные дорожные знаки относятся к предупреждающим.</p>","image":"assets/adrive-questions/q200100601.webp"},{"id":200100602,"themeId":2,"group":2001006,"chapter":76,"chapters":[76],"q":"Какой из показанных дорожных знаков информирует водителей о приближении к опасному участку дороги, движение по которому требует принятия мер, соответствующих дорожной обстановке?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":0,"e":"<p>Предупреждающие дорожные знаки информируют водителей о приближении к опасному участку дороги, движение по которому требует принятия мер, соответствующих дорожной обстановке.</p> <p>Дорожный знак 1.28 «Низколетящие самолеты» относится к группе предупреждающих.</p>","image":"assets/adrive-questions/q200100602.webp"},{"id":200100701,"themeId":2,"group":2001007,"chapter":76,"chapters":[76],"q":"О чём информирует водителей дорожный знак, изображённый на рисунке?","a":["О том, что впереди переправа вброд.","О выезде на набережную или берег водоёма.","О подъезде к оборудованному месту рыбной ловли.","О выезде на разводной мост или паромную переправу."],"c":1,"e":"<p>Дорожный знак 1.10 «Выезд на набережную» предупреждает о приближении к выезду на набережную (берег водоёма).</p>","image":"assets/adrive-questions/q200100701.webp"},{"id":200100702,"themeId":2,"group":2001007,"chapter":76,"chapters":[76],"q":"О чём информирует водителей дорожный знак, изображённый на рисунке?","a":["О выезде на набережную или берег водоёма.","О выезде на разводной мост или паромную переправу.","О подъезде к охраняемому пляжу, оборудованному шлагбаумом.","О подъезде к охраняемому месту рыбной ловли, оборудованному шлагбаумом."],"c":1,"e":"<p>Дорожный знак 1.9 «Разводной мост или паромная переправа» предупреждает о приближении к разводному мосту или паромной переправе.</p>","image":"assets/adrive-questions/q200100702.webp"},{"id":200100901,"themeId":2,"group":2001009,"chapter":76,"chapters":[76],"q":"Как называется дорожный знак, изображённый на рисунке?","a":["Неровная дорога.","Скользкая дорога.","Опасные повороты.","Скользкая полоса наката.","Аварийно-опасный участок."],"c":1,"e":"<p>Изображённый на рисунке дорожный знак называется 1.15 «Скользкая дорога» .<br> Этот дорожный знак предупреждает водителя об ухудшении сцепления шин с поверхностью дороги, что ведёт к увеличению длины тормозного пути и повышает вероятность возникновения бокового заноса.</p>","image":"assets/adrive-questions/q200100901.webp"},{"id":200100902,"themeId":2,"group":2001009,"chapter":76,"chapters":[76],"q":"Какой из показанных на рисунке дорожных знаков называется «Скользкая дорога»?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":2,"e":"<p>На рисунке под номером 3 изображён дорожный знак 1.15 «Скользкая дорога» .</p>","image":"assets/adrive-questions/q200100902.webp"},{"id":200100903,"themeId":2,"group":2001009,"chapter":76,"chapters":[76],"q":"Как называется показанный дорожный знак?","a":["Крутой спуск.","Крутой подъём.","Опасная обочина.","Неровная дорога."],"c":0,"e":"<p>На показанном участке дороги установлен предупреждающий дорожный знак 1.13 «Крутой спуск» .<br> Чтобы не перепутать его с похожим дорожным знаком 1.14 «Крутой подъём» , необходимо провести аналогию с порядком прочтения текста: слева направо. Если слева направо на знаке дорога имеет понижение, значит это дорожный знак «Крутой спуск».</p>","image":"assets/adrive-questions/q200100903.webp"},{"id":200101001,"themeId":2,"group":2001010,"chapter":76,"chapters":[76],"q":"О чём информирует водителей дорожный знак, изображённый на рисунке?","a":["О приближении к участку дороги с неровностями на проезжей части (волнами, наплывами, гребёнкой).","О приближении к участку дороги, имеющему неплавные сопряжения с покрытием дороги в виде наплыва (бугра).","О приближении к участку дороги, на котором возможно появление детей с территории детского учреждения.","О приближении к участку дороги с установленной искусственной неровностью (искусственными неровностями) на проезжей части дороги."],"c":3,"e":"<p>Дорожный знак 1.16.1 «Искусственная неровность» информирует о приближении к участку дороги с установленной искусственной неровностью (неровностями) на проезжей части дороги.</p>","image":"assets/adrive-questions/q200101001.webp"},{"id":200101002,"themeId":2,"group":2001010,"chapter":76,"chapters":[76],"q":"Какой из показанных на рисунке дорожных знаков информирует водителя о приближении к участку дороги с установленной искусственной неровностью (искусственными неровностями) на проезжей части дороги?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":2,"e":"<p>На рисунке под номером 3 изображён дорожный знак 1.16.1 «Искусственная неровность» , который информирует водителя о приближении к участку дороги с установленной искусственной неровностью (неровностями) на проезжей части дороги.</p>","image":"assets/adrive-questions/q200101002.webp"},{"id":200101201,"themeId":2,"group":2001012,"chapter":76,"chapters":[76],"q":"Какой из показанных на рисунке дорожных знаков информирует водителей о приближении к участку дороги с неровностями на проезжей части (волнами, наплывами, гребёнкой)?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":1,"e":"<p>На рисунке под номером 2 изображён дорожный знак 1.16.2 «Неровная дорога» , который информирует водителя о приближении к участку дороги с неровностями на проезжей части (волнами, наплывами, гребёнкой).</p>","image":"assets/adrive-questions/q200101201.webp"},{"id":200101202,"themeId":2,"group":2001012,"chapter":76,"chapters":[76],"q":"Какой из показанных на рисунке дорожных знаков информирует водителей о приближении к участку дороги с неровностями на проезжей части (волнами, наплывами, гребёнкой)?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":2,"e":"<p>На рисунке под номером 3 изображён дорожный знак 1.16.2 «Неровная дорога» , который информирует водителя о приближении к участку дороги с неровностями на проезжей части (волнами, наплывами, гребёнкой).</p>","image":"assets/adrive-questions/q200101202.webp"},{"id":200101301,"themeId":2,"group":2001013,"chapter":76,"chapters":[76],"q":"Какой из показанных на рисунке дорожных знаков информирует водителей о приближении к участку дороги, имеющему неплавные сопряжения с покрытием дороги в виде наплыва (бугра)?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":3,"e":"<p>На рисунке под номером 4 изображён дорожный знак 1.16.3 «Неровная дорога» , который информирует водителя об участке дороги, имеющем неплавные сопряжения с полотном дороги в виде наплыва (бугра).</p>","image":"assets/adrive-questions/q200101301.webp"},{"id":200101302,"themeId":2,"group":2001013,"chapter":76,"chapters":[76],"q":"О чём информирует водителей знак, изображённый на рисунке?","a":["О приближении к участку дороги с неровностями на проезжей части (волнами, наплывами, гребёнкой).","О приближении к участку дороги, имеющему неплавные сопряжения с покрытием дороги в виде наплыва (бугра).","О приближении к участку дороги, на котором возможно появление детей с территории детского учреждения.","О приближении к участку дороги с установленной искусственной неровностью (искусственными неровностями) на проезжей части дороги."],"c":1,"e":"<p>Изображённый на рисунке дорожный знак 1.16.3 «Неровная дорога» информирует водителя о приближении к участку дороги, имеющему неплавные сопряжения с полотном дороги в виде наплыва (бугра).</p>","image":"assets/adrive-questions/q200101302.webp"},{"id":200101401,"themeId":2,"group":2001014,"chapter":76,"chapters":[76],"q":"Какой из показанных на рисунке дорожных знаков информирует водителей о приближении к участку дороги, имеющему повреждения покрытия в виде отдельных выбоин, просадок?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":0,"e":"<p>На рисунке под номером 1 изображён дорожный знак 1.16.4 «Неровная дорога» , который информирует водителей об участке дороги с выбоинами или просадками.</p>","image":"assets/adrive-questions/q200101401.webp"},{"id":200101402,"themeId":2,"group":2001014,"chapter":76,"chapters":[76],"q":"О чём информирует водителей дорожный знак, изображённый на рисунке?","a":["О приближении к участку дороги с неровностями на проезжей части (волнами, наплывами, гребёнкой).","О приближении к участку дороги, имеющему неплавные сопряжения с покрытием дороги в виде наплыва (бугра).","О приближении к участку дороги, имеющему повреждения покрытия в виде отдельных выбоин, просадок.","О приближении к участку дороги, на котором в установленном порядке выполняются ремонтные и другие работы."],"c":2,"e":"<p>Изображённый на рисунке дорожный знак 1.16.4 «Неровная дорога» информирует водителей о приближении к участку дороги, имеющему повреждения покрытия в виде отдельных выбоин, просадок.</p>","image":"assets/adrive-questions/q200101402.webp"},{"id":200101501,"themeId":2,"group":2001015,"chapter":76,"chapters":[76],"q":"О чём информирует водителей дорожный знак, изображённый на рисунке?","a":["О приближении к участку дороги с заниженной или разрушенной обочиной либо на котором ведутся работы по ремонту обочин.","О приближении к участку дороги, где дорога с усовершенствованным покрытием переходит в дорогу без усовершенствованного покрытия.","О приближении к участку дороги с усовершенствованным покрытием, на котором возможен выброс щебня из-под колёс транспортных средств.","О приближении к участку дороги без усовершенствованного покрытия, на котором возможен выброс щебня из-под колёс транспортных средств."],"c":2,"e":"<p>Изображённый на рисунке дорожный знак 1.17 «Выброс щебня» информирует водителей о возможном выбросе щебня из-под колёс транспортных средств на участке дороги с усовершенствованным покрытием.</p>","image":"assets/adrive-questions/q200101501.webp"},{"id":200101561,"themeId":2,"group":2001015,"chapter":76,"chapters":[76],"q":"О чём информирует участников дорожного движения показанный стрелкой дорожный знак?","a":["О приближении к участку дороги, на котором имеются повреждения дорожного покрытия в виде выбоин.","О приближении к участку дороги, на котором возможен выброс щебня из-под колёс транспортных средств.","О приближении к участку дороги повышенной скользкости, на котором возможен выброс грязи из-под колёс транспортных средств."],"c":1,"e":"<p>Показанный стрелкой дорожный знак «Выброс щебня» информирует о приближении к участку дороги с усовершенствованным покрытием, на котором возможен выброс щебня из-под колёс транспортных средств.</p>","image":"assets/adrive-questions/q200101561.webp"},{"id":200101701,"themeId":2,"group":2001017,"chapter":76,"chapters":[76],"q":"О чём информирует водителей дорожный знак, изображённый на рисунке?","a":["О приближении к сужению дороги.","О приближении к аварийно-опасному участку дороги.","О приближении к участку дороги с опасными поворотами.","О приближении к участку дороги, на котором необходимо уступить дорогу встречным транспортным средствам."],"c":0,"e":"<p>Изображённый на рисунке дорожный знак 1.18.1 «Сужение дороги» информирует водителей о сужении дороги с обеих сторон.</p>","image":"assets/adrive-questions/q200101701.webp"},{"id":200101702,"themeId":2,"group":2001017,"chapter":76,"chapters":[76],"q":"Какие из показанных на рисунке дорожных знаков называются «Сужение дороги»?","a":["Только дорожный знак 1.","Дорожные знаки 1 и 3.","Все показанные дорожные знаки."],"c":2,"e":"<p>Все дорожные знаки, изображённые на рисунке, называются 1.18 «Сужение дороги».</p>","image":"assets/adrive-questions/q200101702.webp"},{"id":200101801,"themeId":2,"group":2001018,"chapter":76,"chapters":[76],"q":"О чём информирует водителей дорожный знак, изображённый на рисунке?","a":["О начале участка дороги, на одной или нескольких полосах которого направление движения может изменяться на противоположное.","О приближении к началу участка дороги (проезжей части дороги) со встречным движением после участка дороги с односторонним движением.","О необходимости уступить дорогу встречным транспортным средствам, находящимся на данном участке дороги или противоположном подъезде к нему."],"c":1,"e":"<p>Дорожный знак 1.19.2 «Двустороннее движение» информирует водителей о приближении к началу участка дороги (проезжей части дороги) со встречным движением после участка дороги с односторонним движением.</p>","image":"assets/adrive-questions/q200101801.webp"},{"id":200101901,"themeId":2,"group":2001019,"chapter":76,"chapters":[76],"q":"В каких случаях для информирования водителей применяется предупреждающий дорожный знак, изображённый на рисунке?","a":["При приближении к нерегулируемому пешеходному переходу.","При приближении к пешеходному переходу, оборудованному дорожными светофорами.","Применяется в обоих перечисленных случаях."],"c":0,"e":"<p>Дорожный знак 1.20 «Впереди пешеходный переход» информирует водителей о приближении к нерегулируемому пешеходному переходу.</p>","image":"assets/adrive-questions/q200101901.webp"},{"id":200101902,"themeId":2,"group":2001019,"chapter":76,"chapters":[76],"q":"Какой из показанных на рисунке дорожных знаков применяется для информирования водителей о приближении только к нерегулируемому пешеходному переходу?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":1,"e":"<p>На рисунке под номером 2 изображён дорожный знак 1.20 «Впереди пешеходный переход» , который информирует водителей о приближении только к нерегулируемому пешеходному переходу.</p>","image":"assets/adrive-questions/q200101902.webp"},{"id":200101941,"themeId":2,"group":2001019,"chapter":76,"chapters":[76],"q":"Какой из показанных дорожных знаков предупреждает о приближении к велосипедному переезду?","a":["Знак 1.","Знак 2.","Знак 3.","Знак 4.","Знак 5."],"c":1,"e":"<p>О приближении к велосипедному переезду предупреждает второй дорожный знак.</p>","image":"assets/adrive-questions/q200101941.webp"},{"id":200101962,"themeId":2,"group":2001019,"chapter":76,"chapters":[76],"q":"О чём информирует показанный стрелкой дорожный знак?","a":["О приближении к пересечению с пешеходной дорожкой.","О приближении к нерегулируемому пешеходному переходу, обозначенному соответствующими дорожными знаками и (или) горизонтальной дорожной разметкой.","О приближении к оборудованному дорожными светофорами пешеходному переходу, обозначенному соответствующими дорожными знаками и (или) горизонтальной дорожной разметкой."],"c":1,"e":"<p>Показанный дорожный знак «Впереди пешеходный переход» информирует о приближении к нерегулируемому пешеходному переходу.</p>","image":"assets/adrive-questions/q200101962.webp"},{"id":200102102,"themeId":2,"group":2001021,"chapter":76,"chapters":[76],"q":"Какие из показанных на рисунке дорожных знаков относятся к группе «Предупреждающие знаки»?","a":["Только дорожный знак 5.","Только дорожный знак 2.","Дорожные знаки 2 и 5.","Дорожные знаки 3, 4 и 5.","Все показанные на рисунке дорожные знаки."],"c":2,"e":"<p>На рисунке под номерами 2 и 5 изображены дорожные знаки 1.21 «Дети» и 1.22 «Впереди велосипедный переезд» , которые относятся к группе предупреждающих дорожных знаков.</p>","image":"assets/adrive-questions/q200102102.webp"},{"id":200102201,"themeId":2,"group":2001022,"chapter":76,"chapters":[76],"q":"О чём информирует водителей дорожный знак, установленный справа?","a":["О приближении к началу участка дороги, на котором возможны обвалы, оползни, падение камней.","О приближении к началу участка дороги, на котором часто совершаются дорожно-транспортные происшествия.","О приближении к началу участка дороги, на котором возможен затор ввиду проводимых работ на проезжей части дороги.","О приближении к началу опасного участка дороги, который невозможно обозначить другими предупреждающими знаками.","О приближении к началу участка дороги, на котором возможны снежные заносы либо ледяные или снежно-ледяные образования."],"c":1,"e":"<p>Показанный дорожный знак 1.29 «Аварийно-опасный участок» информирует водителей о приближении к началу участка дороги, на котором часто совершаются дорожно-транспортные происшествия.</p>","image":"assets/adrive-questions/q200102201.webp"},{"id":200102202,"themeId":2,"group":2001022,"chapter":76,"chapters":[76],"q":"Какой из показанных на рисунке дорожных знаков применяется для информирования водителей о приближении к участку дороги, на котором часто совершаются дорожно-транспортные происшествия?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":3,"e":"<p>На рисунке под номером 4 изображён дорожный знак 1.29 «Аварийно-опасный участок» , который информирует водителей об участке дороги, на котором часто совершаются дорожно-транспортные происшествия.</p>","image":"assets/adrive-questions/q200102202.webp"},{"id":200102301,"themeId":2,"group":2001023,"chapter":76,"chapters":[76],"q":"О чём информирует предупреждающий дорожный знак, установленный справа?","a":["О приближении к пересечению с пешеходной дорожкой.","О приближении к регулируемому пешеходному переходу.","О приближении к нерегулируемому пешеходному переходу.","О приближении к началу участка дороги, на котором запрещено движение пешеходов.","О приближении к началу участка дороги, на котором часто совершаются дорожно-транспортные происшествия."],"c":4,"e":"<p>Установленный предупреждающий дорожный знак 1.29 «Аварийно-опасный участок дороги» информирует водителей об участке дороги, на котором часто совершаются дорожно-транспортные происшествия.</p>","image":"assets/adrive-questions/q200102301.webp"},{"id":200102302,"themeId":2,"group":2001023,"chapter":76,"chapters":[76],"q":"О чём информирует предупреждающий дорожный знак, установленный справа?","a":["О приближении к регулируемому перекрёстку.","О приближении к нерегулируемому перекрёстку.","О приближении к началу участка дороги, на котором часто совершаются дорожно-транспортные происшествия.","О приближении к участку дороги, на котором возможен затор ввиду проводимых работ на проезжей части дороги."],"c":2,"e":"<p>Установленный предупреждающий дорожный знак 1.29 «Аварийно-опасный участок дороги» информирует водителей об участке дороги, на котором часто совершаются дорожно-транспортные происшествия.</p>","image":"assets/adrive-questions/q200102302.webp"},{"id":200102401,"themeId":2,"group":2001024,"chapter":76,"chapters":[76],"q":"О чём может информировать водителей предупреждающий дорожный знак, изображённый на рисунке?","a":["О направлении движения на Т-образном перекрёстке.","О направлении объезда центрального островка на перекрёстке с круговым движением.","О направлении движения на повороте дороги малого радиуса с ограниченной обзорностью.","О направлении объезда препятствия для дорожного движения на ремонтируемом участке дороги.","Может информировать обо всём вышеперечисленном."],"c":4,"e":"<p>Предупреждающий дорожный знак 1.31.1 «Направление поворота» может информировать водителей о направлении движения на повороте дороги малого радиуса с ограниченной обзорностью, о направлении движения на Т-образном перекрёстке, о направлении объезда центрального островка на перекрёстке с круговым движением и объезда препятствия для дорожного движения на ремонтируемом участке дороги.</p>","image":"assets/adrive-questions/q200102401.webp"},{"id":200102402,"themeId":2,"group":2001024,"chapter":76,"chapters":[76],"q":"О чём может информировать водителей предупреждающий дорожный знак, изображённый на рисунке?","a":["О том, что поворот направо запрещён.","Об изменении направления главной дороги.","Об участке дороги, на котором возможны сильный боковой ветер или его внезапные порывы.","Об участке дороги, на котором в установленном порядке выполняются ремонтные и другие работы.","О направлении объезда препятствия для дорожного движения на ремонтируемом участке дороги."],"c":4,"e":"<p>Предупреждающий дорожный знак 1.31.1 «Направление поворота» может информировать водителей о направлении объезда препятствия для дорожного движения на ремонтируемом участке дороги.</p>","image":"assets/adrive-questions/q200102402.webp"},{"id":200102501,"themeId":2,"group":2001025,"chapter":76,"chapters":[76],"q":"Какой из показанных на рисунке дорожных знаков применяется для информирования водителей о направлении движения на Т-образном перекрёстке, разветвлении дорог?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":3,"e":"<p>На рисунке под номером 4 изображён дорожный знак 1.31.3 «Направление поворота» , который применяется для информирования водителей о направлении движения на Т-образном перекрёстке, разветвлении дорог.</p>","image":"assets/adrive-questions/q200102501.webp"},{"id":200102502,"themeId":2,"group":2001025,"chapter":76,"chapters":[76],"q":"Какой из показанных на рисунке дорожных знаков применяется для информирования водителей о направлении объезда препятствия для дорожного движения слева на ремонтируемом участке дороги?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":3,"e":"<p>На рисунке под номером 4 изображён дорожный знак 1.31.2 «Направление поворота» , который может информировать водителей о направлении объезда препятствия для дорожного движения слева на ремонтируемом участке дороги.</p>","image":"assets/adrive-questions/q200102502.webp"},{"id":200102601,"themeId":2,"group":2001026,"chapter":76,"chapters":[76],"q":"Какие из показанных на рисунке дорожных знаков относятся к группе «Предупреждающие знаки»?","a":["Только дорожный знак 5.","Только дорожный знак 4.","Дорожные знаки 4 и 5.","Дорожные знаки 1 и 4.","Все показанные дорожные знаки."],"c":3,"e":"<p>Предупреждающие дорожные знаки информируют водителей о приближении к опасному участку дороги, движение по которому требует принятия мер, соответствующих дорожной обстановке.</p> <p>Дорожные знаки 1.4.3 «Приближение к железнодорожному переезду» и 1.31.4 «Направление поворота» относятся к группе предупреждающих.</p>","image":"assets/adrive-questions/q200102601.webp"},{"id":200102602,"themeId":2,"group":2001026,"chapter":76,"chapters":[76],"q":"Какие из показанных на рисунке дорожных знаков относятся к группе «Предупреждающие знаки»?","a":["Дорожные знаки 1 и 3.","Дорожные знаки 2 и 4.","Дорожные знаки 4 и 5.","Дорожные знаки 1, 2 и 3.","Все показанные дорожные знаки."],"c":1,"e":"<p>Дорожные знаки 1.19.1 «Двустороннее движение» и 1.31.1 «Направление поворота» относятся к группе предупреждающих дорожных знаков.</p>","image":"assets/adrive-questions/q200102602.webp"},{"id":200102641,"themeId":2,"group":2001026,"chapter":76,"chapters":[76],"q":"Какие из показанных дорожных знаков относятся к группе «Предупреждающие знаки»?","a":["Только знак 1.","Только знаки 1 и 4.","Знаки 1, 3 и 4.","Знаки 1, 3, 4 и 5.","Все показанные знаки."],"c":2,"e":"<p>К предупреждающим дорожным знакам относятся первый («1.31.4 Направление поворота» ), третий («1.37 Контроль выполнения требований Правил дорожного движения» ) и четвёртый («1.38 Начало участка контроля средней скорости движения транспортных средств» ) знаки.</p>","image":"assets/adrive-questions/q200102641.webp"},{"id":200102801,"themeId":2,"group":2001028,"chapter":76,"chapters":[76],"q":"О чём информирует водителей предупреждающий дорожный знак, изображённый на рисунке?","a":["О приближении к участку дороги с заниженной или разрушенной обочиной.","О приближении к началу участка дороги, на котором возможны обвалы, оползни, падение камней.","О приближении к участку дороги с неровностями на проезжей части (волнами, наплывами, гребёнкой).","О приближении к участку дороги, имеющему неплавные сопряжения с покрытием дороги в виде наплыва (бугра).","О приближении к началу участка дороги, на котором часто совершаются дорожно-транспортные происшествия."],"c":0,"e":"<p>Предупреждающий дорожный знак 1.32 «Опасная обочина» информирует водителей о приближении к участку дороги, на котором обочина занижена или разрушена.</p>","image":"assets/adrive-questions/q200102801.webp"},{"id":200102802,"themeId":2,"group":2001028,"chapter":76,"chapters":[76],"q":"Какой из показанных на рисунке дорожных знаков применяется для информирования водителей о приближении к участку дороги с заниженной или разрушенной обочиной?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":2,"e":"<p>На рисунке под номером 3 изображён дорожный знак 1.32 «Опасная обочина» , который информирует водителей о приближении к участку дороги, на котором обочина занижена или разрушена.</p>","image":"assets/adrive-questions/q200102802.webp"},{"id":200102851,"themeId":2,"group":2001028,"chapter":76,"chapters":[76],"q":"О чём информирует участников дорожного движения показанный дорожный знак?","a":["О неровной дороге.","О скользкой дороге.","Об опасной обочине.","Об опасном повороте."],"c":2,"e":"<p>Дорожный знак «Опасная обочина» информирует о приближении к участку дороги с заниженной или разрушенной обочиной либо на котором ведутся работы по ремонту обочин.</p>","image":"assets/adrive-questions/q200102851.webp"},{"id":200102901,"themeId":2,"group":2001029,"chapter":76,"chapters":[76],"q":"О чём информирует водителей предупреждающий дорожный знак, изображённый на рисунке?","a":["О приближении к участку дороги с покрытием повышенной скользкости.","О необходимости использования шин, предназначенных для эксплуатации в зимних условиях.","О приближении к участку дороги, на котором возможно изменение коэффициента сцепления по ширине дороги.","О приближении к участку дороги, на котором возможны снежные заносы либо ледяные или снежно-ледяные образования."],"c":3,"e":"<p>Предупреждающий дорожный знак 1.33 «Гололедица» информирует водителей о приближении к участку дороги, на котором возможны снежные заносы либо ледяные или снежно-ледяные образования.</p>","image":"assets/adrive-questions/q200102901.webp"},{"id":200102902,"themeId":2,"group":2001029,"chapter":76,"chapters":[76],"q":"Какой из показанных на рисунке дорожных знаков применяется для информирования водителей о приближении к участку дороги, на котором возможны снежные заносы либо ледяные или снежно-ледяные образования?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":2,"e":"<p>На рисунке под номером 3 изображён дорожный знак 1.33 «Гололедица» , который информирует водителей о приближении к участку дороги, на котором возможны снежные заносы либо ледяные или снежно-ледяные образования.</p>","image":"assets/adrive-questions/q200102902.webp"},{"id":200103001,"themeId":2,"group":2001030,"chapter":76,"chapters":[76],"q":"О чём информирует водителей предупреждающий дорожный знак, изображённый на рисунке?","a":["О приближении к участку дороги, на котором возможно образование заторов.","О приближении к участку дороги с повышенной скользкостью дорожного покрытия.","О приближении к участку дороги, на котором часто совершаются дорожно-транспортные происшествия.","О приближении к участку дороги, на котором действуют ограничения по выбору минимальной дистанции между транспортными средствами."],"c":0,"e":"<p>Предупреждающий дорожный знак 1.34 «Затор на дороге» информирует водителей о приближении к участку дороги, на котором возможно образование заторов.</p>","image":"assets/adrive-questions/q200103001.webp"},{"id":200103002,"themeId":2,"group":2001030,"chapter":76,"chapters":[76],"q":"О чём информирует установленный справа предупреждающий дорожный знак?","a":["О приближении к участку дороги, на котором проводятся дорожные работы.","О приближении к участку дороги, на котором возможно образование заторов.","О приближении к участку дороги с повышенной скользкостью дорожного покрытия.","О приближении к участку дороги, где будет запрещено движение транспортных средств.","О приближении к участку дороги, на котором действуют ограничения по выбору минимальной дистанции между транспортными средствами."],"c":1,"e":"<p>Предупреждающий дорожный знак 1.34 «Затор на дороге» информирует водителей о приближении к участку дороги, на котором возможно образование заторов.</p>","image":"assets/adrive-questions/q200103002.webp"},{"id":200103102,"themeId":2,"group":2001031,"chapter":76,"chapters":[76],"q":"О чём информирует водителей предупреждающий дорожный знак, изображённый на рисунке?","a":["О том, что дорога проходит по Национальному парку.","О приближении к участку дороги, на котором возможно образование заторов.","О приближении к участку дороги, проходящему по набережной или берегу водоёма.","О приближении к участку дороги, на котором возможны массовые появления земноводных на проезжей части."],"c":3,"e":"<p>На рисунке изображён дорожный знак 1.35 «Сезонные миграции земноводных» , который информирует водителей о приближении к участку дороги, на котором возможны массовые появления земноводных на проезжей части.</p>","image":"assets/adrive-questions/q200103102.webp"},{"id":200103201,"themeId":2,"group":2001032,"chapter":76,"chapters":[76],"q":"На каком расстоянии от железнодорожного переезда находится зелёный автомобиль в показанной ситуации в населённом пункте?","a":["20–50 метров.","50–100 метров.","100–150 метров.","150–300 метров."],"c":1,"e":"<p>Предупреждающий дорожный знак 1.1 «Железнодорожный переезд со шлагбаумом» в населённых пунктах устанавливается на расстоянии 50–100 метров от железнодорожного переезда.</p>","image":"assets/adrive-questions/q200103201.webp"},{"id":200103202,"themeId":2,"group":2001032,"chapter":76,"chapters":[76],"q":"Имеет ли преимущество пешеход в показанной ситуации вне населённого пункта?","a":["Да, имеет.","Нет, не имеет."],"c":1,"e":"<p>Пешеход не имеет преимущества, так как показанный предупреждающий дорожный знак 1.20 «Впереди пешеходный переход» вне населённых пунктов устанавливается на расстоянии 150–300 метров до нерегулируемого пешеходного перехода.</p>","image":"assets/adrive-questions/q200103202.webp"},{"id":200103341,"themeId":2,"group":2001033,"chapter":76,"chapters":[76],"q":"Показанный дорожный знак предупреждает, что на участке дороги:","a":["Установлены камеры видеонаблюдения за дорожной обстановкой.","Осуществляется контроль за соблюдением установленной скорости движения с использованием технических средств в автоматическом режиме.","Осуществляется контроль за соблюдением установленной скорости движения с использованием технических средств в автоматическом режиме, а также за соблюдением прочих требований Правил дорожного движения."],"c":1,"e":"<p>Показанный дорожный знак «1.36 Контроль установленной скорости движения транспортных средств» предупреждает о въезде на участок дороги, на котором осуществляется контроль за соблюдением установленной скорости движения с использованием технических средств в автоматическом режиме.</p> <p>Знак устанавливается совместно со знаком «3.24.1 Ограничение максимальной скорости» или «3.24.2 Ограничение максимальной скорости» , определяющими скорость движения, соблюдение которой контролируется (в данном случае — 80 км/ч).</p>","image":"assets/adrive-questions/q200103341.webp"},{"id":200103342,"themeId":2,"group":2001033,"chapter":76,"chapters":[76],"q":"Показанный дорожный знак предупреждает, что на участке дороги:","a":["Осуществляется контроль средней скорости движения транспортных средств с использованием технических средств в автоматическом режиме.","Осуществляется контроль максимальной скорости движения транспортных средств с использованием технических средств в автоматическом режиме.","Осуществляется контроль за соблюдением установленной скорости движения с использованием технических средств в автоматическом режиме, а также за соблюдением прочих требований Правил дорожного движения."],"c":0,"e":"<p>Показанный дорожный знак «1.38 Начало участка контроля средней скорости движения транспортных средств» предупреждает о въезде на участок дороги, на котором осуществляется контроль средней скорости движения транспортных средств с использованием технических средств в автоматическом режиме.</p> <p>Знак устанавливается совместно со знаком «3.24.1 Ограничение максимальной скорости» или «3.24.2 Ограничение максимальной скорости» , определяющими скорость движения.</p>","image":"assets/adrive-questions/q200103342.webp"},{"id":200103343,"themeId":2,"group":2001033,"chapter":76,"chapters":[76],"q":"Показанный дорожный знак информирует:","a":["О начале участка дороги, на котором осуществляется контроль средней скорости движения транспортных средств с использованием технических средств в автоматическом режиме.","О начале участка дороги, на котором осуществляется контроль максимальной скорости движения транспортных средств с использованием технических средств в автоматическом режиме.","О конце участка дороги, на котором осуществляется контроль средней скорости движения транспортных средств с использованием технических средств в автоматическом режиме."],"c":2,"e":"<p>Показанный дорожный знак информирует о конце участка дороги, на котором осуществляется контроль средней скорости движения транспортных средств с использованием технических средств в автоматическом режиме.</p>","image":"assets/adrive-questions/q200103343.webp"},{"id":200103401,"themeId":2,"group":2001034,"chapter":76,"chapters":[76],"q":"На каком расстоянии устанавливаются дорожные знаки, показанные на рисунке, в населённом пункте?","a":["20–50 метров.","50–100 метров.","100–150 метров.","150–300 метров."],"c":1,"e":"<p>Изображённые на рисунке дорожные знаки являются предупреждающими.</p> <p>Показанные предупреждающие знаки в населённых пунктах устанавливаются на расстоянии 50–100 метров до начала опасного участка дороги.</p>","image":"assets/adrive-questions/q200103401.webp"},{"id":200103402,"themeId":2,"group":2001034,"chapter":76,"chapters":[76],"q":"На каком расстоянии устанавливаются дорожные знаки, показанные на рисунке, в населённом пункте?","a":["20–50 метров.","50–100 метров.","100–150 метров.","150–300 метров."],"c":1,"e":"<p>Изображённые на рисунке дорожные знаки являются предупреждающими.</p> <p>Показанные предупреждающие знаки в населённых пунктах устанавливаются на расстоянии 50–100 метров до начала опасного участка дороги.</p>","image":"assets/adrive-questions/q200103402.webp"},{"id":200103501,"themeId":2,"group":2001035,"chapter":76,"chapters":[76],"q":"На каком расстоянии устанавливаются дорожные знаки, показанные на рисунке, вне населённого пункта?","a":["20–50 метров.","50–100 метров.","100–150 метров.","150–300 метров."],"c":3,"e":"<p>Изображённые на рисунке дорожные знаки являются предупреждающими.</p> <p>Показанные предупреждающие знаки вне населённых пунктов устанавливаются на расстоянии 150–300 метров до начала опасного участка дороги.</p>","image":"assets/adrive-questions/q200103501.webp"},{"id":200103502,"themeId":2,"group":2001035,"chapter":76,"chapters":[76],"q":"На каком расстоянии устанавливаются дорожные знаки, показанные на рисунке, вне населённого пункта?","a":["20–50 метров.","50–100 метров.","100–150 метров.","150–300 метров."],"c":3,"e":"<p>Изображённые на рисунке дорожные знаки являются предупреждающими.</p> <p>Показанные предупреждающие знаки вне населённых пунктов устанавливаются на расстоянии 150–300 метров до начала опасного участка дороги.</p>","image":"assets/adrive-questions/q200103502.webp"},{"id":200103601,"themeId":2,"group":2001036,"chapter":76,"chapters":[76],"q":"О чём информирует водителей такое сочетание предупреждающих дорожных знаков?","a":["О приближении к железнодорожному переезду, не оборудованному шлагбаумом, в населённом пункте, до которого от 50 до 100 метров.","О приближении к железнодорожному переезду, оборудованному шлагбаумом, вне населённого пункта, до которого от 150 до 300 метров.","О приближении к железнодорожному переезду, не оборудованному шлагбаумом, вне населённого пункта, до которого от 150 до 300 метров."],"c":2,"e":"<p>Сочетание дорожных знаков 1.2 «Железнодорожный переезд без шлагбаума» и 1.4.4 «Приближение к железнодорожному переезду» информирует водителей о приближении к железнодорожному переезду, не оборудованному шлагбаумом, до которого от 150 до 300 метров, вне населённого пункта.</p>","image":"assets/adrive-questions/q200103601.webp"},{"id":200103602,"themeId":2,"group":2001036,"chapter":76,"chapters":[76],"q":"На какой стороне дороги устанавливается такое сочетание предупреждающих дорожных знаков?","a":["На левой стороне.","На правой стороне."],"c":0,"e":"<p>Сочетание предупреждающих дорожных знаков 1.2 «Железнодорожный переезд без шлагбаума» и 1.4.4 «Приближение к железнодорожному переезду» устанавливается на левой стороне дороги.</p>","image":"assets/adrive-questions/q200103602.webp"},{"id":200103701,"themeId":2,"group":2001037,"chapter":76,"chapters":[76],"q":"Какие из показанных на рисунке дорожных знаков повторяются при их установке вне населённого пункта?","a":["Только дорожный знак 1.","Только дорожный знак 3.","Дорожные знаки 1 и 3.","Дорожные знаки 2 и 3.","Все показанные дорожные знаки."],"c":3,"e":"<p>На рисунках под номерами 2 и 3 изображены дорожные знаки 1.21 «Дети» и 1.23 «Дорожные работы» , которые повторяются при их установке вне населённого пункта.</p>","image":"assets/adrive-questions/q200103701.webp"},{"id":200103702,"themeId":2,"group":2001037,"chapter":76,"chapters":[76],"q":"Какие из показанных на рисунке дорожных знаков повторяются при их установке вне населённого пункта?","a":["Только дорожный знак 1.","Дорожные знаки 1 и 2.","Дорожные знаки 1, 2 и 4.","Все показанные дорожные знаки."],"c":1,"e":"<p>На рисунке под номерами 1 и 2 изображены дорожные знаки 1.9 «Разводной мост или паромная переправа» и 1.10 «Выезд на набережную» , которые повторяются при их установке вне населённого пункта.</p>","image":"assets/adrive-questions/q200103702.webp"},{"id":200103802,"themeId":2,"group":2001038,"chapter":76,"chapters":[76],"q":"Какой из показанных на рисунке дорожных знаков повторяется при установке вне населённого пункта?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":4,"e":"<p>На рисунке под номером 5 изображён дорожный знак 1.21 «Дети» , который повторяется при установке вне населённого пункта.</p>","image":"assets/adrive-questions/q200103802.webp"},{"id":200103901,"themeId":2,"group":2001039,"chapter":76,"chapters":[76],"q":"Какой из показанных на рисунке дорожных знаков повторяется при установке в населённом пункте?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":4,"e":"<p>На рисунке под номером 5 изображён дорожный знак 1.23 «Дорожные работы» , который повторяется при установке в населённом пункте.</p>","image":"assets/adrive-questions/q200103901.webp"},{"id":200103902,"themeId":2,"group":2001039,"chapter":76,"chapters":[76],"q":"На каком расстоянии от начала опасного участка дороги устанавливается показанный на рисунке дорожный знак, если он установлен повторно в населённом пункте?","a":["10 метров.","От 20 до 50 метров.","От 50 до 100 метров.","От 100 до 150 метров.","Непосредственно у начала опасного участка дороги."],"c":4,"e":"<p>Изображённый на рисунке дорожный знак 1.23 «Дорожные работы» устанавливается повторно в населённом пункте непосредственно у начала участка проведения ремонтных и других работ.</p>","image":"assets/adrive-questions/q200103902.webp"},{"id":200104001,"themeId":2,"group":2001040,"chapter":76,"chapters":[76],"q":"Какой из показанных на рисунке дорожных знаков устанавливается в пределах опасного участка дороги или непосредственно перед ним?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":0,"e":"<p>Изображённый на рисунке под номером 1 дорожный знак 1.3.1 «Однопутная железная дорога» устанавливается в пределах опасного участка дороги или непосредственно перед ним.</p>","image":"assets/adrive-questions/q200104001.webp"},{"id":200104002,"themeId":2,"group":2001040,"chapter":76,"chapters":[76],"q":"Какой из показанных на рисунке дорожных знаков устанавливается в пределах опасного участка дороги или непосредственно перед ним?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":4,"e":"<p>Изображённый на рисунке под номером 5 дорожный знак 1.31.5 «Направление поворота» устанавливается в пределах опасного участка дороги или непосредственно перед ним.</p>","image":"assets/adrive-questions/q200104002.webp"},{"id":200104142,"themeId":2,"group":2001041,"chapter":76,"chapters":[76],"q":"О чём информирует водителей дорожный знак с жёлтым фоном, установленный справа в показанной ситуации?","a":["Об осуществлении круглосуточного мониторинга дорожной обстановки на участке дороги.","Об осуществлении контроля соблюдения Правил дорожного движения с использованием технических средств в автоматическом режиме.","Об осуществлении контроля за соблюдением установленной скорости движения с использованием технических средств в автоматическом режиме.","Об осуществлении контроля средней скорости движения транспортных средств с использованием технических средств в автоматическом режиме."],"c":1,"e":"<p>Показанный дорожный знак «1.37 Контроль выполнения требований Правил дорожного движения» предупреждает о въезде на участок дороги, на котором осуществляется контроль соблюдения Правил дорожного движения с использованием технических средств в автоматическом режиме.</p> <p>Может устанавливаться совместно со светофорами либо знаками, соблюдение требований которых контролируется (то есть в показанной ситуации осуществляется контроль движения по полосе для маршрутных транспортных средств).</p>","image":"assets/adrive-questions/q200104142.webp"},{"id":200200301,"themeId":2,"group":2002003,"chapter":77,"chapters":[77],"q":"Какие из показанных на рисунке дорожных знаков устанавливают очерёдность проезда перекрёстков, пересечений отдельных проезжих частей дорог, движение на которых не регулируется сигналами регулировщика или светофора?","a":["Только дорожный знак 1.","Дорожные знаки 1 и 2.","Дорожные знаки 2 и 3.","Дорожные знаки 2, 3 и 4.","Все показанные дорожные знаки."],"c":2,"e":"<p>Изображённые на рисунке под номерами 2 и 3 дорожные знаки 2.3.2 «Примыкание второстепенной дороги» и 2.5 «Движение без остановки запрещено» относятся к группе знаков приоритета и устанавливают очерёдность проезда перекрёстков, пересечений отдельных проезжих частей дорог, движение на которых не регулируется сигналами регулировщика или светофора.</p>","image":"assets/adrive-questions/q200200301.webp"},{"id":200200302,"themeId":2,"group":2002003,"chapter":77,"chapters":[77],"q":"Какой из показанных на рисунке дорожных знаков устанавливает очерёдность проезда узких участков дорог, движение на которых не регулируется сигналами регулировщика или светофора?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":4,"e":"<p>Изображённый на рисунке под номером 5 дорожный знак 2.6.1 «Преимущество встречного движения» устанавливает очерёдность проезда узких участков дорог, движение на которых не регулируется сигналами регулировщика или светофора.</p>","image":"assets/adrive-questions/q200200302.webp"},{"id":200200303,"themeId":2,"group":2002003,"chapter":77,"chapters":[77],"q":"Какой из показанных на рисунке дорожных знаков устанавливает очерёдность проезда узких участков дорог, движение на которых не регулируется сигналами регулировщика или светофора?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":0,"e":"<p>Изображённый на рисунке под номером 1 дорожный знак 2.7 «Преимущество перед встречным движением» устанавливает очерёдность проезда узких участков дорог, движение на которых не регулируется сигналами регулировщика или светофора.</p>","image":"assets/adrive-questions/q200200303.webp"},{"id":200200401,"themeId":2,"group":2002004,"chapter":77,"chapters":[77],"q":"В каком из указанных мест Вы обязаны остановиться при приближении к перекрёстку в показанной ситуации?","a":["Перед «стоп-линией».","Перед пешеходным переходом.","Вы не обязаны останавливаться перед перекрёстком в показанной ситуации."],"c":0,"e":"<p>Перед перекрёстком установлен дорожный знак 2.5 «Движение без остановки запрещено» , который обязывает водителя остановиться перед «стоп-линией».</p>","image":"assets/adrive-questions/q200200401.webp"},{"id":200200432,"themeId":2,"group":2002004,"chapter":77,"chapters":[77],"q":"Должны ли Вы остановиться в показанной ситуации перед краем пересекаемой проезжей части дороги, если к перекрёстку не приближаются в пределах видимости по главной дороге транспортные средства?","a":["Да, должны.","Нет, не должны."],"c":0,"e":"<p>Перед перекрёстком установлен дорожный знак 2.5 «Движение без остановки запрещено» , который обязывает водителя при отсутствии «стоп-линии» остановиться перед краем пересекаемой проезжей части дороги.</p>","image":"assets/adrive-questions/q200200432.webp"},{"id":200200433,"themeId":2,"group":2002004,"chapter":77,"chapters":[77],"q":"Должны ли Вы остановиться в показанной ситуации, если к перекрёстку не приближаются в пределах видимости по главной дороге транспортные средства?","a":["Да, должны перед краем пересекаемой проезжей части дороги.","Да, должны перед знаком."],"c":0,"e":"<p>Перед перекрёстком установлен дорожный знак 2.5 «Движение без остановки запрещено» , который обязывает водителя при отсутствии «стоп-линии» остановиться перед краем пересекаемой проезжей части дороги.</p>","image":"assets/adrive-questions/q200200433.webp"},{"id":200200461,"themeId":2,"group":2002004,"chapter":77,"chapters":[77],"q":"Должны ли Вы остановиться в показанной ситуации, если к перекрёстку в пределах видимости не приближаются по главной дороге транспортные средства?","a":["Да, должны перед дорожным знаком «Движение без остановки запрещено».","Да, должны перед краем пересекаемой проезжей части дороги.","Нет, не должны."],"c":1,"e":"<p>В показанной ситуации при наличии перед перекрёстком дорожного знака 2.5 «Движение без остановки запрещено» запрещается движение без остановки перед краем пересекаемой проезжей части дороги.</p>","image":"assets/adrive-questions/q200200461.webp"},{"id":200200601,"themeId":2,"group":2002006,"chapter":77,"chapters":[77],"q":"Какой из показанных на рисунке дорожных знаков обязывает водителя уступать дорогу транспортным средствам, движущимся по пересекаемой дороге?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":1,"e":"<p>Изображённый на рисунке под номером 2 дорожный знак 2.5 «Движение без остановки запрещено» обязывает водителя уступать дорогу транспортным средствам, движущимся по пересекаемой дороге.</p>","image":"assets/adrive-questions/q200200601.webp"},{"id":200200602,"themeId":2,"group":2002006,"chapter":77,"chapters":[77],"q":"Какой из показанных на рисунке дорожных знаков обязывает водителя уступать дорогу транспортным средствам, движущимся по пересекаемой дороге?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":3,"e":"<p>Изображённый на рисунке под номером 4 дорожный знак 2.4 «Уступить дорогу» обязывает водителя уступать дорогу транспортным средствам, движущимся по пересекаемой дороге.</p>","image":"assets/adrive-questions/q200200602.webp"},{"id":200200701,"themeId":2,"group":2002007,"chapter":77,"chapters":[77],"q":"Какие из показанных на рисунке дорожных знаков обязывают водителя уступать дорогу транспортным средствам, движущимся по пересекаемой дороге?","a":["Только дорожный знак 4.","Дорожные знаки 2 и 4.","Дорожные знаки 4 и 5.","Дорожные знаки 3 и 4.","Дорожные знаки 1, 4 и 5."],"c":2,"e":"<p>Изображённые на рисунке под номерами 4 и 5 дорожные знаки 2.4 «Уступить дорогу» и 2.5 «Движение без остановки запрещено» обязывают водителя уступать дорогу транспортным средствам, движущимся по пересекаемой дороге.</p>","image":"assets/adrive-questions/q200200701.webp"},{"id":200200702,"themeId":2,"group":2002007,"chapter":77,"chapters":[77],"q":"Какие из показанных на рисунке дорожных знаков обязывают водителя уступать дорогу транспортным средствам, движущимся по пересекаемой дороге?","a":["Только дорожный знак 2.","Дорожные знаки 2 и 3.","Дорожные знаки 1, 2 и 3.","Все показанные дорожные знаки."],"c":1,"e":"<p>Изображённые на рисунке под номерами 2 и 3 дорожные знаки 2.4 «Уступить дорогу» и 2.5 «Движение без остановки запрещено» обязывают водителя уступать дорогу транспортным средствам, движущимся по пересекаемой дороге.</p>","image":"assets/adrive-questions/q200200702.webp"},{"id":200200801,"themeId":2,"group":2002008,"chapter":77,"chapters":[77],"q":"Какие из показанных на рисунке дорожных знаков устанавливают очерёдность проезда перекрёстков и пересечений отдельных проезжих частей дорог?","a":["Только дорожный знак 2.","Дорожные знаки 2 и 4.","Дорожные знаки 2, 3 и 4.","Дорожные знаки 1, 2, 3 и 4.","Все показанные дорожные знаки."],"c":2,"e":"<p>Изображённые на рисунке под номерами 2, 3 и 4 дорожные знаки 2.1 «Главная дорога» , 2.3.4 «Пересечение равнозначных дорог» и 2.5 «Движение без остановки запрещено» устанавливают очерёдность проезда перекрёстков и пересечений отдельных проезжих частей дорог.</p>","image":"assets/adrive-questions/q200200801.webp"},{"id":200200802,"themeId":2,"group":2002008,"chapter":77,"chapters":[77],"q":"Какие из показанных на рисунке дорожных знаков устанавливают очерёдность проезда перекрёстков и пересечений отдельных проезжих частей дорог?","a":["Только дорожный знак 1.","Только дорожный знак 3.","Дорожные знаки 1 и 3.","Дорожные знаки 1, 2 и 3.","Все показанные дорожные знаки."],"c":3,"e":"<p>Изображённые на рисунке под номерами 1, 2 и 3 дорожные знаки 2.3.3 «Примыкание второстепенной дороги» , 2.3.4 «Пересечение равнозначных дорог» и 2.4 «Уступить дорогу» устанавливают очерёдность проезда перекрёстков и пересечений отдельных проезжих частей дорог.</p>","image":"assets/adrive-questions/q200200802.webp"},{"id":200200901,"themeId":2,"group":2002009,"chapter":77,"chapters":[77],"q":"Какие из показанных на рисунке дорожных знаков относятся к группе знаков приоритета?","a":["Только дорожный знак 4.","Дорожные знаки 4 и 5.","Дорожные знаки 1, 4 и 5.","Дорожные знаки 1, 2, 4 и 5.","Все показанные дорожные знаки."],"c":1,"e":"<p>Изображённые на рисунке под номерами 4 и 5 дорожные знаки 2.3.1 «Пересечение со второстепенной дорогой» и 2.3.4 «Пересечение равнозначных дорог» относятся к группе знаков приоритета.</p>","image":"assets/adrive-questions/q200200901.webp"},{"id":200200902,"themeId":2,"group":2002009,"chapter":77,"chapters":[77],"q":"Какие из показанных на рисунке дорожных знаков относятся к группе знаков приоритета?","a":["Только дорожный знак 3.","Дорожные знаки 1 и 4.","Дорожные знаки 1, 3 и 4.","Все показанные дорожные знаки."],"c":2,"e":"<p>Изображённые на рисунке под номерами 1, 3 и 4 дорожные знаки 2.6.1 «Преимущество встречного движения» , 2.5 «Движение без остановки запрещено» и 2.7 «Преимущество перед встречным движением» относятся к группе знаков приоритета.</p>","image":"assets/adrive-questions/q200200902.webp"},{"id":200201001,"themeId":2,"group":2002010,"chapter":77,"chapters":[77],"q":"При проезде показанного узкого участка дороги Вы:","a":["Имеете преимущество.","Обязаны уступить дорогу грузовому автомобилю."],"c":1,"e":"<p>Установленный дорожный знак «2.6.1 Преимущество встречного движения» обязывает Вас уступить дорогу встречному автомобилю.</p>","image":"assets/adrive-questions/q200201001.webp"},{"id":200201101,"themeId":2,"group":2002011,"chapter":77,"chapters":[77],"q":"Разрешается ли Вам въехать на мост одновременно с велосипедистом в показанной ситуации?","a":["Разрешается.","Запрещается, если это затруднит встречное движение."],"c":1,"e":"<p>Установленный дорожный знак 2.6.1 «Преимущество встречного движения» запрещает въезд на участок дороги, если это может затруднить встречное движение.</p> <p>Необходимо уступить дорогу встречному велосипедисту, находящемуся на данном участке дороги.</p>","image":"assets/adrive-questions/q200201101.webp"},{"id":200201102,"themeId":2,"group":2002011,"chapter":77,"chapters":[77],"q":"Разрешается ли Вам въехать на мост одновременно с мотоциклистом в показанной ситуации?","a":["Запрещается.","Разрешается только в случае, если это не затруднит встречное движение."],"c":1,"e":"<p>Установленный дорожный знак 2.6.1 «Преимущество встречного движения» не запрещает въехать на мост одновременно с мотоциклистом только в случае, если это не затруднит встречное движение.</p>","image":"assets/adrive-questions/q200201102.webp"},{"id":200201201,"themeId":2,"group":2002012,"chapter":77,"chapters":[77],"q":"В показанной ситуации водитель белого легкового автомобиля:","a":["Имеет преимущество.","Обязан уступить дорогу только первому грузовому автомобилю, въезжающему на мост.","Обязан уступить дорогу обоим встречным автомобилям."],"c":2,"e":"<p>Установленный дорожный знак 2.6.1 «Преимущество встречного движения» обязывает водителя уступить дорогу обоим встречным автомобилям.</p>","image":"assets/adrive-questions/q200201201.webp"},{"id":200201202,"themeId":2,"group":2002012,"chapter":77,"chapters":[77],"q":"Подъезжая к узкому участку дороги, обозначенному таким дорожным знаком, водитель обязан:","a":["Остановиться перед «стоп-линией», а при её отсутствии — перед знаком.","Уступить дорогу только транспортным средствам, находящимся на данном участке дороги.","Уступить дорогу транспортным средствам, находящимся на данном участке дороги или на противоположном подъезде к нему."],"c":2,"e":"<p>Показанный на рисунке дорожный знак 2.6.1 «Преимущество встречного движения» обязывает водителя уступить дорогу транспортным средствам, находящимся на данном участке дороги или на противоположном подъезде к нему.</p>","image":"assets/adrive-questions/q200201202.webp"},{"id":200201301,"themeId":2,"group":2002013,"chapter":77,"chapters":[77],"q":"Как Вы обязаны поступить в показанной ситуации, если на автомобиле скорой помощи маячки выключены?","a":["Проехать узкий участок дороги первым.","Уступить дорогу автомобилю скорой помощи."],"c":0,"e":"<p>В показанной ситуации перед узким участком дороги установлен дорожный знак 2.7 «Преимущество перед встречным движением» , который предоставляет преимущество водителю перед автомобилем скорой помощи с выключенными маячками.</p>","image":"assets/adrive-questions/q200201301.webp"},{"id":200201302,"themeId":2,"group":2002013,"chapter":77,"chapters":[77],"q":"При движении на спуск по участку дороги, обозначенному таким дорожным знаком, водитель:","a":["Имеет преимущество по отношению к встречным транспортным средствам.","Обязан уступить дорогу встречным транспортным средствам, если встречное движение затруднено."],"c":0,"e":"<p>Показанный на рисунке дорожный знак 2.7 «Преимущество перед встречным движением» предоставляет водителю преимущество по отношению к встречным транспортным средствам независимо от наличия и характера уклона дороги.</p>","image":"assets/adrive-questions/q200201302.webp"},{"id":200201401,"themeId":2,"group":2002014,"chapter":77,"chapters":[77],"q":"Какой из показанных на рисунке дорожных знаков предоставляет водителю преимущество в движении по отношению к встречным транспортным средствам?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":2,"e":"<p>Изображённый на рисунке под номером 3 дорожный знак 2.7 «Преимущество перед встречным движением» предоставляет водителю преимущество по отношению к встречным транспортным средствам.</p>","image":"assets/adrive-questions/q200201401.webp"},{"id":200201402,"themeId":2,"group":2002014,"chapter":77,"chapters":[77],"q":"Какие из показанных на рисунке дорожных знаков предоставляют водителю преимущество в движении по отношению к встречным транспортным средствам?","a":["Только дорожный знак 1.","Только дорожный знак 5.","Дорожные знаки 1 и 4.","Дорожные знаки 1, 4 и 5.","Все показанные дорожные знаки."],"c":1,"e":"<p>Изображённый на рисунке под номером 5 дорожный знак 2.7 «Преимущество перед встречным движением» предоставляет водителю преимущество по отношению к встречным транспортным средствам.</p>","image":"assets/adrive-questions/q200201402.webp"},{"id":200201501,"themeId":2,"group":2002015,"chapter":77,"chapters":[77],"q":"Кто в показанной ситуации пользуется преимуществом в движении?","a":["Водитель мотоцикла.","Водитель легкового автомобиля."],"c":1,"e":"<p>В показанной ситуации дорожный знак 2.1 «Главная дорога» , установленный совместно со знаком 5.22.1 «Начало населённого пункта» , предоставляет преимущественное право проезда всех перекрёстков населённого пункта, расположенных на данной дороге.</p> <p>Поэтому водитель легкового автомобиля пользуется преимуществом.</p>","image":"assets/adrive-questions/q200201501.webp"},{"id":200201601,"themeId":2,"group":2002016,"chapter":77,"chapters":[77],"q":"Показанный на рисунке дорожный знак, расположенный перед перекрёстком в населённом пункте, предоставляет преимущество при проезде:","a":["Только перекрёстка, перед которым установлен знак.","Всех перекрёстков, расположенных в населённом пункте.","Всех перекрёстков населённого пункта, расположенных на данной дороге."],"c":0,"e":"<p>Показанный на рисунке дорожный знак 2.1 «Главная дорога» , расположенный перед перекрёстком в населённом пункте, предоставляет преимущество при проезде только перекрёстка, перед которым установлен знак.</p>","image":"assets/adrive-questions/q200201601.webp"},{"id":200201602,"themeId":2,"group":2002016,"chapter":77,"chapters":[77],"q":"Показанное на рисунке сочетание дорожных знаков, расположенное перед началом населённого пункта, предоставляет преимущество при проезде:","a":["Только перекрёстка, перед которым установлен знак.","Всех перекрёстков, расположенных в населённом пункте.","Всех перекрёстков населённого пункта, расположенных на данной дороге."],"c":2,"e":"<p>Дорожный знак 2.1 «Главная дорога» , установленный совместно со знаком 5.22.1 «Начало населённого пункта» , предоставляет преимущественное право проезда всех перекрёстков населённого пункта, расположенных на данной дороге.</p>","image":"assets/adrive-questions/q200201602.webp"},{"id":200201661,"themeId":2,"group":2002016,"chapter":77,"chapters":[77],"q":"Показанное сочетание дорожных знаков предоставляет преимущество при проезде:","a":["Только первого перекрёстка населённого пункта, расположенного на данной дороге.","Всех перекрёстков населённого пункта, расположенных на данной дороге."],"c":1,"e":"<p>Знак 2.1 «Главная дорога», установленный со знаком 5.22.1 или 5.22.2 «Начало населённого пункта», предоставляет преимущество при проезде всех перекрёстков населённого пункта, расположенных на данной дороге.</p>","image":"assets/adrive-questions/q200201661.webp"},{"id":200201701,"themeId":2,"group":2002017,"chapter":77,"chapters":[77],"q":"Показанный на рисунке дорожный знак, установленный перед перекрёстком, предоставляет преимущественное право проезда:","a":["Регулируемого перекрёстка.","Нерегулируемого перекрёстка.","Всех без исключения перекрёстков."],"c":1,"e":"<p>Показанный на рисунке дорожный знак 2.1 «Главная дорога» , установленный перед перекрёстком, предоставляет преимущественное право проезда нерегулируемого перекрёстка.</p>","image":"assets/adrive-questions/q200201701.webp"},{"id":200201702,"themeId":2,"group":2002017,"chapter":77,"chapters":[77],"q":"Является ли обозначенным перекрёсток при работающих светофорах, если перед ним установлены дорожные знаки приоритета?","a":["Да, является.","Нет, не является."],"c":0,"e":"<p>Перекрёсток, если перед ним установлены дорожные знаки приоритета, при работающих светофорах является обозначенным.</p>","image":null},{"id":200201703,"themeId":2,"group":2002017,"chapter":77,"chapters":[77],"q":"В показанной ситуации дорожный знак «Главная дорога»:","a":["Информирует о том, что перекрёсток является обозначенным.","Предоставляет право преимущественного проезда перекрёстка.","Информирует о том, что перекрёсток является обозначенным и предоставляет право преимущественного проезда перекрёстка."],"c":0,"e":"<p>В показанной ситуации, когда движение на перекрёстке регулируется регулировщиком, дорожный знак 2.1 «Главная дорога» только информирует о том, что перекрёсток является обозначенным.</p>","image":"assets/adrive-questions/q200201703.webp"},{"id":200300102,"themeId":2,"group":2003001,"chapter":78,"chapters":[78],"q":"По какой траектории водителю синего легкового автомобиля разрешается въехать на территорию автозаправочной станции?","a":["Только по траектории «А».","Только по траектории «Б».","По любой из указанных траекторий."],"c":1,"e":"<p>Показанные на рисунке дорожные знаки 3.18.1 «Поворот направо запрещён» и 3.1 «Въезд запрещён» запрещают водителю синего легкового автомобиля двигаться по траектории «А».</p>","image":"assets/adrive-questions/q200300102.webp"},{"id":200300201,"themeId":2,"group":2003002,"chapter":78,"chapters":[78],"q":"Какие из показанных на рисунке дорожных знаков вводят или отменяют определённые ограничения дорожного движения?","a":["Только дорожный знак 1.","Только дорожный знак 2.","Дорожные знаки 1 и 5.","Дорожные знаки 1, 2 и 3.","Все показанные дорожные знаки."],"c":2,"e":"<p>Изображённые на рисунке под номерами 1 и 5 дорожные знаки 3.1 «Въезд запрещён» и 3.24.1 «Ограничение максимальной скорости» относятся к группе запрещающих знаков, которые вводят или отменяют определённые ограничения дорожного движения.</p>","image":"assets/adrive-questions/q200300201.webp"},{"id":200300202,"themeId":2,"group":2003002,"chapter":78,"chapters":[78],"q":"Какой из показанных на рисунке дорожных знаков вводит или отменяет определённые ограничения дорожного движения?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":0,"e":"<p>Изображённый на рисунке под номером 1 дорожный знак 3.24.2 «Ограничение максимальной скорости» относятся к группе запрещающих знаков, которые вводят или отменяют определённые ограничения дорожного движения.</p>","image":"assets/adrive-questions/q200300202.webp"},{"id":200300301,"themeId":2,"group":2003003,"chapter":78,"chapters":[78],"q":"В каких направлениях Вам разрешено проехать на перекрёстке в показанной ситуации?","a":["Только налево.","Прямо и налево.","Налево и на разворот.","Прямо, налево и на разворот.","Во всех направлениях."],"c":2,"e":"<p>В показанной ситуации установленный дорожный знак 3.2 «Движение запрещено» запрещает водителю двигаться прямо.</p>","image":"assets/adrive-questions/q200300301.webp"},{"id":200300302,"themeId":2,"group":2003003,"chapter":78,"chapters":[78],"q":"По каким траекториям, показанным стрелками, разрешено движение в показанной ситуации?","a":["Только по траектории «А».","Только по траектории «Б».","Только по траектории «В».","По траекториям «А» и «В».","По траекториям «Б» и «В»."],"c":3,"e":"<p>В показанной ситуации установленный дорожный знак 3.2 «Движение запрещено» запрещает водителю двигаться по траектории «Б».</p>","image":"assets/adrive-questions/q200300302.webp"},{"id":200300401,"themeId":2,"group":2003004,"chapter":78,"chapters":[78],"q":"В каких направлениях разрешено продолжать движение мотоциклисту?","a":["Направо и налево.","Направо, налево и на разворот.","Во всех направлениях."],"c":1,"e":"<p>В показанной ситуации установленный дорожный знак 3.3 «Движение механических транспортных средств запрещено» запрещает мотоциклисту движение прямо.</p>","image":"assets/adrive-questions/q200300401.webp"},{"id":200300402,"themeId":2,"group":2003004,"chapter":78,"chapters":[78],"q":"В каких направлениях разрешено продолжать движение водителю грузового автомобиля?","a":["Только прямо.","Прямо и налево.","Прямо и на разворот.","Налево и на разворот.","Во всех направлениях."],"c":2,"e":"<p>В показанной ситуации установленные дорожные знаки 3.3 «Движение механических транспортных средств запрещено» и 7.3.2 «Направление действия» запрещают движение водителю грузового автомобиля налево.</p>","image":"assets/adrive-questions/q200300402.webp"},{"id":200300501,"themeId":2,"group":2003005,"chapter":78,"chapters":[78],"q":"Разрешено ли каким-либо из перечисленных транспортных средств движение по дороге, обозначенной таким дорожным знаком?","a":["Разрешено автобусам.","Разрешено колёсным тракторам.","Разрешено грузовым автомобилям.","Разрешено всем перечисленным транспортным средствам.","Всем перечисленным транспортным средствам движение запрещено."],"c":4,"e":"<p>Показанный на рисунке дорожный знак 3.3 «Движение механических транспортных средств запрещено» запрещает движение механических транспортных средств (то есть транспортных средств, приводимых в движение двигателем).</p>","image":"assets/adrive-questions/q200300501.webp"},{"id":200300502,"themeId":2,"group":2003005,"chapter":78,"chapters":[78],"q":"Каким из перечисленных транспортных средств запрещено движение по дороге, обозначенной таким дорожным знаком?","a":["Мопедам.","Велосипедам, не оборудованным двигателем.","Гужевым транспортным средствам.","Всем транспортным средствам движение разрешено.","Всем транспортным средствам движение запрещено."],"c":0,"e":"<p>Показанный на рисунке дорожный знак 3.3 «Движение механических транспортных средств запрещено» запрещает движение механических транспортных средств (то есть транспортных средств, приводимых в движение двигателем).</p>","image":"assets/adrive-questions/q200300502.webp"},{"id":200300701,"themeId":2,"group":2003007,"chapter":78,"chapters":[78],"q":"Какой из показанных на рисунке дорожных знаков относится к группе запрещающих знаков?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":2,"e":"<p>Показанный на рисунке под номером 3 дорожный знак 3.2 «Движение запрещено» относится к группе запрещающих знаков.</p>","image":"assets/adrive-questions/q200300701.webp"},{"id":200300702,"themeId":2,"group":2003007,"chapter":78,"chapters":[78],"q":"Какие из показанных на рисунке дорожных знаков относятся к группе запрещающих знаков?","a":["Только дорожный знак 1.","Только дорожный знак 2.","Дорожные знаки 2 и 3.","Дорожные знаки 2 и 4.","Дорожные знаки 2, 3 и 5."],"c":3,"e":"<p>На рисунке под номером 2 и 4 изображены дорожные знаки 3.9 «Движение велосипедов запрещено» и 3.31 «Конец зоны всех ограничений» , которые относятся к группе запрещающих знаков.</p>","image":"assets/adrive-questions/q200300702.webp"},{"id":200300741,"themeId":2,"group":2003007,"chapter":78,"chapters":[78],"q":"Какие из показанных дорожных знаков относятся к группе «Запрещающие знаки»?","a":["Только знак 3.","Знаки 3 и 4.","Знаки 3 и 5.","Знаки 3, 4 и 5.","Все показанные знаки."],"c":2,"e":"<p>К запрещающим дорожным знакам относятся третий («3.2 Движение запрещено» ) и пятый («3.33 Зона с ограничением максимальной скорости движения» ) дорожные знаки.</p>","image":"assets/adrive-questions/q200300741.webp"},{"id":200300801,"themeId":2,"group":2003008,"chapter":78,"chapters":[78],"q":"Что означает надпись на данном дорожном знаке?","a":["Массу перевозимого груза.","Фактическую массу транспортного средства.","Фактическую нагрузку на ось транспортного средства.","Массу транспортного средства в снаряжённом состоянии.","Технически допустимую общую массу транспортного средства."],"c":1,"e":"<p>На дорожном знаке 3.11.1 «Ограничение массы» указана фактическая масса транспортного средства.</p>","image":"assets/adrive-questions/q200300801.webp"},{"id":200300802,"themeId":2,"group":2003008,"chapter":78,"chapters":[78],"q":"Разрешается ли водителю грузового автомобиля с технически допустимой общей массой до 3.5 тонны при движении с прицепом повернуть направо в показанной ситуации?","a":["Да, разрешается.","Нет, запрещается."],"c":1,"e":"<p>В показанной ситуации установленные дорожные знаки 3.7 «Движение с прицепом запрещено» и 7.3.1 «Направление действия» запрещают водителю грузового автомобиля повернуть направо.</p>","image":"assets/adrive-questions/q200300802.webp"},{"id":200300901,"themeId":2,"group":2003009,"chapter":78,"chapters":[78],"q":"В каких направлениях Вам разрешено продолжить движение, управляя легковым автомобилем, после включения разрешающего сигнала светофора?","a":["Только прямо и направо.","Только прямо и на разворот.","Прямо, направо и на разворот.","Во всех направлениях."],"c":2,"e":"<p>В показанной ситуации установленный дорожный знак 3.18.2 «Поворот налево запрещён» запрещает водителю поворот налево, при этом разворот разрешён.</p>","image":"assets/adrive-questions/q200300901.webp"},{"id":200300902,"themeId":2,"group":2003009,"chapter":78,"chapters":[78],"q":"В каких направлениях разрешено продолжить движение водителю легкового автомобиля в показанной ситуации?","a":["Только прямо.","Только налево.","Прямо и налево.","Во всех направлениях."],"c":2,"e":"<p>В показанной ситуации установленный дорожный знак 3.19 «Разворот запрещён» запрещает разворот, при этом поворот налево разрешён.</p>","image":"assets/adrive-questions/q200300902.webp"},{"id":200301001,"themeId":2,"group":2003010,"chapter":78,"chapters":[78],"q":"В каком случае Вы, управляя легковым автомобилем, не нарушите Правила дорожного движения, совершив обгон автобуса в показанной ситуации?","a":["Если скорость движения автобуса менее 30 км/ч.","Если скорость движения автобуса превышает 30 км/ч.","Нарушите в любом случае.","Не нарушите в любом случае."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 3.20.1 «Обгон запрещён» не запрещает обгон автобуса, если скорость его движения менее 30 км/ч.</p>","image":"assets/adrive-questions/q200301001.webp"},{"id":200301002,"themeId":2,"group":2003010,"chapter":78,"chapters":[78],"q":"Разрешено ли Вам, управляя легковым автомобилем, совершить обгон автобуса, движущегося с включённой аварийной световой сигнализацией, в показанной ситуации?","a":["Разрешено, если скорость движения автобуса менее 30 км/ч.","Разрешено, если скорость движения легкового автомобиля превышает 30 км/ч.","Запрещено в любом случае."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 3.20.1 «Обгон запрещён» не запрещает обгон автобуса, если скорость его движения менее 30 км/ч.</p>","image":"assets/adrive-questions/q200301002.webp"},{"id":200301101,"themeId":2,"group":2003011,"chapter":78,"chapters":[78],"q":"Какие действия мотоциклиста не противоречат Правилам дорожного движения?","a":["Обгонит трактор, скорость движения которого менее 30 км/ч.","Опередит трактор без выезда на встречную полосу движения.","Оба перечисленных действия не противоречат Правилам дорожного движения."],"c":2,"e":"<p>В показанной ситуации установленный дорожный знак 3.20.1 «Обгон запрещён» не запрещает обгон, если скорость движения трактора менее 30 км/ч, и не запрещает опережение.</p>","image":"assets/adrive-questions/q200301101.webp"},{"id":200301102,"themeId":2,"group":2003011,"chapter":78,"chapters":[78],"q":"Разрешено ли водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны совершить обгон трактора в показанной ситуации?","a":["Разрешено.","Запрещено.","Разрешено в том случае, если скорость движения трактора менее 30 км/ч."],"c":2,"e":"<p>Обгон в зоне действия дорожного знака 3.20.1 «Обгон запрещён» не запрещён, если обгоняемое транспортное средство одиночное и движется со скоростью менее 30 км/ч.</p>","image":"assets/adrive-questions/q200301102.webp"},{"id":200301161,"themeId":2,"group":2003011,"chapter":78,"chapters":[78],"q":"Разрешено ли водителю легкового автомобиля в показанной ситуации совершить обгон сразу двух транспортных средств?","a":["Разрешено.","Запрещено.","Разрешено, если скорость обгоняемых транспортных средств менее 30 км/ч."],"c":1,"e":"<p>В зоне действия дорожного знака 3.20.1 «Обгон запрещён» совершить обгон не запрещёно, если обгоняемое транспортное средство движется как одиночное со скоростью менее 30 км/ч. Но обогнать два подряд транспортных средства запрещено, даже если их скорость менее 30 км/ч.</p>","image":"assets/adrive-questions/q200301161.webp"},{"id":200301201,"themeId":2,"group":2003012,"chapter":78,"chapters":[78],"q":"Разрешено ли Вам совершить обгон автобуса в показанной ситуации?","a":["Да, разрешено.","Разрешено только в том случае, если скорость движения автобуса не превышает 50 км/ч.","Нет, не разрешено."],"c":1,"e":"<p>В показанной ситуации установленный дорожный знак 3.20.3 «Обгон запрещён» разрешает обгон только в том случае, если скорость движения автобуса не превышает 50 км/ч.</p>","image":"assets/adrive-questions/q200301201.webp"},{"id":200301202,"themeId":2,"group":2003012,"chapter":78,"chapters":[78],"q":"Показанный на рисунке дорожный знак запрещает:","a":["Обгон и движение со скоростью, превышающей указанную на знаке.","Обгон транспортных средств, скорость движения которых больше указанной на знаке.","Движение водителю, совершающему обгон, со скоростью, превышающей указанную на знаке."],"c":1,"e":"<p>Показанный на рисунке дорожный знак 3.20.3 «Обгон запрещён» запрещает обгон транспортных средств, скорость движения которых больше указанной на знаке.</p>","image":"assets/adrive-questions/q200301202.webp"},{"id":200301371,"themeId":2,"group":2003013,"chapter":78,"chapters":[78],"q":"В зоне действия показанного стрелкой дорожного знака звуковой сигнал разрешено использовать:","a":["Только для предупреждения об обгоне.","Только для предотвращения дорожно-транспортного происшествия.","В обоих перечисленных случаях."],"c":1,"e":"<p>В зоне действия дорожного знака «3.26 Подача звукового сигнала запрещена» в качестве исключения разрешено использовать звуковой сигнал только <strong>для предотвращения дорожно-транспортного происшествия</strong>.</p>","image":"assets/adrive-questions/q200301371.webp"},{"id":200301401,"themeId":2,"group":2003014,"chapter":78,"chapters":[78],"q":"Показанный на рисунке дорожный знак запрещает обгон:","a":["Грузовым автомобилям с технически допустимой общей массой более 3.5 тонны.","Грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны.","Всем грузовым автомобилям."],"c":0,"e":"<p>Показанный на рисунке дорожный знак 3.22 «Обгон грузовым автомобилям запрещён» запрещает обгон грузовым автомобилям с технически допустимой общей массой более 3.5 тонны.</p>","image":"assets/adrive-questions/q200301401.webp"},{"id":200301402,"themeId":2,"group":2003014,"chapter":78,"chapters":[78],"q":"Нарушит ли Правила дорожного движения водитель грузового автомобиля с технически допустимой общей массой до 3.5 тонны, совершив обгон легкового автомобиля в показанной ситуации?","a":["Не нарушит.","Нарушит только в случае, если скорость легкового автомобиля более 30 км/ч.","Нарушит в любом случае."],"c":0,"e":"<p>Показанный на рисунке дорожный знак 3.22 «Обгон грузовым автомобилям запрещён» запрещает обгон грузовым автомобилям с технически допустимой общей массой более 3.5 тонны.</p>","image":"assets/adrive-questions/q200301402.webp"},{"id":200301501,"themeId":2,"group":2003015,"chapter":78,"chapters":[78],"q":"Запрещает ли показанный на рисунке дорожный знак обгон каким-либо из перечисленных транспортных средств?","a":["Запрещает автобусам.","Запрещает легковым автомобилям.","Запрещает грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны.","Запрещает всем перечисленным транспортным средствам.","Всем перечисленным транспортным средствам обгон разрешён."],"c":4,"e":"<p>Показанный на рисунке дорожный знак 3.22 «Обгон грузовым автомобилям запрещён» запрещает обгон грузовым автомобилям, технически допустимая общая масса которых превышает 3.5 тонны, а также тракторам и самоходным машинам.</p>","image":"assets/adrive-questions/q200301501.webp"},{"id":200301502,"themeId":2,"group":2003015,"chapter":78,"chapters":[78],"q":"Разрешено ли Вам, управляя легковым автомобилем, совершить обгон автобуса в показанной ситуации?","a":["Да, разрешено.","Разрешено только в том случае, если скорость движения автобуса не превышает 50 км/ч.","Нет, не разрешено."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 3.22 «Обгон грузовым автомобилям запрещён» не запрещает произвести обгон автобуса легковому автомобилю.</p>","image":"assets/adrive-questions/q200301502.webp"},{"id":200301601,"themeId":2,"group":2003016,"chapter":78,"chapters":[78],"q":"Укажите наиболее правильное значение данного сочетания дорожных знаков:","a":["Обгон запрещён со скоростью более 50 км/ч.","Обгон запрещён, движение со скоростью более 50 км/ч запрещено.","Запрещён обгон транспортных средств, кроме одиночных, движущихся со скоростью не более 50 км/ч."],"c":1,"e":"<p>Дорожный знак 3.20.1 «Обгон запрещён» запрещает обгон всех транспортных средств, кроме одиночных, движущихся со скоростью менее 30 км/ч.</p> <p>Дорожный знак 3.24.1 «Ограничение максимальной скорости» запрещает движение со скоростью, превышающей указанную на знаке.</p>","image":"assets/adrive-questions/q200301601.webp"},{"id":200301602,"themeId":2,"group":2003016,"chapter":78,"chapters":[78],"q":"В каком из перечисленных случаев водитель легкового автомобиля нарушит Правила дорожного движения в показанной ситуации?","a":["Двигаясь со скоростью 50 км/ч.","Двигаясь со скоростью более 50 км/ч.","Двигаясь со скоростью менее 50 км/ч."],"c":1,"e":"<p>В показанной ситуации установленный дорожный знак 3.24.1 «Ограничение максимальной скорости» запрещает движение со скоростью, превышающей указанную на знаке.</p>","image":"assets/adrive-questions/q200301602.webp"},{"id":200301701,"themeId":2,"group":2003017,"chapter":78,"chapters":[78],"q":"Разрешается ли Вам остановиться в зоне действия показанного дорожного знака?","a":["Разрешается для посадки и высадки пассажиров.","Разрешается только для посадки и высадки инвалида.","Запрещается."],"c":2,"e":"<p>В показанной ситуации установленный дорожный знак 3.27 «Остановка запрещена» запрещает остановку всех транспортных средств, за исключением маршрутных и автомобилей-такси с включённым таксометром (активным заказом электронной информационной системы с функцией оплаты в безналичном порядке) для посадки (высадки) пассажиров, если это не создаст препятствия другим участникам дорожного движения.</p>","image":"assets/adrive-questions/q200301701.webp"},{"id":200301702,"themeId":2,"group":2003017,"chapter":78,"chapters":[78],"q":"В зоне действия какого из показанных дорожных знаков запрещено совершить остановку 25 октября?","a":["В зоне действия дорожного знака 1.","В зоне действия дорожного знака 2.","В зоне действия дорожного знака 3.","В зоне действия дорожных знаков 1 и 2."],"c":0,"e":"<p>На рисунке под номером 1 изображён дорожный знак 3.27 «Остановка запрещена» , который запрещает остановку транспортных средств во все дни месяца.<br> Знаки под номерами 2 и 3 запрещают только стоянку по нечётным и чётным числам месяца соответственно. Остановку они не запрещают.</p>","image":"assets/adrive-questions/q200301702.webp"},{"id":200301802,"themeId":2,"group":2003018,"chapter":78,"chapters":[78],"q":"Что запрещается в зоне действия показанного на рисунке дорожного знака?","a":["Стоянка по чётным числам месяца.","Стоянка по нечётным числам месяца.","Остановка по чётным числам месяца.","Остановка по нечётным числам месяца."],"c":0,"e":"<p>Показанный на рисунке дорожный знак 3.30 «Стоянка запрещена по чётным числам месяца» запрещает стоянку транспортных средств по чётным числам месяца.</p>","image":"assets/adrive-questions/q200301802.webp"},{"id":200301831,"themeId":2,"group":2003018,"chapter":78,"chapters":[78],"q":"Водителям каких транспортных средств разрешается поставить их на стоянку на показанном участке дороги в населённом пункте 22 мая в 18 часов 30 минут?","a":["Разрешается всем водителям.","Разрешается водителю транспортного средства с опознавательным знаком «Инвалид».","Запрещается всем водителям."],"c":1,"e":"<p>Дорожный знак 3.30 «Стоянка запрещена по чётным числам месяца» запрещает стоянку транспортных средств по чётным числам месяца, кроме транспортных средств с опознавательным знаком «Инвалид».</p>","image":"assets/adrive-questions/q200301831.webp"},{"id":200301901,"themeId":2,"group":2003019,"chapter":78,"chapters":[78],"q":"Разрешается ли поставить на стоянку автомобиль в показанной ситуации 22 мая в 17 часов 30 минут в населённом пункте?","a":["Разрешается.","Разрешается только автомобиль с опознавательным знаком «Инвалид».","Запрещается."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 3.29 «Стоянка запрещена по нечётным числам месяца» запрещает стоянку транспортных средств только по нечётным числам месяца.</p>","image":"assets/adrive-questions/q200301901.webp"},{"id":200301903,"themeId":2,"group":2003019,"chapter":78,"chapters":[78],"q":"Разрешено ли выполнить посадку пассажиров в зоне действия показанного дорожного знака, если это займёт более 5 минут?","a":["Разрешено.","Разрешено только автомобилям-такси.","Разрешено только по чётным числам месяца.","Разрешено только по нечётным числам месяца.","Запрещено."],"c":0,"e":"<p>Показанный на рисунке дорожный знак 3.29 «Стоянка запрещена по нечётным числам месяца» запрещает стоянку транспортных средств по нечётным числам месяца, остановка при этом разрешается.</p>","image":"assets/adrive-questions/q200301903.webp"},{"id":200301932,"themeId":2,"group":2003019,"chapter":78,"chapters":[78],"q":"Каким транспортным средствам разрешается произвести остановку в зоне действия показанного на рисунке дорожного знака?","a":["Такси с включенным таксометром (активным заказом электронной информационной системы с функцией оплаты в безналичном порядке) для посадки (высадки) пассажиров, если это не создаст препятствия другим участникам дорожного движения.","Маршрутным транспортным средствам.","Грузовым автомобилям, предназначенным для перевозки пассажиров.","Всем перечисленным транспортным средствам."],"c":3,"e":"<p>Показанный на рисунке дорожный знак 3.29 «Стоянка запрещена по нечётным числам месяца» запрещает стоянку транспортных средств по нечётным числам месяца, остановка при этом разрешается.</p>","image":"assets/adrive-questions/q200301932.webp"},{"id":200302001,"themeId":2,"group":2003020,"chapter":78,"chapters":[78],"q":"Разрешается ли переставить транспортное средство на стоянку на противоположную обочину дороги в населённом пункте 22 июня в 18 часов?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>При одновременном применении дорожных знаков 3.29 «Стоянка запрещена по нечётным числам месяца» и 3.30 «Стоянка запрещена по чётным числам месяца» на противоположных сторонах дороги транспортные средства должны быть переставлены с одной стороны дороги на другую в период времени с 19 до 24 часов.</p>","image":"assets/adrive-questions/q200302001.webp"},{"id":200302002,"themeId":2,"group":2003020,"chapter":78,"chapters":[78],"q":"Какой промежуток времени установлен Правилами дорожного движения для перестановки транспортных средств на другую сторону дороги при одновременном применении показанных на рисунке дорожных знаков?","a":["С 23 до 24 часов.","С 21 до 24 часов.","С 19 до 24 часов.","С 22 до 02 часов."],"c":2,"e":"<p>При одновременном применении дорожных знаков 3.29 «Стоянка запрещена по нечётным числам месяца» и 3.30 «Стоянка запрещена по чётным числам месяца» на противоположных сторонах дороги транспортные средства должны быть переставлены с одной стороны дороги на другую в период времени с 19 до 24 часов.</p>","image":"assets/adrive-questions/q200302002.webp"},{"id":200302101,"themeId":2,"group":2003021,"chapter":78,"chapters":[78],"q":"Водители каких автомобилей в показанной ситуации правильно поставили автомобили на стоянку 23 июня в 20 часов 30 минут в показанной ситуации?","a":["Водитель синего автомобиля.","Водитель зелёного автомобиля.","Водители обоих автомобилей."],"c":2,"e":"<p>При одновременном применении дорожных знаков 3.29 «Стоянка запрещена по нечётным числам месяца» и 3.30 «Стоянка запрещена по чётным числам месяца» на противоположных сторонах дороги транспортные средства должны быть переставлены с одной стороны дороги на другую в период времени с 19 до 24 часов.</p> <p>Таким образом, стоянка в указанный период времени разрешена на обеих сторонах дороги.</p>","image":"assets/adrive-questions/q200302101.webp"},{"id":200302102,"themeId":2,"group":2003021,"chapter":78,"chapters":[78],"q":"В показанной ситуации в зоне действия дорожного знака, показанного на рисунке, 23 июня в 12 часов разрешена:","a":["Стоянка.","Остановка.","Остановка и стоянка."],"c":1,"e":"<p>В показанной ситуации установленный дорожный знак 3.29 «Стоянка запрещена по нечётным числам месяца» запрещает стоянку транспортных средств по нечётным числам месяца, остановка при этом разрешается.</p>","image":"assets/adrive-questions/q200302102.webp"},{"id":200302161,"themeId":2,"group":2003021,"chapter":78,"chapters":[78],"q":"Разрешено ли Вам поставить автомобиль в населённом пункте на стоянку в указанном месте в нечётное число месяца?","a":["Да, разрешено.","Нет, не разрешено.","Разрешено только после 19 часов."],"c":2,"e":"<p>Показанный справа дорожный знак запрещает стоянку справа у тротуара только по нечётным числам месяца.</p> <p>При одновременном применении знаков 3.29 и 3.30 на противоположных сторонах дороги транспортные средства должны быть переставлены с одной её стороны на другую в период с 19 до 24 часов.</p> <p>Поэтому в показанной ситуации транспортное средство разрешено поставить на стоянку после 19 часов.</p>","image":"assets/adrive-questions/q200302161.webp"},{"id":200302201,"themeId":2,"group":2003022,"chapter":78,"chapters":[78],"q":"Под каким номером изображён дорожный знак, при проезде места установки которого не заканчивается зона действия дорожного знака «Ограничение максимальной скорости»?","a":["Под номером 1.","Под номером 2.","Под номером 3.","Под номером 4.","Под номером 5."],"c":1,"e":"<p>На рисунке под номером 2 изображён дорожный знак 2.3.1 «Пересечение со второстепенной дорогой» , при проезде места установки которого не заканчивается зона действия дорожного знака 3.24.1 «Ограничение максимальной скорости» , так как он устанавливается заблаговременно до обозначенного перекрёстка на расстоянии от 150 до 300 метров.</p> <p>Зона действия дорожного знака 3.24.1 «Ограничение максимальной скорости» будет распространяться непосредственно до обозначенного перекрёстка.</p>","image":"assets/adrive-questions/q200302201.webp"},{"id":200302202,"themeId":2,"group":2003022,"chapter":78,"chapters":[78],"q":"Под каким номером изображён дорожный знак, при проезде места установки которого заканчивается зона действия дорожного знака «Ограничение максимальной скорости»?","a":["Под номером 1.","Под номером 2.","Под номером 3.","Под номером 4.","Под номером 5."],"c":2,"e":"<p>На рисунке под номером 3 изображён дорожный знак 3.31 «Конец зоны всех ограничений» , при проезде места установки которого заканчивается зона действия дорожного знака 3.24.1 «Ограничение максимальной скорости» .</p>","image":"assets/adrive-questions/q200302202.webp"},{"id":200302301,"themeId":2,"group":2003023,"chapter":78,"chapters":[78],"q":"Под каким номером изображён дорожный знак, окончание зоны действия которого обозначают дорожным знаком «Конец зоны всех ограничений»?","a":["Под номером 1.","Под номером 2.","Под номером 3.","Под номером 4.","Под номером 5."],"c":0,"e":"<p>На рисунке под номером 1 изображён дорожный знак 3.26 «Подача звукового сигнала запрещена» , зона действия которого заканчивается при проезде места установки дорожного знака 3.31 «Конец зоны всех ограничений» .</p>","image":"assets/adrive-questions/q200302301.webp"},{"id":200302302,"themeId":2,"group":2003023,"chapter":78,"chapters":[78],"q":"Зона действия каких из показанных дорожных знаков заканчивается в месте установки дорожного знака «Конец зоны всех ограничений»?","a":["Только дорожного знака 2.","Дорожных знаков 1 и 2.","Дорожных знаков 4 и 5.","Всех показанных на рисунке дорожных знаков."],"c":3,"e":"<p>На рисунке изображены дорожные знаки 3.16 «Ограничение минимальной дистанции» , 3.20.3 «Обгон запрещён» , 3.26 «Подача звукового сигнала запрещена» , 3.27 «Остановка запрещена» , 3.29 «Стоянка запрещена по нечётным числам месяца» , зона действия которых заканчивается в месте установки дорожного знака 3.31 «Конец зоны всех ограничений» .</p>","image":"assets/adrive-questions/q200302302.webp"},{"id":200302401,"themeId":2,"group":2003024,"chapter":78,"chapters":[78],"q":"Разрешается ли Вам, управляя легковым автомобилем, повернуть налево в показанной ситуации, если Вы проживаете в доме, расположенном за дорожным знаком?","a":["Да, разрешается.","Нет, запрещается."],"c":1,"e":"<p>В показанной ситуации установленный дорожный знак 3.18.2 «Поворот налево запрещён» запрещает повернуть налево, даже если Вы проживаете в доме, расположенном за дорожным знаком.</p> <p>Как правило, в таком случае для проезда к жилым домам будет организован подъезд с иного направления.</p>","image":"assets/adrive-questions/q200302401.webp"},{"id":200302402,"themeId":2,"group":2003024,"chapter":78,"chapters":[78],"q":"Разрешается ли водителю легкового автомобиля повернуть направо в показанной ситуации, если он проживает в доме, расположенном за дорожным знаком, изображённым на рисунке, при отсутствии иных возможностей подъезда?","a":["Да, разрешается.","Нет, запрещается."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 3.2 «Движение запрещено» разрешает водителю легкового автомобиля повернуть направо, если он проживает в доме, расположенном за знаком, при отсутствии иных возможностей подъезда.</p>","image":"assets/adrive-questions/q200302402.webp"},{"id":200302403,"themeId":2,"group":2003024,"chapter":78,"chapters":[78],"q":"Разрешается ли Вам, управляя легковым автомобилем, повернуть на перекрёстке направо, если Вы работаете в здании, расположенном за перекрёстком?","a":["Да, разрешено.","Нет, запрещено."],"c":1,"e":"<p>Дорожный знак 3.18.1 «Поворот направо запрещён» не действует только на маршрутные транспортные средства. Если Вы работаете или проживаете в зоне, расположенной справа от перекрёстка, то Вы должны либо подъехать с другого направления, либо следовать к месту назначения пешком, оставив автомобиль в месте, где разрешена стоянка транспортных средств.</p>","image":"assets/adrive-questions/q200302403.webp"},{"id":200302542,"themeId":2,"group":2003025,"chapter":78,"chapters":[78],"q":"Разрешается ли водителю средства персональной мобильности продолжить движение прямо в показанной ситуации?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>Показанный запрещающий дорожный знак «3.35 Движение на средствах персональной мобильности запрещено» запрещает движение на средствах персональной мобильности.</p>","image":"assets/adrive-questions/q200302542.webp"},{"id":200302543,"themeId":2,"group":2003025,"chapter":78,"chapters":[78],"q":"Разрешено ли передвижение на средстве персональной мобильности по элементу дороги, обозначенному показанным запрещающим знаком?","a":["Нет, не разрешено.","Разрешено, не создавая препятствия пешеходам."],"c":0,"e":"<p>Верхний дорожный знак «3.35 Движение на средствах персональной мобильности запрещено» запрещает передвижение на средствах персональной мобильности по показанному элементу дороги.</p>","image":"assets/adrive-questions/q200302543.webp"},{"id":200302601,"themeId":2,"group":2003026,"chapter":78,"chapters":[78],"q":"Какие из показанных на рисунке дорожных знаков не распространяют своё действие на транспортные средства, принадлежащие гражданам, проживающим в обозначенной зоне, при отсутствии иных возможностей их подъезда?","a":["Дорожные знаки 1 и 5.","Дорожные знаки 3 и 4.","Дорожные знаки 2 и 4.","Дорожные знаки 2, 3 и 4.","Все показанные на рисунке дорожные знаки."],"c":2,"e":"<p>На рисунке под номерами 2 и 4 изображены дорожные знаки 3.7 «Движение с прицепом запрещено» и 3.5 «Движение мотоциклов запрещено» , которые не распространяют своё действие на транспортные средства, принадлежащие гражданам, проживающим в обозначенной зоне, при отсутствии иных возможностей их подъезда.</p>","image":"assets/adrive-questions/q200302601.webp"},{"id":200302602,"themeId":2,"group":2003026,"chapter":78,"chapters":[78],"q":"Какой из показанных на рисунке дорожных знаков не распространяет своё действие на транспортные средства, принадлежащие гражданам, проживающим в обозначенной зоне, при отсутствии иных возможностей их подъезда?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":3,"e":"<p>На рисунке под номером 4 изображён дорожный знак 3.4 «Движение грузовых автомобилей запрещено» , который не распространяет своё действие на транспортные средства, принадлежащие гражданам, проживающим в обозначенной зоне, при отсутствии иных возможностей их подъезда.</p>","image":"assets/adrive-questions/q200302602.webp"},{"id":200302701,"themeId":2,"group":2003027,"chapter":78,"chapters":[78],"q":"Разрешается ли поставить транспортное средство на стоянку в населённом пункте на правой обочине в зоне действия показанного на рисунке дорожного знака?","a":["Да, разрешается.","Нет, не разрешается.","Разрешается водителю транспортного средства с опознавательным знаком «Инвалид»."],"c":2,"e":"<p>В показанной ситуации установленный дорожный знак 3.28 «Стоянка запрещена» запрещает стоянку транспортных средств, кроме транспортных средств с опознавательным знаком «Инвалид».</p>","image":"assets/adrive-questions/q200302701.webp"},{"id":200302732,"themeId":2,"group":2003027,"chapter":78,"chapters":[78],"q":"В какой из показанных точек разрешено поставить автомобиль с опознавательным знаком «Инвалид» на стоянку в населённом пункте?","a":["Только в точке «А».","Только в точке «Б».","В любой из показанных точек.","В любой из показанных точек стоянка запрещена."],"c":2,"e":"<p>В показанной ситуации установленный дорожный знак 3.28 «Стоянка запрещена» запрещает стоянку транспортных средств, кроме транспортных средств с опознавательным знаком «Инвалид».</p> <p>Стоянка транспортного средства перед дорожным знаком не запрещена, если при этом дорожный знак будет виден иным участникам дорожного движения.</p>","image":"assets/adrive-questions/q200302732.webp"},{"id":200302831,"themeId":2,"group":2003028,"chapter":78,"chapters":[78],"q":"Каким транспортным средствам разрешена остановка в зоне действия показанного на рисунке дорожного знака?","a":["Такси с включённым таксометром для посадки (высадки) пассажиров, если это не создаст препятствия другим участникам дорожного движения.","Грузовым автомобилям, предназначенным для перевозки пассажиров.","Экскурсионным и туристическим автобусам.","Всем перечисленным транспортным средствам."],"c":0,"e":"<p>Дорожный знак 3.27 «Остановка запрещена» не запрещает остановку такси с включённым таксометром (активным заказом электронной информационной системы с функцией оплаты в безналичном порядке) для посадки (высадки) пассажиров, если это не создаст препятствия другим участникам дорожного движения.</p>","image":"assets/adrive-questions/q200302831.webp"},{"id":200302832,"themeId":2,"group":2003028,"chapter":78,"chapters":[78],"q":"Каким транспортным средствам разрешена остановка в зоне действия показанного дорожного знака?","a":["Такси с включённым таксометром для посадки (высадки) пассажиров, если это не создаст препятствия другим участникам дорожного движения.","Транспортным средствам с опознавательным знаком «Инвалид».","Транспортным средствам, обслуживающим организации, расположенные на участке дороги в зоне действия знака.","Всем перечисленным транспортным средствам."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 3.27 «Остановка запрещена» запрещает остановку транспортных средств, кроме такси с включённым таксометром (активным заказом электронной информационной системы с функцией оплаты в безналичном порядке) для посадки (высадки) пассажиров, если это не создаст препятствия другим участникам дорожного движения.</p>","image":"assets/adrive-questions/q200302832.webp"},{"id":200302901,"themeId":2,"group":2003029,"chapter":78,"chapters":[78],"q":"Разрешается ли в указанном месте остановить автомобиль для посадки (высадки) пассажиров?","a":["Разрешается.","Запрещается.","Разрешается только в случае, если это займёт не более 5 минут."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 3.28 «Стоянка запрещена» запрещает стоянку транспортных средств, остановка при этом разрешается.</p>","image":"assets/adrive-questions/q200302901.webp"},{"id":200302902,"themeId":2,"group":2003029,"chapter":78,"chapters":[78],"q":"Разрешается ли в указанном месте остановить транспортное средство для посадки (высадки) пассажиров на время более 5 минут?","a":["Разрешается остановить любое транспортное средство.","Разрешается остановить только транспортное средство с опознавательным знаком «Инвалид».","Запрещается."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 3.28 «Стоянка запрещена» запрещает стоянку транспортных средств, остановка при этом разрешается.</p>","image":"assets/adrive-questions/q200302902.webp"},{"id":200302941,"themeId":2,"group":2003029,"chapter":78,"chapters":[78],"q":"Что означает дорожный знак с жёлтым фоном в показанной дорожной ситуации?","a":["Запрещается фотографирование в зоне действия знака.","Запрещается пользование видеорегистратором в зоне действия знака.","Осуществляется контроль соблюдения требований дорожного знака «Остановка запрещена» с использованием технических средств в автоматическом режиме."],"c":2,"e":"<p>Показанный дорожный знак «1.37 Контроль выполнения требований Правил дорожного движения» предупреждает о въезде на участок дороги, на котором осуществляется контроль соблюдения Правил дорожного движения с использованием технических средств в автоматическом режиме.</p> <p>Может устанавливаться совместно со светофорами либо знаками, соблюдение требований которых контролируется (то есть в показанной ситуации осуществляется контроль выполнения требований знака «3.27 Остановка запрещена» ).</p>","image":"assets/adrive-questions/q200302941.webp"},{"id":200303001,"themeId":2,"group":2003030,"chapter":78,"chapters":[78],"q":"Действие каких дорожных знаков из показанных на рисунке не распространяется на транспортные средства с опознавательным знаком «Инвалид»?","a":["Дорожных знаков 1 и 2.","Дорожных знаков 2 и 5.","Дорожных знаков 1, 2 и 5.","Дорожных знаков 2, 4 и 5.","Всех показанных на рисунке дорожных знаков."],"c":1,"e":"<p>На рисунке под номерами 2 и 5 изображены дорожные знаки 3.2 «Движение запрещено» и 3.28 «Стоянка запрещена» , действие которых не распространяется на транспортные средства с опознавательным знаком «Инвалид».</p>","image":"assets/adrive-questions/q200303001.webp"},{"id":200303002,"themeId":2,"group":2003030,"chapter":78,"chapters":[78],"q":"Действие каких дорожных знаков из показанных на рисунке не распространяется на транспортные средства с опознавательным знаком «Инвалид»?","a":["Дорожных знаков 1 и 2.","Дорожных знаков 2 и 3.","Дорожных знаков 2, 3 и 4.","Дорожных знаков 2, 3 и 5.","Всех показанных на рисунке знаков."],"c":3,"e":"<p>На рисунке под номерами 2, 3 и 5 изображены дорожные знаки 3.2 «Движение запрещено» , 3.3 «Движение механических транспортных средств запрещено» и 3.30 «Стоянка запрещена по чётным числам месяца» , действие которых не распространяется на транспортные средства с опознавательным знаком «Инвалид».</p>","image":"assets/adrive-questions/q200303002.webp"},{"id":200303101,"themeId":2,"group":2003031,"chapter":78,"chapters":[78],"q":"Разрешается ли после проезда обозначенного дорожным знаком приоритета перекрёстка двигаться со скоростью, превышающей указанную на дорожном знаке «Ограничение максимальной скорости»?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>Зона действия дорожного знака 3.24.1 «Ограничение максимальной скорости» в показанной ситуации распространяется до ближайшего обозначенного перекрёстка. Перекрёсток, перед которым на данной дороге установлен дорожный знак «2.3.1 Пересечение со второстепенной дорогой», является обозначенным.</p>","image":"assets/adrive-questions/q200303101.webp"},{"id":200303102,"themeId":2,"group":2003031,"chapter":78,"chapters":[78],"q":"Разрешается ли Вам после проезда ближайшего перекрёстка двигаться со скоростью, превышающей указанную на дорожном знаке?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>В показанной ситуации ближайший перекрёсток не является обозначенным.</p> <p>Зона действия дорожного знака 3.24.1 «Ограничение максимальной скорости» не ограничивается необозначенным перекрёстком.</p>","image":"assets/adrive-questions/q200303102.webp"},{"id":200303201,"themeId":2,"group":2003032,"chapter":78,"chapters":[78],"q":"Распространяется ли действие дорожного знака «Ограничение максимальной скорости» на участок дороги за перекрёстком?","a":["Да, распространяется.","Нет, не распространяется."],"c":1,"e":"<p>Зона действия дорожного знака 3.24.1 «Ограничение максимальной скорости» в показанной ситуации распространяется только до ближайшего обозначенного перекрёстка.</p>","image":"assets/adrive-questions/q200303201.webp"},{"id":200303202,"themeId":2,"group":2003032,"chapter":78,"chapters":[78],"q":"Распространяется ли действие дорожного знака «Ограничение максимальной скорости» на участок дороги за перекрёстком при движении прямо?","a":["Да, распространяется.","Нет, не распространяется."],"c":0,"e":"<p>В показанной ситуации перекрёсток является регулируемым, но не обозначенным.<br> Поэтому действие дорожного знака 3.24.1 «Ограничение максимальной скорости» распространяется на участок дороги за перекрёстком.</p>","image":"assets/adrive-questions/q200303202.webp"},{"id":200303301,"themeId":2,"group":2003033,"chapter":78,"chapters":[78],"q":"В каких направлениях из показанных на рисунке разрешено продолжить движение водителю жёлтого легкового автомобиля?","a":["Только в направлении «А».","Только в направлении «Б».","В любом из показанных направлений."],"c":2,"e":"<p>В показанной ситуации установленный дорожный знак 3.18.2 «Поворот налево запрещён» распространяет своё действие только на ближайшее пересечение проезжих частей дорог на перекрёстке.</p> <p>При этом разворот не запрещён.</p>","image":"assets/adrive-questions/q200303301.webp"},{"id":200304041,"themeId":2,"group":2003040,"chapter":78,"chapters":[78],"q":"Разрешено ли Вам после проезда перекрёстка продолжить движение со скоростью 40 км/ч?","a":["Да, разрешено.","Нет, не разрешено."],"c":1,"e":"<p>Зона действия дорожного знака «3.33 Зона с ограничением максимальной скорости движения» распространяется до места установки знака «3.34 Конец зоны с ограничением максимальной скорости движения» , а не до ближайшего обозначенного перекрёстка.</p>","image":"assets/adrive-questions/q200304041.webp"},{"id":200304042,"themeId":2,"group":2003040,"chapter":78,"chapters":[78],"q":"Разрешено ли Вам после проезда перекрёстка продолжить движение со скоростью 40 км/ч?","a":["Да, разрешено.","Нет, не разрешено."],"c":0,"e":"<p>Исходя из того, какие дорожные знаки установлены в показанной обстановке, движение осуществляется в населённом пункте после выезда с территории зоны с ограничением максимальной скорости.</p> <p>Поэтому после проезда перекрёстка Вам разрешается двигаться со скоростью до 60 км/ч.</p>","image":"assets/adrive-questions/q200304042.webp"},{"id":200304043,"themeId":2,"group":2003040,"chapter":78,"chapters":[78],"q":"С какой максимальной скоростью разрешено движение водителю легкового автомобиля при движении прямо после проезда искусственной неровности?","a":["20 км/ч.","30 км/ч.","40 км/ч.","60 км/ч."],"c":1,"e":"<p>Водитель находится на территории зоны с ограничением максимальной скорости. После проезда небольшого участка с дополнительным ограничением скорости (20 км/ч перед искусственной неровностью) он останется на территории с ограничением максимальной скорости до 30 км/ч.</p>","image":"assets/adrive-questions/q200304043.webp"},{"id":200400101,"themeId":2,"group":2004001,"chapter":79,"chapters":[79],"q":"В каком направлении Вам разрешено продолжить движение в показанной ситуации?","a":["Только направо.","Направо и налево.","Направо, налево и на разворот.","Во всех направлениях."],"c":2,"e":"<p>В показанной ситуации установленный дорожный знак 4.1.6 «Движение направо или налево» разрешает движение в направлениях, указанных стрелками, а также разворот.</p> <p>Движение прямо запрещено.</p>","image":"assets/adrive-questions/q200400101.webp"},{"id":200400103,"themeId":2,"group":2004001,"chapter":79,"chapters":[79],"q":"По какой из показанных на рисунке траекторий водителю белого автомобиля разрешено продолжить движение?","a":["Только по траектории «Б».","По траектории «Б» и «В».","По любой из показанных траекторий."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 4.1.1 «Движение прямо» разрешает движение только прямо.</p>","image":"assets/adrive-questions/q200400103.webp"},{"id":200400152,"themeId":2,"group":2004001,"chapter":79,"chapters":[79],"q":"Разрешено ли Вам повернуть направо на прилегающую территорию в показанной ситуации?","a":["Разрешено.","Запрещено."],"c":1,"e":"<p>Дорожный знак «4.1.1 Движение прямо» запрещает съезд на прилегающую территорию и требует продолжать движение <strong>только прямо</strong>.</p>","image":"assets/adrive-questions/q200400152.webp"},{"id":200400201,"themeId":2,"group":2004002,"chapter":79,"chapters":[79],"q":"По какой из показанных на рисунке траекторий водителю белого автомобиля разрешено повернуть налево?","a":["Только по траектории «А».","Только по траектории «Б».","По любой из показанных траекторий.","Запрещено по любой из показанных траекторий."],"c":1,"e":"<p>В показанной ситуации установленный дорожный знак 4.2.1 «Объезд препятствия справа» разрешает объезд островков безопасности и различного рода препятствий только со стороны, указанной стрелкой.</p>","image":"assets/adrive-questions/q200400201.webp"},{"id":200400202,"themeId":2,"group":2004002,"chapter":79,"chapters":[79],"q":"Разрешено ли водителю жёлтого легкового автомобиля повернуть налево в показанной ситуации?","a":["Да, разрешено.","Нет, не разрешено."],"c":0,"e":"<p>В показанной ситуации водитель жёлтого легкового автомобиля находится на перекрёстке, где не установлены дорожные знаки, запрещающие поворот налево.</p>","image":"assets/adrive-questions/q200400202.webp"},{"id":200400252,"themeId":2,"group":2004002,"chapter":79,"chapters":[79],"q":"В каких направлениях Вам разрешено продолжить движение в показанной ситуации?","a":["Только направо.","Только прямо и направо.","Только направо и на разворот.","Прямо, направо и на разворот."],"c":2,"e":"<p>Дорожный знак «3.1 Въезд запрещён» запрещает движение прямо на показанном перекрёстке. Знак «4.2.1 Объезд препятствия справа» не запрещает осуществить поворот направо на перекрёстке. Знаков или разметки, запрещающих разворот, на перекрёстке нет. Следовательно, на показанном перекрёстке <strong>движение разрешено направо и на разворот</strong>.</p>","image":"assets/adrive-questions/q200400252.webp"},{"id":200400301,"themeId":2,"group":2004003,"chapter":79,"chapters":[79],"q":"Какой из показанных на рисунке дорожных знаков называется «Объезд препятствия справа»?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":2,"e":"<p>На рисунке под номером 3 изображён дорожный знак 4.2.1 «Объезд препятствия справа» .</p>","image":"assets/adrive-questions/q200400301.webp"},{"id":200400302,"themeId":2,"group":2004003,"chapter":79,"chapters":[79],"q":"Какой из показанных на рисунке дорожных знаков называется «Объезд препятствия справа или слева»?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":1,"e":"<p>На рисунке под номером 2 изображён дорожный знак 4.2.3 «Объезд препятствия справа или слева» .</p>","image":"assets/adrive-questions/q200400302.webp"},{"id":200400401,"themeId":2,"group":2004004,"chapter":79,"chapters":[79],"q":"В каких направлениях в показанной ситуации разрешено продолжить движение мотоциклисту?","a":["Только прямо.","Направо или налево.","Прямо и на разворот.","Во всех направлениях."],"c":3,"e":"<p>В показанной ситуации установленный дорожный знак 4.4 «Движение легковых автомобилей» разрешает движение только легковым автомобилям и мотоциклам, поэтому мотоциклисту разрешено продолжить движение в любом направлении.</p>","image":"assets/adrive-questions/q200400401.webp"},{"id":200400402,"themeId":2,"group":2004004,"chapter":79,"chapters":[79],"q":"В каких направлениях в показанной ситуации разрешено продолжить движение водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны?","a":["Только прямо.","Направо или налево.","Прямо и на разворот.","Во всех направлениях."],"c":2,"e":"<p>В показанной ситуации установленный дорожный знак 4.4 «Движение легковых автомобилей» разрешает движение только легковым автомобилям и мотоциклам (грузовым автомобилям до 3.5 т, маршрутным транспортным средствам, автобусам и другим видам транспортных средств движение запрещено).</p>","image":"assets/adrive-questions/q200400402.webp"},{"id":200400501,"themeId":2,"group":2004005,"chapter":79,"chapters":[79],"q":"По какой полосе движения водителю легкового автомобиля разрешено продолжать движение в населённом пункте?","a":["Только по крайней левой.","Только по крайней правой.","По любой из попутных полос движения."],"c":2,"e":"<p>В показанной ситуации над крайней левой полосой движения установлены дорожные знаки:</p> <ul><li>4.4 «Движение легковых автомобилей» — разрешает движение только легковым автомобилям и мотоциклам;</li> <li>7.14 «Полоса движения» — указывает полосу, на которую распространяется действие дорожного знака или светофора.</li></ul> <p>Поэтому водителю легкового автомобиля разрешено продолжать движение в населённом пункте по любой из попутных полос движения.</p>","image":"assets/adrive-questions/q200400501.webp"},{"id":200400502,"themeId":2,"group":2004005,"chapter":79,"chapters":[79],"q":"По какой полосе движения водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны разрешено продолжать движение в населённом пункте?","a":["Только по крайней левой.","Только по крайней правой.","По любой из попутных полос движения."],"c":1,"e":"<p>В показанной ситуации над крайней левой полосой движения установлены дорожные знаки:</p> <ul><li>4.4 «Движение легковых автомобилей» — разрешает движение только легковым автомобилям и мотоциклам;</li> <li>7.14 «Полоса движения» — указывает полосу, на которую распространяется действие дорожного знака или светофора.</li></ul> <p>Поэтому водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны разрешено продолжать движение в населённом пункте только по крайней правой полосе движения.</p>","image":"assets/adrive-questions/q200400502.webp"},{"id":200400601,"themeId":2,"group":2004006,"chapter":79,"chapters":[79],"q":"Разрешено ли каким-либо транспортным средствам из нижеперечисленных движение по полосе движения, над которой установлен такой дорожный знак?","a":["Разрешено мопедам.","Разрешено велосипедам.","Разрешено маршрутным автобусам.","Разрешено грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны.","Запрещено всем перечисленным."],"c":4,"e":"<p>Показанный на рисунке дорожный знак 4.4 «Движение легковых автомобилей» разрешает движение только легковым автомобилям и мотоциклам.</p>","image":"assets/adrive-questions/q200400601.webp"},{"id":200400602,"themeId":2,"group":2004006,"chapter":79,"chapters":[79],"q":"Разрешено ли каким-либо транспортным средствам из нижеперечисленных движение по полосе движения, обозначенной таким дорожным знаком?","a":["Разрешено мопедам.","Разрешено мотоциклам.","Разрешено велосипедам.","Разрешено гужевым транспортным средствам.","Запрещено всем перечисленным."],"c":1,"e":"<p>Показанный на рисунке дорожный знак 4.4 «Движение легковых автомобилей» разрешает движение только легковым автомобилям и мотоциклам.</p>","image":"assets/adrive-questions/q200400602.webp"},{"id":200400701,"themeId":2,"group":2004007,"chapter":79,"chapters":[79],"q":"Какие из показанных на рисунке дорожных знаков запрещают движение мопедов по обозначенному ими элементу дороги?","a":["Только дорожный знак 1.","Только дорожный знак 5.","Дорожные знаки 1 и 5.","Дорожные знаки 1, 4 и 5.","Все показанные на рисунке дорожные знаки."],"c":3,"e":"<p>На рисунке под номерами 1, 4 и 5 изображены дорожные знаки 3.5 «Движение мотоциклов запрещено» , 4.5.1 «Велосипедная дорожка» и 4.6.1 «Пешеходная дорожка» , которые запрещают движение мопедов по обозначенному ими элементу дороги.</p>","image":"assets/adrive-questions/q200400701.webp"},{"id":200400732,"themeId":2,"group":2004007,"chapter":79,"chapters":[79],"q":"Кому разрешается движение по элементу дороги, обозначенному таким дорожным знаком?","a":["Всадникам.","Водителям гужевых транспортных средств.","Водителям средств персональной мобильности.","Водителям мопедов при интенсивном движении транспортных средств по дороге.","Всем перечисленным участникам дорожного движения."],"c":2,"e":"<p>Движение по велосипедным дорожкам разрешено на велосипедах и средствах персональной мобильности.</p>","image":"assets/adrive-questions/q200400732.webp"},{"id":200400741,"themeId":2,"group":2004007,"chapter":79,"chapters":[79],"q":"Какие из показанных дорожных знаков обозначают велосипедную дорожку?","a":["Только знак 1.","Только знак 2.","Только знак 3.","Только знак 4.","Только знаки 1 и 2."],"c":4,"e":"<p>Для обозначения велосипедной дорожки могут применяться первый («4.11.1 Велосипедная и пешеходная дорожка» ) и второй («4.5.1 Велосипедная дорожка» ) дорожные знаки.</p>","image":"assets/adrive-questions/q200400741.webp"},{"id":200400801,"themeId":2,"group":2004008,"chapter":79,"chapters":[79],"q":"Кому разрешено движение по элементу дороги, обозначенному таким дорожным знаком?","a":["Всадникам.","Водителям мопедов.","Велосипедистам при отсутствии велосипедной дорожки.","Всем перечисленным."],"c":2,"e":"<p>Показанный на рисунке дорожный знак 4.6.1 «Пешеходная дорожка» разрешает движение только пешеходам, а при отсутствии велосипедной дорожки — и на велосипедах, при этом велосипедисты не должны создавать препятствий для движения пешеходов.</p>","image":"assets/adrive-questions/q200400801.webp"},{"id":200400802,"themeId":2,"group":2004008,"chapter":79,"chapters":[79],"q":"Кто из перечисленных участников дорожного движения не нарушает Правила дорожного движения, двигаясь по элементу дороги, обозначенному таким дорожным знаком?","a":["Пешеход, ведущий мопед.","Пешеход, ведущий велосипед.","Велосипедист в случае отсутствия велосипедной дорожки.","Все перечисленные участники дорожного движения."],"c":3,"e":"<p>Показанный на рисунке дорожный знак 4.6.1 «Пешеходная дорожка» разрешает движение только пешеходам, а при отсутствии велосипедной дорожки — и на велосипедах, при этом велосипедисты не должны создавать препятствий для движения пешеходов.</p>","image":"assets/adrive-questions/q200400802.webp"},{"id":200400851,"themeId":2,"group":2004008,"chapter":79,"chapters":[79],"q":"Разрешается ли движение на велосипедах по дорожке, обозначенной показанным предписывающим дорожным знаком?","a":["Разрешается.","Запрещается.","Разрешается, но только при отсутствии велосипедной дорожки."],"c":2,"e":"<p>При отсутствии велосипедной дорожки велосипедистам разрешается осуществлять движение по пешеходной дорожке, не создавая препятствия для безопасного движения пешеходов.</p>","image":"assets/adrive-questions/q200400851.webp"},{"id":200400901,"themeId":2,"group":2004009,"chapter":79,"chapters":[79],"q":"Какой из показанных на рисунке дорожных знаков относится к группе «Предписывающие знаки»?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":0,"e":"<p>На рисунке под номером 1 изображён дорожный знак 4.9.2 «Направление движения транспортных средств с опасными грузами» , который относится к группе «Предписывающие знаки».</p>","image":"assets/adrive-questions/q200400901.webp"},{"id":200400902,"themeId":2,"group":2004009,"chapter":79,"chapters":[79],"q":"Какие из показанных на рисунке дорожных знаков не запрещают движение грузовых автомобилей с фактической массой не более 3.5 тонны?","a":["Только дорожный знак 2.","Только дорожный знак 4.","Только дорожный знак 5.","Дорожные знаки 3 и 4.","Дорожные знаки 3, 4 и 5."],"c":3,"e":"<p>На рисунке под номерами 3 и 4 изображены дорожные знаки 3.11.1 «Ограничение массы» (запрещается движение транспортных средств, в том числе автопоездов, общая фактическая масса которых больше указанной на знаке) и 3.4 «Движение грузовых автомобилей запрещено» (запрещается движение грузовых автомобилей (автопоездов) с технически допустимой общей массой более 3.5 тонны (если на знаке не указана масса) или с фактической массой, превышающей указанную на знаке, а также колёсных тракторов и самоходных машин), которые не запрещают движение грузовых автомобилей с фактической общей массой не более 3.5 тонны.</p>","image":"assets/adrive-questions/q200400902.webp"},{"id":200401001,"themeId":2,"group":2004010,"chapter":79,"chapters":[79],"q":"В каком из перечисленных случаев водитель мопеда не нарушит Правила дорожного движения, двигаясь по дороге, обозначенной показанным дорожным знаком?","a":["Съедет на обочину и, став пешеходом, будет вести мопед по обочине.","Займёт крайнее правое положение на проезжей части дороги и не будет выезжать далее 1 метра от края проезжей части дороги."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 4.7 «Ограничение минимальной скорости» разрешает движение только с указанной или большей скоростью.</p> <p>Максимальная конструктивная скорость движения мопеда определена его технической характеристикой и составляет не более 50 км/ч по Правилам дорожного движения.</p> <p>Поэтому водитель мопеда при движении по дороге, обозначенной таким дорожным знаком, должен съехать на обочину и, став пешеходом, вести мопед по обочине.</p>","image":"assets/adrive-questions/q200401001.webp"},{"id":200401002,"themeId":2,"group":2004010,"chapter":79,"chapters":[79],"q":"Водитель легкового автомобиля двигается к месту ремонта со скоростью 40 км/ч. Нарушит ли он Правила дорожного движения, продолжая движение вперёд на показанном участке дороги, если автомобиль не может развивать более высокую скорость?","a":["Нарушит.","Не нарушит."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 4.7 «Ограничение минимальной скорости» разрешает движение только с указанной или большей скоростью.</p> <p>Поэтому водитель легкового автомобиля, двигаясь со скоростью 40 км/ч, нарушит Правила дорожного движения.</p>","image":"assets/adrive-questions/q200401002.webp"},{"id":200401101,"themeId":2,"group":2004011,"chapter":79,"chapters":[79],"q":"По какой из показанных на рисунке траекторий водителю белого автомобиля разрешено совершить разворот?","a":["Только по траектории «Б».","Только по траектории «В».","По траекториям «Б» и «В».","По любой из показанных траекторий."],"c":1,"e":"<p>В показанной ситуации установленный дорожный знак 4.1.4 «Движение прямо или направо» разрешает движение только в направлениях, указанных стрелками.</p> <p>Действие дорожного знака распространяется на весь перекрёсток, поэтому водителю белого автомобиля разрешено совершить разворот только по траектории «В» (после проезда перекрёстка).</p>","image":"assets/adrive-questions/q200401101.webp"},{"id":200401102,"themeId":2,"group":2004011,"chapter":79,"chapters":[79],"q":"По какой из показанных на рисунке траекторий водителю жёлтого автомобиля разрешено совершить разворот?","a":["Только по траектории «А».","Только по траектории «Б».","По любой из показанных траекторий."],"c":2,"e":"<p>В показанной ситуации установленный дорожный знак 4.1.5 «Движение прямо или налево» разрешает движение только в направлениях, указанных стрелками.<br> При этом, так как разрешён поворот налево, разрешён и разворот.</p> <p>Действие дорожного знака распространяется на весь перекрёсток, поэтому водителю жёлтого автомобиля разрешено совершить разворот по любой из показанных траекторий.</p>","image":"assets/adrive-questions/q200401102.webp"},{"id":200401201,"themeId":2,"group":2004012,"chapter":79,"chapters":[79],"q":"По какой из показанных на рисунке траекторий разрешено продолжить движение водителю красного легкового автомобиля?","a":["Только по траектории «А».","Только по траектории «Б».","По траекториям «А» и «Б».","Запрещено по любой из показанных траекторий."],"c":1,"e":"<p>В показанной ситуации установленный дорожный знак 4.1.1 «Движение прямо» разрешает движение только прямо.</p> <p>Действие данного дорожного знака распространяется на перекрёсток, поэтому водителю красного легкового автомобиля разрешено продолжить движение только по траектории «Б» (после проезда перекрёстка и окончания сплошной линии горизонтальной дорожной разметки).</p>","image":"assets/adrive-questions/q200401201.webp"},{"id":200401202,"themeId":2,"group":2004012,"chapter":79,"chapters":[79],"q":"Разрешено ли водителю красного легкового автомобиля продолжить движение по показанным на рисунке траекториям?","a":["Разрешено только по траектории «А».","Разрешено только по траектории «Б».","Разрешено по траекториям «А» и «Б».","Запрещено по любой из показанных траекторий."],"c":3,"e":"<p>В показанной ситуации установленный дорожный знак 4.1.1 «Движение прямо» разрешает движение только прямо.</p> <p>Действие дорожного знака распространяется на весь перекрёсток, поэтому водителю красного легкового автомобиля разрешено продолжить движение только прямо.</p>","image":"assets/adrive-questions/q200401202.webp"},{"id":200401401,"themeId":2,"group":2004014,"chapter":79,"chapters":[79],"q":"Разрешено ли водителю жёлтого легкового автомобиля продолжить движение по показанным на рисунке траекториям?","a":["Разрешено только по траектории «А».","Разрешено только по траектории «Б».","Разрешено по траекториям «А» и «Б».","Запрещено по любой из показанных траекторий."],"c":3,"e":"<p>В показанной ситуации установленный за перекрёстком дорожный знак 4.1.1 «Движение прямо» запрещает водителю жёлтого легкового автомобиля совершить поворот налево и разворот до следующего обозначенного перекрёстка.</p>","image":"assets/adrive-questions/q200401401.webp"},{"id":200401402,"themeId":2,"group":2004014,"chapter":79,"chapters":[79],"q":"Разрешается ли водителю жёлтого легкового автомобиля повернуть на дворовую территорию после проезда показанного на рисунке дорожного знака, установленного за предыдущим перекрёстком?","a":["Разрешается только направо.","Разрешается как направо, так и налево.","Разрешается только направо в случае, если водитель проживает в показанном на рисунке доме, при отсутствии иных возможностей подъезда.","Запрещается как направо, так и налево."],"c":3,"e":"<p>В показанной ситуации установленный за предыдущим перекрёстком дорожный знак 4.1.1 «Движение прямо» запрещает водителю жёлтого легкового автомобиля совершить поворот как налево, так и направо.</p>","image":"assets/adrive-questions/q200401402.webp"},{"id":200401601,"themeId":2,"group":2004016,"chapter":79,"chapters":[79],"q":"Разрешается ли водителю жёлтого легкового автомобиля развернуться на ближайшем по ходу движения перекрёстке?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>В показанной ситуации установленный за предыдущим перекрёстком дорожный знак 4.1.1 «Движение прямо» распространяет своё действие до ближайшего по ходу движения обозначенного перекрёстка.</p> <p>Поэтому водителю жёлтого легкового автомобиля разрешено развернуться на ближайшем по ходу движения перекрёстке.</p>","image":"assets/adrive-questions/q200401601.webp"},{"id":200401602,"themeId":2,"group":2004016,"chapter":79,"chapters":[79],"q":"В каких направлениях водителю жёлтого легкового автомобиля разрешается продолжить движение на ближайшем по ходу движения перекрёстке?","a":["Только прямо.","Прямо и направо.","Прямо, направо и налево.","Во всех направлениях."],"c":3,"e":"<p>В показанной ситуации установленный за предыдущим перекрёстком дорожный знак 4.1.1 «Движение прямо» распространяет своё действие до ближайшего по ходу движения обозначенного перекрёстка.</p> <p>Ближайший перекрёсток является обозначенным, значит водитель легкового автомобиля может при его проезде проследовать в любом направлении.</p>","image":"assets/adrive-questions/q200401602.webp"},{"id":200401603,"themeId":2,"group":2004016,"chapter":79,"chapters":[79],"q":"В каких направлениях водителю синего легкового автомобиля разрешается продолжить движение на ближайшем по ходу движения перекрёстке?","a":["Только направо.","Направо и налево.","Во всех направлениях."],"c":2,"e":"<p>В показанной ситуации установленный за предыдущим перекрёстком дорожный знак 4.1.1 «Движение прямо» распространяет своё действие до ближайшего по ходу движения обозначенного перекрёстка.</p> <p>Ближайший перекрёсток является обозначенным, значит водитель легкового автомобиля может при его проезде проследовать в любом направлении.</p>","image":"assets/adrive-questions/q200401603.webp"},{"id":200401731,"themeId":2,"group":2004017,"chapter":79,"chapters":[79],"q":"Разрешается ли водителю белого легкового автомобиля объехать место ДТП по показанной траектории?","a":["Да, разрешается.","Нет, не разрешается."],"c":1,"e":"<p>В показанной ситуации установленный дорожный знак 4.3 «Круговое движение» разрешает объезд центрального островка на перекрёстке (площади) с круговым движением только в направлении, указанном стрелками.</p>","image":"assets/adrive-questions/q200401731.webp"},{"id":200401732,"themeId":2,"group":2004017,"chapter":79,"chapters":[79],"q":"Кто из водителей выбрал правильную траекторию для движения через показанный на рисунке перекрёсток?","a":["Водитель синего автомобиля.","Водитель зелёного автомобиля.","Водители обоих автомобилей.","Водители обоих автомобилей выбрали неправильные траектории для движения."],"c":1,"e":"<p>В показанной ситуации установленный дорожный знак 4.3 «Круговое движение» разрешает объезд центрального островка на перекрёстке (площади) с круговым движением только в направлении, указанном стрелками.</p>","image":"assets/adrive-questions/q200401732.webp"},{"id":200401733,"themeId":2,"group":2004017,"chapter":79,"chapters":[79],"q":"Кто из водителей выбрал правильную траекторию для движения через показанный на рисунке перекрёсток?","a":["Водитель синего автомобиля.","Водитель белого автомобиля.","Водители обоих автомобилей."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 4.3 «Круговое движение» разрешает объезд центрального островка на перекрёстке (площади) с круговым движением только в направлении, указанном стрелками.</p>","image":"assets/adrive-questions/q200401733.webp"},{"id":200500101,"themeId":2,"group":2005001,"chapter":80,"chapters":[80],"q":"В каких направлениях разрешено продолжить движение водителю синего легкового автомобиля?","a":["Только налево.","Налево и на разворот.","Прямо, налево и на разворот."],"c":1,"e":"<p>В показанной ситуации установленный над крайней левой полосой дорожный знак 5.8.2 «Направление движения по полосе» разрешает поворот налево и разворот.</p>","image":"assets/adrive-questions/q200500101.webp"},{"id":200500102,"themeId":2,"group":2005001,"chapter":80,"chapters":[80],"q":"В каких направлениях Вам разрешено продолжить движение, управляя легковым автомобилем, при нахождении в показанной полосе движения?","a":["Только прямо.","Только прямо и направо.","Прямо, направо и налево.","Во всех направлениях."],"c":2,"e":"<p>В показанной ситуации установленный дорожный знак 5.8.2 «Направление движения по полосе» указывает, что, находясь в средней полосе движения, разрешено продолжить движение прямо, налево и направо.</p> <p>Разворот может быть разрешён только с крайней левой полосы движения.</p>","image":"assets/adrive-questions/q200500102.webp"},{"id":200500103,"themeId":2,"group":2005001,"chapter":80,"chapters":[80],"q":"По какой из показанных на рисунке траекторий разрешено проехать перекрёсток водителю красного автомобиля?","a":["Только по траектории «А».","Только по траектории «Б».","По любой из показанных траекторий."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 5.8.1 «Направления движения по полосам» указывает, что водитель легкового автомобиля может проехать только по траектории «А».</p> <p>Перестроение на данном перекрёстке запрещается.</p>","image":"assets/adrive-questions/q200500103.webp"},{"id":200500104,"themeId":2,"group":2005001,"chapter":80,"chapters":[80],"q":"В каких направлениях разрешено продолжить движение водителю синего легкового автомобиля в показанной ситуации?","a":["Только на разворот.","Налево или на разворот.","Прямо, налево или на разворот."],"c":0,"e":"<p>Над крайней левой полосой движения установлен дорожный знак 5.8.2 «Направление движения по полосе» , разрешающий только разворот из занимаемой полосы.</p>","image":"assets/adrive-questions/q200500104.webp"},{"id":200500201,"themeId":2,"group":2005002,"chapter":80,"chapters":[80],"q":"Разрешено ли водителю синего легкового автомобиля продолжить движение в крайней правой полосе, как показано на рисунке, если ему необходимо повернуть направо на место для стоянки сразу за перекрёстком?","a":["Да, разрешено.","Нет, запрещено.","Разрешено только при условии, что не будет создано угрозы безопасности дорожного движения."],"c":1,"e":"<p>В показанной ситуации установленный дорожный знак 5.8.1 «Направления движения по полосам» запрещает водителю синего легкового автомобиля продолжить движение в крайней правой полосе прямо.</p>","image":"assets/adrive-questions/q200500201.webp"},{"id":200500202,"themeId":2,"group":2005002,"chapter":80,"chapters":[80],"q":"Кто из водителей в ситуации, изображённой на рисунке, нарушит Правила дорожного движения, проехав перекрёсток в показанных направлениях?","a":["Водитель синего автомобиля.","Водитель красного автомобиля.","Водитель зелёного автомобиля.","Водители всех автомобилей нарушат Правила дорожного движения в показанной ситуации."],"c":3,"e":"<p>В показанной ситуации установленные дорожные знаки 5.8.2 «Направление движения по полосе» указывают разрешённые направления движения по полосам.</p> <p>Поэтому водители всех автомобилей нарушат Правила дорожного движения.</p>","image":"assets/adrive-questions/q200500202.webp"},{"id":200500203,"themeId":2,"group":2005002,"chapter":80,"chapters":[80],"q":"Разрешено ли водителю красного легкового автомобиля повернуть налево из занимаемой полосы движения?","a":["Да, разрешено.","Нет, запрещено.","Разрешено только для проезда к месту проживания."],"c":1,"e":"<p>В показанной ситуации на дорожный знак 5.8.1 «Направления движения по полосам» нанесено изображение запрещающего знака 3.1 «Въезд запрещён» , который запрещает поворот налево из данной полосы.</p>","image":"assets/adrive-questions/q200500203.webp"},{"id":200500204,"themeId":2,"group":2005002,"chapter":80,"chapters":[80],"q":"Разрешается ли Вам, управляя легковым автомобилем, проехать перекрёсток прямо, если Вы проживаете в доме, расположенном за перекрёстком?","a":["Да, разрешено.","Нет, запрещено."],"c":1,"e":"<p>Дорожные знаки 5.8.1 «Направления движения по полосам» и 4.1.6 «Движение направо или налево» запрещают проезд прямо через перекрёсток с данного направления. Проехать к указанному дому можно, например, повернув направо, а затем, после разворота в разрешённом месте, повернуть ещё раз направо, при условии отсутствия иных способов подъезда к указанному дому.</p>","image":"assets/adrive-questions/q200500204.webp"},{"id":200500235,"themeId":2,"group":2005002,"chapter":80,"chapters":[80],"q":"Разрешается ли в показанной ситуации водителю синего легкового автомобиля проехать перекрёсток прямо?","a":["Разрешается, если водитель проживает в доме, расположенном за перекрёстком, при отсутствии иных возможностей подъезда.","Разрешается, если ребёнок водителя учится в школе (воспитывается в детском саду), расположенной за перекрёстком, при отсутствии иных возможностей подъезда.","Разрешается в обоих перечисленных случаях.","Запрещается."],"c":3,"e":"<p>Дорожный знак 5.8.1 «Направления движения по полосам» , установленный перед перекрёстком, запрещает движение прямо с данного направления.</p> <p>При движении в этом направлении с иных сторон на перекрёстке следует руководствоваться требованиями дорожного знака 3.2 «Движение запрещено» , установленного за перекрёстком.</p>","image":"assets/adrive-questions/q200500235.webp"},{"id":200500301,"themeId":2,"group":2005003,"chapter":80,"chapters":[80],"q":"Разрешается ли Вам при управлении легковым автомобилем вне населённого пункта превысить скорость, указанную на дорожном знаке, на 15 км/ч, при условии, что Ваш водительский стаж составляет не менее двух лет?","a":["Да, разрешается.","Нет, не разрешается."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 5.18.1 «Рекомендуемая скорость» не обязывает водителей двигаться со скоростью, указанной на знаке, однако им следует учитывать, что эта скорость определена с учётом дорожных условий, параметров транспортных и пешеходных потоков, а также анализа причин возникновения дорожно-транспортных происшествий.</p> <p>Поэтому движение транспортных средств с указанной скоростью, при выполнении других требований Правил дорожного движения, будет наиболее эффективным и безопасным.</p>","image":"assets/adrive-questions/q200500301.webp"},{"id":200500302,"themeId":2,"group":2005003,"chapter":80,"chapters":[80],"q":"Нарушает ли Правила дорожного движения водитель зелёного автомобиля, двигаясь в указанной ситуации со скоростью 45 км/ч?","a":["Да, нарушает.","Нет, не нарушает."],"c":1,"e":"<p>В показанной ситуации установленный дорожный знак 5.18.1 «Рекомендуемая скорость» не обязывает водителей двигаться со скоростью, указанной на знаке, однако им следует учитывать, что эта скорость определена с учётом дорожных условий, параметров транспортных и пешеходных потоков, а также анализа причин возникновения дорожно-транспортных происшествий.</p>","image":"assets/adrive-questions/q200500302.webp"},{"id":200500401,"themeId":2,"group":2005004,"chapter":80,"chapters":[80],"q":"Какой из показанных на рисунке дорожных знаков называется «Рекомендуемая скорость»?","a":["Только дорожный знак 3.","Только дорожный знак 4.","Только дорожный знак 5.","Дорожные знаки 4 и 5.","Дорожные знаки 3 и 4."],"c":1,"e":"<p>На рисунке под номером 4 изображён дорожный знак 5.18.1 «Рекомендуемая скорость» .</p>","image":"assets/adrive-questions/q200500401.webp"},{"id":200500402,"themeId":2,"group":2005004,"chapter":80,"chapters":[80],"q":"Распространяется ли зона действия дорожного знака «Рекомендуемая скорость» на участок дороги за показанным на рисунке перекрёстком?","a":["Да, распространяется.","Нет, не распространяется."],"c":1,"e":"<p>В показанной ситуации зона действия установленного дорожного знака 5.18.1 «Рекомендуемая скорость» распространяется до ближайшего обозначенного перекрёстка.</p>","image":"assets/adrive-questions/q200500402.webp"},{"id":200500403,"themeId":2,"group":2005004,"chapter":80,"chapters":[80],"q":"Как определяется в показанной ситуации зона действия дорожного знака «Рекомендуемая скорость»?","a":["Зона действия распространяется до ближайшего обозначенного перекрёстка.","Зона действия определяется протяжённостью опасного участка дороги, обозначенного предупреждающим дорожным знаком.","Зона действия распространяется до места установки дорожного знака «Конец зоны ограничения максимальной скорости»."],"c":1,"e":"<p>Зона действия дорожного знака 5.18.1 «Рекомендуемая скорость» , установленного совместно с предупреждающим дорожным знаком, определяется протяжённостью опасного участка дороги.</p>","image":"assets/adrive-questions/q200500403.webp"},{"id":200500501,"themeId":2,"group":2005005,"chapter":80,"chapters":[80],"q":"Каким транспортным средствам из перечисленных ниже запрещается движение по дороге, обозначенной таким дорожным знаком?","a":["Мопедам.","Велосипедам.","Колёсным тракторам.","Гужевым транспортным средствам.","Всем перечисленным."],"c":4,"e":"<p>Показанный на рисунке дорожный знак 5.3 «Дорога для автомобилей» разрешает движение только автомобилям, автобусам и мотоциклам, поэтому движение мопедам, велосипедам, колёсным тракторам и гужевым транспортным средствам по дороге, обозначенной таким дорожным знаком, запрещено.</p>","image":"assets/adrive-questions/q200500501.webp"},{"id":200500502,"themeId":2,"group":2005005,"chapter":80,"chapters":[80],"q":"Каким транспортным средствам из перечисленных ниже запрещается движение по дороге, обозначенной таким дорожным знаком?","a":["Велосипедам.","Мотоциклам с боковым прицепом.","Автобусам, следующим в пригородном сообщении.","Грузовым автомобилям с технически допустимой общей массой более 3.5 тонны.","Легковым автомобилям, управляемым водителями с общим водительским стажем менее двух лет."],"c":0,"e":"<p>Показанный на рисунке дорожный знак 5.3 «Дорога для автомобилей» разрешает движение только автомобилям, автобусам и мотоциклам, поэтому движение велосипедам по дороге, обозначенной таким дорожным знаком, запрещено.</p>","image":"assets/adrive-questions/q200500502.webp"},{"id":200500701,"themeId":2,"group":2005007,"chapter":80,"chapters":[80],"q":"Является ли опережение, выполняемое водителем красного легкового автомобиля, обгоном?","a":["Да, является.","Нет, не является."],"c":1,"e":"<p>В показанной ситуации водитель красного автомобиля движется по дороге, где установлен дорожный знак 5.5 «Дорога с односторонним движением» .</p> <p>Поэтому водитель легкового автомобиля выполняет опережение, не являющееся обгоном.</p>","image":"assets/adrive-questions/q200500701.webp"},{"id":200500702,"themeId":2,"group":2005007,"chapter":80,"chapters":[80],"q":"Нарушит ли Правила дорожного движения водитель красного легкового автомобиля, совершив показанный на рисунке манёвр?","a":["Да, нарушит.","Нет, не нарушит."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 5.5 «Дорога с односторонним движением» запрещает разворот, так как движение должно осуществляться только в направлении, указанном стрелкой.</p>","image":"assets/adrive-questions/q200500702.webp"},{"id":200500761,"themeId":2,"group":2005007,"chapter":80,"chapters":[80],"q":"Разрешён ли разворот на дороге, обозначенной показанным дорожным знаком?","a":["Разрешён.","Запрещён."],"c":1,"e":"<p>Показанная дорога обозначена дорожным знаком «5.5 Дорога с односторонним движением», следовательно движение организовано только в одном направлении, и разворот на этой дороге запрещён.</p>","image":"assets/adrive-questions/q200500761.webp"},{"id":200500801,"themeId":2,"group":2005008,"chapter":80,"chapters":[80],"q":"Какой из показанных на рисунке дорожных знаков информирует водителей о начале дороги, по которой движение транспортных средств по всей ширине осуществляется в одном направлении?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":3,"e":"<p>Изображённый на рисунке под номером 4 дорожный знак 5.5 «Дорога с односторонним движением» информирует водителей о начале дороги, по которой движение транспортных средств по всей ширине осуществляется в одном направлении.</p>","image":"assets/adrive-questions/q200500801.webp"},{"id":200500802,"themeId":2,"group":2005008,"chapter":80,"chapters":[80],"q":"Какой из показанных на рисунке дорожных знаков информирует водителей об окончании дороги, по которой движение транспортных средств по всей ширине осуществляется в одном направлении?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":4,"e":"<p>На рисунке под номером 5 изображён дорожный знак 5.6 «Конец дороги с односторонним движением» , который информирует водителей об окончании дороги, по которой движение транспортных средств по всей ширине осуществляется в одном направлении.</p>","image":"assets/adrive-questions/q200500802.webp"},{"id":200500902,"themeId":2,"group":2005009,"chapter":80,"chapters":[80],"q":"В каких направлениях разрешено продолжить движение водителю синего легкового автомобиля в показанной ситуации?","a":["Только направо.","Прямо и направо.","Прямо на разворот.","Прямо, направо и на разворот.","Во всех направлениях."],"c":3,"e":"<p>В показанной ситуации установленный дорожный знак 5.7.1 «Выезд на дорогу с односторонним движением» информирует водителей о выезде на дорогу, по которой движение транспортных средств разрешено только в направлении, указанном на знаке.</p> <p>Поэтому водителю синего легкового автомобиля запрещено повернуть налево.</p> <p>Движение в остальных направлениях не запрещается.</p>","image":"assets/adrive-questions/q200500902.webp"},{"id":200501001,"themeId":2,"group":2005010,"chapter":80,"chapters":[80],"q":"В каких направлениях разрешено продолжить движение водителю белого легкового автомобиля в показанной ситуации?","a":["Только прямо.","Только налево.","Прямо и налево.","Прямо, налево и на разворот.","Во всех направлениях."],"c":3,"e":"<p>В показанной ситуации установленный дорожный знак 5.7.2 «Выезд на дорогу с односторонним движением» информирует водителей о выезде на дорогу, по которой движение транспортных средств разрешено только в направлении, указанном на знаке.</p> <p>Поэтому водителю белого легкового автомобиля запрещено повернуть направо.</p> <p>Движение в остальных направлениях не запрещается.</p>","image":"assets/adrive-questions/q200501001.webp"},{"id":200501002,"themeId":2,"group":2005010,"chapter":80,"chapters":[80],"q":"В каких направлениях разрешено продолжить движение водителю белого легкового автомобиля в показанной ситуации?","a":["Только налево.","Прямо и налево.","Прямо на разворот.","Прямо, налево и на разворот.","Во всех направлениях."],"c":3,"e":"<p>В показанной ситуации установленный дорожный знак 5.7.2 «Выезд на дорогу с односторонним движением» информирует водителей о выезде на дорогу, по которой движение транспортных средств разрешено только в направлении, указанном на знаке.</p> <p>Поэтому водителю белого легкового автомобиля разрешено продолжить движение прямо, налево и на разворот.</p>","image":"assets/adrive-questions/q200501002.webp"},{"id":200501051,"themeId":2,"group":2005010,"chapter":80,"chapters":[80],"q":"В каких направлениях из перечисленных Вам разрешено продолжить движение в показанной ситуации?","a":["Только направо.","Только прямо или направо.","Прямо, направо или на разворот.","Направо, налево или на разворот."],"c":1,"e":"<p>В показанной ситуации движение до перекрёстка осуществлялось по дороге с односторонним движением, поэтому разворот запрещён. На перекрёстке выезд осуществляется на дорогу с односторонним движением, организованным слева направо, поэтому поворот налево также запрещён.</p>","image":"assets/adrive-questions/q200501051.webp"},{"id":200501131,"themeId":2,"group":2005011,"chapter":80,"chapters":[80],"q":"В показанной ситуации водитель жёлтого легкового автомобиля собирается выполнить:","a":["Обгон.","Опережение."],"c":1,"e":"<p>В показанной ситуации установленный дорожный знак 5.8.7 «Направление движения по полосам» указывает на наличие двух полос в попутном направлении, поэтому водитель жёлтого легкового автомобиля собирается выполнить опережение, не связанное с выездом на встречную полосу движения.</p>","image":"assets/adrive-questions/q200501131.webp"},{"id":200501132,"themeId":2,"group":2005011,"chapter":80,"chapters":[80],"q":"Разрешается ли водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны выполнить опережение на показанном участке дороги?","a":["Да, разрешается.","Нет, запрещается."],"c":0,"e":"<p>В показанной ситуации на дорожный знак 5.8.7 «Направление движения по полосам» нанесено изображение запрещающего знака 3.4 «Движение грузовых автомобилей запрещено» , который запрещает движение по крайней левой полосе движение грузовым автомобилям с технически допустимой общей массой более 3.5 тонны.</p> <p>Поэтому водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны не запрещено выполнить опережение на показанном участке дороги.</p>","image":"assets/adrive-questions/q200501132.webp"},{"id":200501201,"themeId":2,"group":2005012,"chapter":80,"chapters":[80],"q":"В каких направлениях из показанных стрелками на рисунке разрешается продолжить движение в населённом пункте водителю жёлтого легкового автомобиля?","a":["Только в направлении «А».","Только в направлении «В».","В направлениях «А» и «В».","Во всех показанных направлениях."],"c":2,"e":"<p>В показанной ситуации установленный дорожный знак 5.11.1 «Место для разворота» разрешает разворот, а дорожный знак 4.2.1 «Объезд препятствия справа» обязывает водителя объезжать начало разделительной полосы с правой стороны.</p> <p>Поэтому водителю жёлтого легкового автомобиля разрешается продолжить движение в населённом пункте в направлениях «А» и «В».</p>","image":"assets/adrive-questions/q200501201.webp"},{"id":200501202,"themeId":2,"group":2005012,"chapter":80,"chapters":[80],"q":"Кто из водителей поступает в соответствии с Правилами дорожного движения при выполнении разворота в показанной ситуации?","a":["Водитель синего автомобиля, выполняющий разворот в начале зоны для разворота.","Водитель белого автомобиля, выполняющий разворот в конце зоны для разворота.","Водители обоих автомобилей выполняют разворот в соответствии с Правилами дорожного движения."],"c":2,"e":"<p>В показанной ситуации установленный дорожный знак 5.11.2 «Зона для разворота» обозначает начало зоны для разворота транспортных средств и указывает её длину (15 м), поэтому водители обоих автомобилей выполняют разворот в соответствии с Правилами дорожного движения.</p>","image":"assets/adrive-questions/q200501202.webp"},{"id":200501203,"themeId":2,"group":2005012,"chapter":80,"chapters":[80],"q":"Разрешено ли водителю жёлтого легкового автомобиля повернуть налево в показанной ситуации?","a":["Да, разрешено.","Нет, запрещено."],"c":0,"e":"<p>Дорожный знак 5.11.1 «Место для разворота» не запрещает поворот налево .</p>","image":"assets/adrive-questions/q200501203.webp"},{"id":200501301,"themeId":2,"group":2005013,"chapter":80,"chapters":[80],"q":"Какие из показанных на рисунке дорожных знаков не запрещают выполнить поворот налево?","a":["Только дорожный знак 1.","Дорожные знаки 1 и 3.","Дорожные знаки 2 и 4.","Дорожные знаки 2, 3 и 5.","Все показанные дорожные знаки."],"c":4,"e":"<p>Все показанные на рисунке дорожные знаки</p> <ul><li>3.18.1 «Поворот направо запрещён» ,</li> <li>5.5 «Дорога с односторонним движением» ,</li> <li>3.19 «Разворот запрещён» ,</li> <li>5.11.1 «Место для разворота» ,</li> <li>5.19.3 «Тупик» </li></ul> <p>не запрещают выполнить поворот налево.</p>","image":"assets/adrive-questions/q200501301.webp"},{"id":200501302,"themeId":2,"group":2005013,"chapter":80,"chapters":[80],"q":"Какие из показанных на рисунке дорожных знаков не запрещают выполнить поворот налево?","a":["Только дорожный знак 5.","Дорожные знаки 2 и 5.","Дорожные знаки 1, 2 и 5.","Дорожные знаки 2, 4 и 5.","Все показанные дорожные знаки."],"c":3,"e":"<p>На рисунке под номерами 2, 4 и 5 изображены дорожные знаки</p> <ul><li>5.5 «Дорога с односторонним движением» ,</li> <li>5.11.1 «Место для разворота» ,</li> <li>4.1.6 «Движение направо или налево» ,</li></ul> <p>которые не запрещают выполнить левый поворот.</p>","image":"assets/adrive-questions/q200501302.webp"},{"id":200501441,"themeId":2,"group":2005014,"chapter":80,"chapters":[80],"q":"В каких направлениях Вам, управляя легковым автомобилем, разрешено продолжить движение в показанной обстановке?","a":["Только на разворот.","Только налево и на разворот.","Направо, налево и на разворот."],"c":1,"e":"<p>Поворот направо запрещён, так как в этом направлении имеется только велосипедная дорожка, по которой движение велосипедистов осуществляется навстречу общему потоку транспортных средств.<br> В остальных направлениях движение не запрещено.</p>","image":"assets/adrive-questions/q200501441.webp"},{"id":200501442,"themeId":2,"group":2005014,"chapter":80,"chapters":[80],"q":"Какие из показанных дорожных знаков запрещают Вам при управлении электромобилем повернуть направо?","a":["Только знак 1.","Только знаки 1 и 3.","Знаки 1, 3 и 4.","Знаки 1, 3, 4 и 5.","Все показанные знаки."],"c":2,"e":"<p>Повернуть направо на электромобиле запрещают первый («4.1.1 Движение прямо» ), третий («5.7.2 Выезд на дорогу с односторонним движением» ) и четвёртый («5.10.7 Выезд на дорогу с велосипедной дорожкой» ) дорожный знаки.</p> <p>Пятый знак («5.10.3 Выезд на дорогу с полосой для маршрутных транспортных средств» ) не запрещает движение на электромобиле по полосе для маршрутных транспортных средств.</p>","image":"assets/adrive-questions/q200501442.webp"},{"id":200501541,"themeId":2,"group":2005015,"chapter":80,"chapters":[80],"q":"Что обозначает нанесённый на показанный дорожный знак силуэт велосипедиста?","a":["Наличие наряду с пешеходным переходом велосипедного переезда.","По пешеходному переходу могут осуществлять движение велосипедисты.","Велосипедисты имеют преимущество перед пешеходами на пешеходном переходе."],"c":0,"e":"<p>Если на знаке «5.16.1, 5.16.2 Пешеходный переход» дополнительно нанесён силуэт велосипедиста, это обозначает наличие наряду с пешеходным переходом велосипедного переезда.</p>","image":"assets/adrive-questions/q200501541.webp"},{"id":200501602,"themeId":2,"group":2005016,"chapter":80,"chapters":[80],"q":"Разрешено ли водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны повернуть налево в показанной ситуации?","a":["Разрешено только в случае, если водитель проживает в обозначенной знаком зоне.","Разрешено только в случае, если водитель обслуживает торговое предприятие, расположенное в обозначенной знаком зоне.","Разрешено только в обоих вышеперечисленных случаях.","Разрешено в любом случае."],"c":3,"e":"<p>В показанной ситуации установленный дорожный знак 5.19.3 «Тупик» не запрещает поворот налево, поэтому водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны разрешено повернуть налево в любом случае.</p>","image":"assets/adrive-questions/q200501602.webp"},{"id":200501603,"themeId":2,"group":2005016,"chapter":80,"chapters":[80],"q":"Разрешено ли Вам продолжить движение прямо через перекрёсток в показанной ситуации?","a":["Да, разрешено.","Нет, запрещено.","Разрешено только к месту проживания при отсутствии иной возможности подъезда."],"c":0,"e":"<p>В показанной ситуации установленный дорожный знак 5.19.1 «Тупик» не запрещает движение прямо.</p>","image":"assets/adrive-questions/q200501603.webp"},{"id":200501651,"themeId":2,"group":2005016,"chapter":80,"chapters":[80],"q":"Разрешено ли Вам в показанной ситуации на перекрёстке повернуть направо?","a":["Разрешено.","Запрещено."],"c":0,"e":"<p>Дорожные знаки «5.19.1 – 5.19.3 Тупик» не запрещают движение, а информируют, что у данной дороги нет сквозного проезда.</p>","image":"assets/adrive-questions/q200501651.webp"},{"id":200501701,"themeId":2,"group":2005017,"chapter":80,"chapters":[80],"q":"Какие из показанных на рисунке дорожных знаков информируют о направлениях движения к населённым пунктам или другим объектам?","a":["Только дорожный знак 1.","Дорожные знаки 3 и 4.","Дорожные знаки 1, 3 и 4.","Все показанные на рисунке дорожные знаки."],"c":3,"e":"<p>Все показанные на рисунке дорожные знаки 5.20.1 «Предварительный указатель направлений» информируют о направлениях движения к населённым пунктам или другим объектам.</p>","image":"assets/adrive-questions/q200501701.webp"},{"id":200501702,"themeId":2,"group":2005017,"chapter":80,"chapters":[80],"q":"Какие из показанных на рисунке дорожных знаков информируют о направлениях движения к населённым пунктам или другим объектам?","a":["Только дорожный знак 5.","Дорожные знаки 4 и 5.","Дорожные знаки 1, 4 и 5.","Дорожные знаки 1, 2, 4 и 5.","Все показанные на рисунке дорожные знаки."],"c":2,"e":"<p>На рисунке под номерами 1, 4 и 5 изображены дорожные знаки 5.20.1, 5.20.2 «Предварительный указатель направлений» .</p> <p>Они информируют о направлениях движения к населённым пунктам или другим объектам.</p>","image":"assets/adrive-questions/q200501702.webp"},{"id":200501801,"themeId":2,"group":2005018,"chapter":80,"chapters":[80],"q":"Что означает цифра в нижней части показанного на рисунке дорожного знака?","a":["Расстояние до «стоп-линии» перед перекрёстком.","Расстояние до установленного запрещающего знака.","Расстояние от места установки знака до перекрёстка или начала полосы торможения."],"c":2,"e":"<p>Цифра в нижней части показанного на рисунке дорожного знака 5.20.1 «Предварительный указатель направлений» означает расстояние от места его установки до перекрёстка или начала полосы торможения.</p>","image":"assets/adrive-questions/q200501801.webp"},{"id":200501802,"themeId":2,"group":2005018,"chapter":80,"chapters":[80],"q":"Какие из показанных на рисунке дорожных знаков информируют о направлениях движения к населённым пунктам или другим объектам?","a":["Только дорожный знак 2.","Только дорожный знак 4.","Дорожные знаки 1, 2 и 4.","Дорожные знаки 1, 2, 3 и 4.","Все показанные на рисунке дорожные знаки."],"c":2,"e":"<p>На рисунке под номерами 1, 2 и 4 изображены дорожные знаки 5.20.1 «Предварительный указатель направлений» , 5.20.2 «Предварительный указатель направлений» и 5.21.1 «Указатель направления» .</p> <p>Они информируют о направлениях движения к населённым пунктам или другим объектам.</p>","image":"assets/adrive-questions/q200501802.webp"},{"id":200502001,"themeId":2,"group":2005020,"chapter":80,"chapters":[80],"q":"Какие из показанных на рисунке дорожных знаков информируют о начале населённого пункта, в котором действуют специальные требования Правил дорожного движения, устанавливающие порядок дорожного движения в населённых пунктах?","a":["Только дорожный знак 2.","Дорожные знаки 1 и 2.","Дорожные знаки 1, 2 и 3.","Дорожные знаки 1, 2 и 5.","Все показанные на рисунке дорожные знаки."],"c":1,"e":"<p>На рисунках под номерами 1, 2 изображены дорожные знаки 5.22.1, 5.22.2 «Начало населённого пункта» .</p> <p>Они информируют о начале населённого пункта, в котором действуют специальные требования Правил дорожного движения, устанавливающие порядок дорожного движения в населённых пунктах.</p>","image":"assets/adrive-questions/q200502001.webp"},{"id":200502002,"themeId":2,"group":2005020,"chapter":80,"chapters":[80],"q":"Какие из показанных на рисунке дорожных знаков информируют о начале границы населённого пункта, при движении по которому на данной дороге не действуют специальные требования Правил дорожного движения, устанавливающие порядок дорожного движения в населённых пунктах?","a":["Только дорожный знак 2.","Только дорожный знак 3.","Только дорожный знак 5.","Дорожные знаки 1 и 3.","Дорожные знаки 3 и 4."],"c":1,"e":"<p>На рисунке под номером 3 изображён дорожный знак 5.24 «Начало границы населённого пункта» , который информирует о начале границы населённого пункта, при движении по которому на данной дороге не действуют специальные требования Правил дорожного движения, устанавливающие порядок дорожного движения в населённых пунктах.</p>","image":"assets/adrive-questions/q200502002.webp"},{"id":200502051,"themeId":2,"group":2005020,"chapter":80,"chapters":[80],"q":"За дорожным знаком с белым фоном на показанном участке дороги:","a":["Действуют специальные требования Правил дорожного движения, устанавливающие порядок дорожного движения в населённых пунктах.","Не действуют специальные требования Правил дорожного движения, устанавливающие порядок дорожного движения в населённых пунктах."],"c":0,"e":"<p>На показанном участке дороги установлен дорожный знак «5.22.1 Начало населённого пункта», который обозначает начало населённого пункта, в котором действуют специальные требования Правил дорожного движения, устанавливающие порядок дорожного движения в населённых пунктах.</p>","image":"assets/adrive-questions/q200502051.webp"},{"id":200502052,"themeId":2,"group":2005020,"chapter":80,"chapters":[80],"q":"За дорожным знаком с синим фоном на показанном участке дороги:","a":["Действуют специальные требования Правил дорожного движения, устанавливающие порядок дорожного движения в населённых пунктах.","Не действуют специальные требования Правил дорожного движения, устанавливающие порядок дорожного движения в населённых пунктах."],"c":1,"e":"<p>На показанном участке дороги установлен дорожный знак «5.24 Начало границы населённого пункта». Он означает начало границы населённого пункта, при движении по которому на данной дороге не действуют специальные требования Правил дорожного движения, устанавливающие порядок дорожного движения в населённых пунктах.</p>","image":"assets/adrive-questions/q200502052.webp"},{"id":200502201,"themeId":2,"group":2005022,"chapter":80,"chapters":[80],"q":"Какие из показанных на рисунке дорожных знаков информируют только о расстоянии до населённых пунктов или других объектов?","a":["Только дорожный знак 3.","Только дорожный знак 4.","Дорожные знаки 3 и 4.","Все показанные на рисунке дорожные знаки."],"c":0,"e":"<p>На рисунке под номером 3 изображён дорожный знак 5.27 «Указатель расстояний» , который информирует о расстоянии до населённых пунктов или других объектов.</p>","image":"assets/adrive-questions/q200502201.webp"},{"id":200502202,"themeId":2,"group":2005022,"chapter":80,"chapters":[80],"q":"Какой из показанных на рисунке дорожных знаков информирует о расстоянии от начала дороги (км)?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4."],"c":1,"e":"<p>На рисунке под номером 2 изображён дорожный знак 5.28 «Километровый знак» , который информирует о расстоянии от начала дороги (в км).</p>","image":"assets/adrive-questions/q200502202.webp"},{"id":200502401,"themeId":2,"group":2005024,"chapter":80,"chapters":[80],"q":"О чём информирует участников дорожного движения установленный слева дорожный знак?","a":["О номере дороги.","О расстоянии от начала дороги.","О расстоянии до ближайшего города.","О расстоянии до ближайшего населённого пункта.","О рекомендуемой скорости на показанном участке дороги."],"c":1,"e":"<p>Установленный слева дорожный знак 5.28 «Километровый знак» информирует о расстоянии от начала дороги в километрах.</p>","image":"assets/adrive-questions/q200502401.webp"},{"id":200502402,"themeId":2,"group":2005024,"chapter":80,"chapters":[80],"q":"О чём информирует участников дорожного движения показанный дорожный знак?","a":["О расстоянии до места стоянки или отдыха.","О номере дороги, на которой установлен данный знак.","О номере дороги, в направлении к которой осуществляется движение."],"c":2,"e":"<p>В показанной ситуации установленный дорожный знак 5.29.2 «Номер дороги» информирует участников дорожного движения о номере дороги, в направлении к которой осуществляется движение.</p>","image":"assets/adrive-questions/q200502402.webp"},{"id":200502501,"themeId":2,"group":2005025,"chapter":80,"chapters":[80],"q":"В каких направлениях разрешено продолжить движение водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны?","a":["Только направо.","Прямо и направо.","Направо и на разворот.","Прямо, направо и на разворот.","Во всех направлениях."],"c":3,"e":"<p>В показанной ситуации установлены дорожные знаки:</p> <ul><li>3.4 «Движение грузовых автомобилей запрещено» — не запрещает водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны продолжить движение прямо.</li> <li>5.7.1 «Выезд на дорогу с односторонним движением» — запрещает водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны продолжить движение налево, при этом разрешён разворот.</li> <li>5.30.2 «Направление движения грузовых автомобилей» — информирует о рекомендуемом направлении движения для грузовых автомобилей.</li></ul> <p>Учитывая требования дорожных знаков, движение грузовому автомобилю с технически допустимой общей массой не более 3.5 тонны разрешено прямо, направо и на разворот.</p>","image":"assets/adrive-questions/q200502501.webp"},{"id":200502502,"themeId":2,"group":2005025,"chapter":80,"chapters":[80],"q":"В каких направлениях разрешено продолжить движение водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны?","a":["Только направо.","Прямо и направо.","Направо и на разворот.","Прямо, направо и на разворот.","Во всех направлениях."],"c":4,"e":"<p>В показанной ситуации установлены дорожные знаки:</p> <ul><li>3.4 «Движение грузовых автомобилей запрещено» — не запрещает водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны продолжить движение прямо.</li> <li>5.30.2 «Направление движения грузовых автомобилей» — информирует о рекомендуемом направлении движения для грузовых автомобилей.</li></ul> <p>Учитывая требования дорожных знаков, движение грузовому автомобилю с технически допустимой общей массой не более 3.5 тонны разрешено во всех направлениях.</p>","image":"assets/adrive-questions/q200502502.webp"},{"id":200502601,"themeId":2,"group":2005026,"chapter":80,"chapters":[80],"q":"Какой из показанных на рисунке дорожных знаков имеет рекомендательный характер?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":3,"e":"<p>На рисунке под номером 4 изображён дорожный знак 5.30.1 «Направление движения грузовых автомобилей» , который имеет рекомендательный характер.</p>","image":"assets/adrive-questions/q200502601.webp"},{"id":200502602,"themeId":2,"group":2005026,"chapter":80,"chapters":[80],"q":"Какой из показанных на рисунке дорожных знаков имеет рекомендательный характер?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":3,"e":"<p>На рисунке под номером 4 изображён дорожный знак 5.18.1 «Рекомендуемая скорость» , который имеет рекомендательный характер.</p>","image":"assets/adrive-questions/q200502602.webp"},{"id":200502701,"themeId":2,"group":2005027,"chapter":80,"chapters":[80],"q":"О чём информирует водителей дорожный знак, изображённый на рисунке?","a":["О том, что по указанному маршруту расположены два перекрёстка, на которых организовано круговое движение.","О маршруте объезда участка дороги, временно закрытого для движения.","О том, что по указанному на знаке маршруту объезда проводятся дорожные работы."],"c":1,"e":"<p>На рисунке изображён дорожный знак 5.31 «Схема объезда» , который информирует водителей о маршруте объезда участка дороги, временно закрытого для движения.</p>","image":"assets/adrive-questions/q200502701.webp"},{"id":200502702,"themeId":2,"group":2005027,"chapter":80,"chapters":[80],"q":"Какой из показанных на рисунке дорожных знаков называется «Схема объезда»?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":2,"e":"<p>На рисунке под номером 3 изображён дорожный знак 5.31 «Схема объезда» .</p>","image":"assets/adrive-questions/q200502702.webp"},{"id":200502801,"themeId":2,"group":2005028,"chapter":80,"chapters":[80],"q":"Какой из показанных на рисунке дорожных знаков называется «Направление объезда»?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":1,"e":"<p>На рисунке под номером 2 изображён дорожный знак 5.32.2 «Направление объезда» .</p>","image":"assets/adrive-questions/q200502801.webp"},{"id":200502802,"themeId":2,"group":2005028,"chapter":80,"chapters":[80],"q":"Какой из показанных на рисунке дорожных знаков информирует о направлении объезда участка дороги, временно закрытого для движения?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":0,"e":"<p>На рисунке под номером 1 изображён дорожный знак 5.32.2 «Направление объезда» , который информирует о направлении объезда участка дороги, временно закрытого для движения.</p>","image":"assets/adrive-questions/q200502802.webp"},{"id":200502901,"themeId":2,"group":2005029,"chapter":80,"chapters":[80],"q":"В каких направлениях разрешено продолжить движение водителю легкового автомобиля?","a":["Только направо.","Налево и на разворот.","Направо и на разворот.","Направо, налево и на разворот."],"c":3,"e":"<p>В показанной ситуации установленный дорожный знак 3.1 «Въезд запрещён» запрещает движение прямо.</p> <p>Поэтому водителю легкового автомобиля разрешено продолжить движение направо, налево и на разворот.</p> <p>Дорожный знак 5.32.2 «Направление объезда» не предписывает водителю поворачивать направо в обязательном порядке.</p>","image":"assets/adrive-questions/q200502901.webp"},{"id":200502903,"themeId":2,"group":2005029,"chapter":80,"chapters":[80],"q":"В каких направлениях Вам при управлении легковым автомобилем разрешено продолжить движение на показанном перекрёстке?","a":["Только налево.","Налево или на разворот.","Направо, налево или на разворот."],"c":2,"e":"<p>Показанный дорожный знак 5.32.3 «Направление объезда» указывает направление объезда участка дороги, временно закрытого для движения. Однако на данном перекрёстке отсутствуют запрещающие или предписывающие дорожные знаки, которые бы запрещали поворот направо.</p> <p>Часто таким образом знаки ставятся на маршруте объезда ремонтируемого участка для удобства ориентирования водителей транспортных средств, следующих транзитом.<br> Поэтому поворот направо на данном перекрёстке не запрещён.</p>","image":"assets/adrive-questions/q200502903.webp"},{"id":200503001,"themeId":2,"group":2005030,"chapter":80,"chapters":[80],"q":"Для каких целей применяется на дорогах дорожный знак, показанный на рисунке?","a":["Для запрещения дальнейшего движения всех транспортных средств.","Для запрещения движения транспортных средств без обязательной остановки перед дорожным знаком.","Для указания места остановки транспортных средств при запрещающем сигнале регулировщика, светофора."],"c":2,"e":"<p>На рисунке изображён дорожный знак 5.33 «Стоп-линия» , который применяется для указания места остановки транспортных средств при запрещающем сигнале регулировщика, светофора.</p>","image":"assets/adrive-questions/q200503001.webp"},{"id":200503002,"themeId":2,"group":2005030,"chapter":80,"chapters":[80],"q":"Какой из показанных на рисунке дорожных знаков указывает место остановки транспортных средств при запрещающем сигнале регулировщика, светофора?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":4,"e":"<p>На рисунке под номером 5 изображён дорожный знак 5.33 «Стоп-линия» , который применяется для указания места остановки транспортных средств при запрещающем сигнале регулировщика, светофора.</p>","image":"assets/adrive-questions/q200503002.webp"},{"id":200503051,"themeId":2,"group":2005030,"chapter":80,"chapters":[80],"q":"Показанный дорожный знак «5.33 Стоп-линия»:","a":["Запрещает движение без остановки перед краем пересекаемой проезжей части дороги.","Указывает место остановки транспортных средств при запрещающем сигнале регулировщика или светофора."],"c":1,"e":"<p>Показанный дорожный знак «5.33 Стоп-линия» указывает место остановки транспортных средств при запрещающем сигнале регулировщика или светофора.<br> В показанной ситуации водитель должен остановиться перед знаком, не выезжая на перекрёсток к светофору.</p>","image":"assets/adrive-questions/q200503051.webp"},{"id":200503101,"themeId":2,"group":2005031,"chapter":80,"chapters":[80],"q":"Какой из показанных на рисунке дорожных знаков указывает направление объезда участка проезжей части дороги с разделительной полосой, временно закрытого для движения?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":3,"e":"<p>На рисунке под номером 4 изображён дорожный знак 5.34.1 «Предварительный указатель перестроения на другую проезжую часть» , который указывает направление объезда участка проезжей части дороги с разделительной полосой, временно закрытого для движения.</p>","image":"assets/adrive-questions/q200503101.webp"},{"id":200503102,"themeId":2,"group":2005031,"chapter":80,"chapters":[80],"q":"Что обязан выполнить водитель на участке дороги, обозначенном таким дорожным знаком?","a":["Развернуться в установленном месте.","Повернуть налево на ближайшем перекрёстке.","Перестроиться в крайнюю левую полосу движения.","В установленном месте перестроиться на другую проезжую часть дороги."],"c":3,"e":"<p>На рисунке изображён дорожный знак 5.34.1 «Предварительный указатель перестроения на другую проезжую часть» , который обязывает водителя в установленном месте перестроиться на другую проезжую часть дороги.</p>","image":"assets/adrive-questions/q200503102.webp"},{"id":200503201,"themeId":2,"group":2005032,"chapter":80,"chapters":[80],"q":"Какой из показанных на рисунке дорожных знаков информирует о начале участка дороги с реверсивным движением?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":2,"e":"<p>На рисунке под номером 3 изображён дорожный знак 5.35 «Реверсивное движение» , который информирует о начале участка дороги с реверсивным движением.</p>","image":"assets/adrive-questions/q200503201.webp"},{"id":200503202,"themeId":2,"group":2005032,"chapter":80,"chapters":[80],"q":"Какой из показанных на рисунке дорожных знаков информирует о начале участка дороги, на одной или нескольких полосах которого направление движения может изменяться на противоположное?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":4,"e":"<p>На рисунке под номером 5 изображён дорожный знак 5.35 «Реверсивное движение» , информирующий о начале участка дороги, на одной или нескольких полосах которого направление движения может изменяться на противоположное.</p>","image":"assets/adrive-questions/q200503202.webp"},{"id":200503401,"themeId":2,"group":2005034,"chapter":80,"chapters":[80],"q":"Какой из показанных на рисунке дорожных знаков называется «Выезд на дорогу с реверсивным движением»?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":2,"e":"<p>На рисунке под номером 3 изображён дорожный знак 5.37 «Выезд на дорогу с реверсивным движением» .</p>","image":"assets/adrive-questions/q200503401.webp"},{"id":200503402,"themeId":2,"group":2005034,"chapter":80,"chapters":[80],"q":"Разрешается ли проехать перекрёсток прямо, если перед ним установлен показанный на рисунке дорожный знак?","a":["Да, разрешается.","Нет, запрещается."],"c":0,"e":"<p>На рисунке изображён дорожный знак 5.37 «Выезд на дорогу с реверсивным движением» , который не запрещает проехать перекрёсток прямо.</p>","image":"assets/adrive-questions/q200503402.webp"},{"id":200503501,"themeId":2,"group":2005035,"chapter":80,"chapters":[80],"q":"Какой из показанных на рисунке дорожных знаков информирует о начале территории, на которой действуют специальные требования Правил дорожного движения, устанавливающие порядок дорожного движения в пешеходных зонах?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":3,"e":"<p>На рисунке под номером 4 изображён дорожный знак 5.40 «Пешеходная зона» , обозначающий начало территории, на которой действуют специальные требования Правил дорожного движения, устанавливающие порядок дорожного движения в пешеходных зонах.</p>","image":"assets/adrive-questions/q200503501.webp"},{"id":200503502,"themeId":2,"group":2005035,"chapter":80,"chapters":[80],"q":"Как называется показанный на рисунке дорожный знак?","a":["Пешеходная зона.","Пешеходная дорожка.","Пешеходный переход.","Впереди пешеходный переход.","Движение пешеходов запрещено."],"c":0,"e":"<p>На рисунке изображён дорожный знак 5.40 «Пешеходная зона» .</p>","image":"assets/adrive-questions/q200503502.webp"},{"id":200503601,"themeId":2,"group":2005036,"chapter":80,"chapters":[80],"q":"О чём из предложенных вариантов ответов информирует показанный на рисунке дорожный знак?","a":["О том, что движение к Москве будет осуществляться по автомагистрали.","О том, что движение к Москве будет осуществляться по дороге, не являющейся автомагистралью."],"c":0,"e":"<p>На рисунке изображён дорожный знак 5.20.1 «Предварительный указатель направлений» , зелёный фон которого информирует о том, что движение к Москве будет осуществляться по автомагистрали.</p>","image":"assets/adrive-questions/q200503601.webp"},{"id":200503602,"themeId":2,"group":2005036,"chapter":80,"chapters":[80],"q":"О чём информирует показанный на рисунке дорожный знак?","a":["О том, что движение к Москве будет осуществляться по автомагистрали.","О том, что движение к Москве будет осуществляться по дороге, не являющейся автомагистралью."],"c":1,"e":"<p>На рисунке изображён дорожный знак 5.20.1 «Предварительный указатель направлений» , синий фон которого информирует о том, что движение к Москве будет осуществляться по дороге, не являющейся автомагистралью.</p>","image":"assets/adrive-questions/q200503602.webp"},{"id":200503701,"themeId":2,"group":2005037,"chapter":80,"chapters":[80],"q":"О чём из предложенных вариантов ответов информирует показанный на рисунке дорожный знак?","a":["О том, что движение к Минску будет осуществляться по автомагистрали.","О том, что движение к Минску будет осуществляться по дороге, не являющейся автомагистралью."],"c":1,"e":"<p>На рисунке изображён дорожный знак 5.20.1 «Предварительный указатель направлений» .</p> <p>Синий фон вставок на дорожном знаке, установленном вне населённого пункта, информирует о том, что движение к Минску будет осуществляться по дороге, не являющейся автомагистралью.</p>","image":"assets/adrive-questions/q200503701.webp"},{"id":200503702,"themeId":2,"group":2005037,"chapter":80,"chapters":[80],"q":"Зелёный фон изображённого дорожного знака указывает, что движение осуществляется:","a":["По автомагистрали.","По дороге, включённой в Европейскую систему автомобильных магистралей."],"c":0,"e":"<p>На рисунке изображён дорожный знак 5.27 «Указатель расстояний» с зелёным фоном, что в свою очередь указывает, что движение осуществляется по автомагистрали.</p>","image":"assets/adrive-questions/q200503702.webp"},{"id":200600101,"themeId":2,"group":2006001,"chapter":81,"chapters":[81],"q":"Какой из показанных на рисунке дорожных знаков называется «Мойка автомобилей»?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":1,"e":"<p>На рисунке под номером 2 изображён дорожный знак 6.5 «Мойка автомобилей» .</p>","image":"assets/adrive-questions/q200600101.webp"},{"id":200600102,"themeId":2,"group":2006001,"chapter":81,"chapters":[81],"q":"Какой из показанных на рисунке дорожных знаков называется «Техническое обслуживание автомобилей»?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":1,"e":"<p>На рисунке под номером 2 изображён дорожный знак 6.4 «Техническое обслуживание автомобилей» .</p>","image":"assets/adrive-questions/q200600102.webp"},{"id":200600202,"themeId":2,"group":2006002,"chapter":81,"chapters":[81],"q":"Какие из показанных на рисунке дорожных знаков информируют о расположении автозаправочной станции, на которой может осуществляться заправка автомобиля газом?","a":["Только дорожный знак 1.","Дорожные знаки 1 и 2.","Дорожные знаки 2 и 3.","Дорожные знаки 1 и 3.","Все показанные дорожные знаки."],"c":2,"e":"<p>На рисунке под номерами 2 и 3 изображены дорожные знаки 6.3.2, 6.3.4 «Автозаправочная станция» , которые информируют о расположении автозаправочной станции, где может осуществляться заправка автомобиля газом.</p>","image":"assets/adrive-questions/q200600202.webp"},{"id":200600241,"themeId":2,"group":2006002,"chapter":81,"chapters":[81],"q":"Каким дорожным знаком может обозначаться станция, на которой имеется возможность зарядить электромобиль?","a":["Только знаком 1.","Знаком 1 или 3.","Любым из показанных знаков."],"c":1,"e":"<p>Электромобиль можно зарядить на автозаправочных станциях, перед которыми установлены знаки с изображением зелёной автоколонки («6.3.3 Автозаправочная станция» , «6.3.4 Автозаправочная станция» ).</p>","image":"assets/adrive-questions/q200600241.webp"},{"id":200600301,"themeId":2,"group":2006003,"chapter":81,"chapters":[81],"q":"Какой из показанных на рисунке дорожных знаков называется «Место отдыха»?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":2,"e":"<p>На рисунке под номером 3 изображён дорожный знак 6.11 «Место отдыха» .</p>","image":"assets/adrive-questions/q200600301.webp"},{"id":200600302,"themeId":2,"group":2006003,"chapter":81,"chapters":[81],"q":"Какой из показанных на рисунке дорожных знаков информирует о расположении мотеля?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":0,"e":"<p>На рисунке под номером 1 изображён дорожный знак 6.9 «Гостиница или мотель» .</p>","image":"assets/adrive-questions/q200600302.webp"},{"id":200600401,"themeId":2,"group":2006004,"chapter":81,"chapters":[81],"q":"Какой из показанных на рисунке дорожных знаков информирует о расположении кемпинга?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":1,"e":"<p>На рисунке под номером 2 изображён дорожный знак 6.10 «Кемпинг» .</p>","image":"assets/adrive-questions/q200600401.webp"},{"id":200600402,"themeId":2,"group":2006004,"chapter":81,"chapters":[81],"q":"Какими дорожными знаками из показанных на рисунке может обозначаться объект, куда участник ДТП обязан доставить пострадавшего при отсутствии возможности вызвать скорую медицинскую помощь?","a":["Только дорожным знаком 1.","Дорожными знаками 1 и 2.","Дорожными знаками 1, 2 и 5.","Дорожными знаками 1, 2 и 4.","Всеми показанными на рисунке дорожными знаками."],"c":1,"e":"<p>На рисунке под номерами 1 и 2 изображены дорожные знаки 6.1 «Пункт первой медицинской помощи» и 6.2 «Больница» , которыми может обозначаться медицинское учреждение, куда участник дорожно-транспортного происшествия обязан доставить пострадавшего при отсутствии возможности вызвать скорую медицинскую помощь.</p>","image":"assets/adrive-questions/q200600402.webp"},{"id":200600541,"themeId":2,"group":2006005,"chapter":81,"chapters":[81],"q":"Показанный дорожный знак информирует о расположении:","a":["Автозаправочной станции.","Платной автомобильной стоянки.","Пункта контроля автомобильных перевозок.","Пункта обслуживания системы электронного сбора платы за проезд."],"c":3,"e":"<p>Показанный дорожный знак «6.16 Пункт обслуживания системы электронного сбора платы за проезд» информирует о расположении пункта обслуживания системы электронного сбора платы за проезд.</p>","image":"assets/adrive-questions/q200600541.webp"},{"id":200700101,"themeId":2,"group":2007001,"chapter":82,"chapters":[82],"q":"Что означает изображённое на рисунке сочетание дорожных знаков?","a":["Через 50 метров на проезжей части дороги установлена искусственная неровность.","Протяжённость участка дороги с искусственными неровностями составляет 50 метров."],"c":0,"e":"<p>В показанной ситуации установленные дорожные знаки 1.16.1 «Искусственная неровность» и 7.1.1 «Расстояние до объекта» означают, что через 50 метров на проезжей части дороги установлена искусственная неровность.</p>","image":"assets/adrive-questions/q200700101.webp"},{"id":200700102,"themeId":2,"group":2007001,"chapter":82,"chapters":[82],"q":"Что означает изображённое на рисунке сочетание дорожных знаков, установленных за перекрёстком?","a":["За перекрёстком возможно образование затора транспортных средств. Длина объезда этого участка дороги — 200 метров.","Через 200 метров возможно образование заторов транспортных средств. Вправо — направление объезда этого участка дороги.","За перекрёстком возможно образование затора транспортных средств протяжённостью до 200 метров. Вправо — направление объезда этого участка дороги."],"c":1,"e":"<p>В показанной ситуации установленные дорожные знаки 1.34 «Затор на дороге» , 7.1.1 «Расстояние до объекта» и 5.32.2 «Направление объезда» означают, что через 200 метров возможно образование заторов транспортных средств. Вправо — направление объезда этого участка дороги.</p>","image":"assets/adrive-questions/q200700102.webp"},{"id":200700201,"themeId":2,"group":2007002,"chapter":82,"chapters":[82],"q":"Что означает показанное сочетание дорожных знаков?","a":["Через 150 метров — перекрёсток, перед которым установлен знак «Уступить дорогу».","Через 150 метров — перекрёсток, перед которым установлен знак «Движение без остановки запрещено»."],"c":0,"e":"<p>В показанной ситуации установленные дорожные знаки 2.4 «Уступить дорогу» и 7.1.1 «Расстояние до объекта» означают, что через 150 метров — перекрёсток, перед которым установлен дорожный знак «Уступить дорогу».</p>","image":"assets/adrive-questions/q200700201.webp"},{"id":200700202,"themeId":2,"group":2007002,"chapter":82,"chapters":[82],"q":"Что означает изображённое на рисунке сочетание дорожных знаков?","a":["Через 50 метров установлен знак «Уступить дорогу».","Через 50 метров — перекрёсток, на котором отменяется право преимущественного проезда перекрёстка.","Через 50 метров — последний перекрёсток на данной дороге, обозначенный знаком «Главная дорога»."],"c":1,"e":"<p>В показанной ситуации установленные дорожные знаки 2.2 «Конец главной дороги» и 7.1.1 «Расстояние до объекта» означают, что через 50 метров — перекрёсток, на котором отменяется право преимущественного проезда перекрёстка.</p>","image":"assets/adrive-questions/q200700202.webp"},{"id":200700301,"themeId":2,"group":2007003,"chapter":82,"chapters":[82],"q":"Что означает изображённое на рисунке сочетание дорожных знаков?","a":["Обгон транспортных средств, движущихся со скоростью менее 50 км/ч, запрещён на протяжении 250 метров.","Обгон транспортных средств, движущихся со скоростью менее 50 км/ч, запрещён через 250 метров.","Обгон транспортных средств, движущихся со скоростью более 50 км/ч, запрещён на протяжении 250 метров.","Обгон транспортных средств, движущихся со скоростью более 50 км/ч, запрещён через 250 метров."],"c":3,"e":"<p>В показанной ситуации установленные дорожные знаки 3.20.3 «Обгон запрещён» и 7.1.1 «Расстояние до объекта» означают, что обгон транспортных средств, движущихся со скоростью более 50 км/ч, запрещён через 250 метров.</p>","image":"assets/adrive-questions/q200700301.webp"},{"id":200700302,"themeId":2,"group":2007003,"chapter":82,"chapters":[82],"q":"В каком из перечисленных случаев водитель легкового автомобиля нарушит Правила дорожного движения, если скорость движения трактора менее 30 км/ч?","a":["Обгонит одиночный трактор со скоростью 50 км/ч более чем через 300 метров.","Обгонит одиночный трактор со скоростью 80 км/ч не более чем через 300 метров.","Обгонит одиночный трактор со скоростью 50 км/ч не более чем через 300 метров.","Не нарушит во всех перечисленных случаях."],"c":1,"e":"<p>В показанной ситуации установленные дорожные знаки 3.20.1 «Обгон запрещён» и 7.1.1 «Расстояние до объекта» означают, что обгон будет запрещён через 300 метров, а дорожный знак 3.24.1 «Ограничение максимальной скорости» запрещает движение со скоростью более 50 км/ч.</p> <p>Поэтому водитель легкового автомобиля нарушит требование дорожного знака 3.24.1 «Ограничение максимальной скорости», если обгонит одиночный трактор со скоростью 80 км/ч.</p>","image":"assets/adrive-questions/q200700302.webp"},{"id":200700401,"themeId":2,"group":2007004,"chapter":82,"chapters":[82],"q":"Нарушает ли водитель легкового автомобиля Правила дорожного движения, проезжая перекрёсток в прямом направлении в показанной ситуации?","a":["Да, нарушает.","Нет, не нарушает.","Не нарушает, если он проживает в зоне действия показанного на рисунке запрещающего знака."],"c":1,"e":"<p>В показанной ситуации установленные дорожные знаки 3.1 «Въезд запрещён» и 7.1.1 «Расстояние до объекта» означают, что въезд будет запрещён только через 150 метров, поэтому в показанной ситуации водитель легкового автомобиля не нарушает Правила дорожного движения.</p>","image":"assets/adrive-questions/q200700401.webp"},{"id":200700402,"themeId":2,"group":2007004,"chapter":82,"chapters":[82],"q":"О чём информирует водителя показанное сочетание дорожных знаков?","a":["О расстоянии до места для стоянки транспортных средств.","О том, что стоянка транспортных средств запрещена до установленного места для стоянки."],"c":0,"e":"<p>В показанной ситуации установленные дорожные знаки 5.15 «Место стоянки» и 7.1.1 «Расстояние до объекта» информируют водителя о расстоянии (200 метров) до места для стоянки транспортных средств.</p>","image":"assets/adrive-questions/q200700402.webp"},{"id":200700601,"themeId":2,"group":2007006,"chapter":82,"chapters":[82],"q":"Какие из показанных на рисунке дорожных знаков называются «Расстояние до объекта»?","a":["Только дорожный знак 1.","Только дорожный знак 3.","Дорожные знаки 3 и 4.","Дорожные знаки 3, 4 и 5.","Все показанные на рисунке дорожные знаки."],"c":2,"e":"<p>На рисунке под номерами 3 и 4 изображены дорожные знаки 7.1.1, 7.1.2 «Расстояние до объекта» .</p>","image":"assets/adrive-questions/q200700601.webp"},{"id":200700602,"themeId":2,"group":2007006,"chapter":82,"chapters":[82],"q":"Какой из показанных на рисунке дорожных знаков называется «Расстояние до объекта»?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":1,"e":"<p>На рисунке под номером 2 изображён дорожный знак 7.1.3 «Расстояние до объекта» .</p>","image":"assets/adrive-questions/q200700602.webp"},{"id":200700701,"themeId":2,"group":2007007,"chapter":82,"chapters":[82],"q":"Об установке какого дорожного знака перед перекрёстком, расположенным через 250 метров, информирует показанное сочетание дорожных знаков?","a":["Стоп-линия.","Уступить дорогу.","Конец главной дороги.","Движение без остановки запрещено.","Преимущество встречного движения."],"c":3,"e":"<p>В показанной ситуации установленные дорожные знаки 2.4 «Уступить дорогу» и 7.1.2 «Расстояние до объекта» информируют о том, что через 250 метров перед перекрёстком установлен дорожный знак 2.5 «Движение без остановки запрещено» .</p>","image":"assets/adrive-questions/q200700701.webp"},{"id":200700732,"themeId":2,"group":2007007,"chapter":82,"chapters":[82],"q":"Что необходимо сделать водителю, двигаясь вперёд, через 250 метров?","a":["Уступить дорогу транспортным средствам, двигающимся по главной дороге, остановившись перед дорожным знаком 5.33 «Стоп-линия» (горизонтальной дорожной разметкой «Стоп-линия»), а при их отсутствии разрешается не останавливаться.","Уступить дорогу транспортным средствам, двигающимся по главной дороге, остановившись перед дорожным знаком 5.33 «Стоп-линия» (горизонтальной дорожной разметкой «Стоп-линия»), а при их отсутствии — перед краем пересекаемой проезжей части дороги."],"c":1,"e":"<p>Табличка, установленная под дорожным знаком «Уступить дорогу» , 7.1.2 «Расстояние до объекта» информирует о расстоянии от знака до перекрестка, если непосредственно перед перекрестком установлен знак 2.5 «Движение без остановки запрещено» .</p> <p>Поэтому на ближайшем перекрёстке запрещается движение без остановки перед знаком 5.33 «Стоп-линия» (горизонтальной дорожной разметкой 1.12 «стоп-линия» ), а при их отсутствии — перед краем пересекаемой проезжей части дорог.</p>","image":"assets/adrive-questions/q200700732.webp"},{"id":200700801,"themeId":2,"group":2007008,"chapter":82,"chapters":[82],"q":"В каком из показанных на рисунке вариантов дорожный знак дополнительной информации указывает расстояние до объекта, расположенного в стороне от дороги?","a":["Только № 1.","Только № 2.","В обоих вариантах."],"c":1,"e":"<p>Изображения табличек 7.2.6 «Зона действия» и 7.1.4 «Расстояние до объекта» идентичны, различают их следующим образом: при применении с дорожными знаками 3.27–3.30 табличка указывает зону действия, при применении с иными дорожными знаками — расстояние до объекта.</p>","image":"assets/adrive-questions/q200700801.webp"},{"id":200700802,"themeId":2,"group":2007008,"chapter":82,"chapters":[82],"q":"Что указывает табличка под предупреждающим дорожным знаком?","a":["Направление объезда опасного участка дороги.","Направление движения к разводному мосту или паромной переправе и ширину реки.","Расстояние до разводного моста или паромной переправы, находящихся слева от дороги."],"c":2,"e":"<p>Показанный на рисунке дорожный знак 7.1.4 «Расстояние до объекта» указывает расстояние до разводного моста или паромной переправы, находящихся слева от дороги.</p>","image":"assets/adrive-questions/q200700802.webp"},{"id":200700901,"themeId":2,"group":2007009,"chapter":82,"chapters":[82],"q":"Нарушит ли Правила дорожного движения водитель легкового автомобиля, начав обгон автобуса, движущегося со скоростью 50 км/ч, в показанном месте?","a":["Не нарушит, если закончит обгон менее чем за 300 метров.","Не нарушит, если закончит обгон более чем за 300 метров.","Нарушит в любом из перечисленных случаев."],"c":2,"e":"<p>В показанной ситуации установленные дорожные знаки 3.20.2 «Обгон запрещён» и 7.2.1 «Зона действия» запрещают обгон на участке дороги протяжённостью 300 метров.</p> <p>Поэтому водитель легкового автомобиля, начав обгон автобуса в показанном месте, нарушит Правила дорожного движения.</p>","image":"assets/adrive-questions/q200700901.webp"},{"id":200700902,"themeId":2,"group":2007009,"chapter":82,"chapters":[82],"q":"Показанное на рисунке сочетание дорожных знаков обязывает водителя:","a":["Не приближаться к движущемуся впереди транспортному средству на расстояние менее 70 метров на протяжении 100 метров дороги.","Поддерживать дистанцию до впереди движущегося транспортного средства не более 70 метров.","Поддерживать дистанцию до впереди движущегося транспортного средства от 70 до 100 метров."],"c":0,"e":"<p>Показанное на рисунке сочетание дорожных знаков 3.16 «Ограничение минимальной дистанции» и 7.2.1 «Зона действия» обязывает водителя не приближаться к движущемуся впереди транспортному средству на расстояние менее 70 метров на протяжении 100 метров дороги.</p>","image":"assets/adrive-questions/q200700902.webp"},{"id":200701001,"themeId":2,"group":2007010,"chapter":82,"chapters":[82],"q":"Что указывает табличка, применённая совместно с дорожным знаком «Пешеходный переход»?","a":["Длину пешеходного перехода.","Ширину зоны пешеходного перехода.","Интенсивность движения (чел./мин).","Расстояние до пешеходного перехода."],"c":1,"e":"<p>На рисунке табличка 7.2.1 «Зона действия» , применённая совместно с дорожным знаком 5.16.2 «Пешеходный переход» , указывает ширину зоны пешеходного перехода.</p>","image":"assets/adrive-questions/q200701001.webp"},{"id":200701002,"themeId":2,"group":2007010,"chapter":82,"chapters":[82],"q":"О чём информирует водителя показанное на рисунке сочетание дорожных знаков?","a":["О протяжённости участка дороги, на котором возможно появление детей с территории детского или иного учреждения, прилегающего непосредственно к дороге.","О расстоянии до начала участка дороги, на котором возможно появление детей с территории детского или иного учреждения, прилегающего непосредственно к дороге."],"c":0,"e":"<p>Показанное на рисунке сочетание дорожных знаков 1.21 «Дети» и 7.2.1 «Зона действия» информирует водителя о протяжённости участка дороги, на котором возможно появление детей с территории детского или иного учреждения, прилегающего непосредственно к дороге.</p>","image":"assets/adrive-questions/q200701002.webp"},{"id":200701051,"themeId":2,"group":2007010,"chapter":82,"chapters":[82],"q":"О чём предупреждает показанное сочетание дорожных знаков?","a":["О том, что протяжённость участка дороги, на котором возможны снежные заносы либо ледяные или снежно-ледяные образования, составляет 500 метров.","О том, что расстояние до начала участка дороги, на котором возможны снежные заносы либо ледяные или снежно-ледяные образования, составляет 500 метров."],"c":0,"e":"<p>Дорожный знак «1.3 Гололедица» предупреждает о приближении к опасному участку дороги, на котором возможны снежные заносы либо ледяные или снежно-ледяные образования.</p> <p>Табличка «7.2.1 Зона действия» <strong>информирует о протяжённости</strong> этого опасного участка дороги.</p>","image":"assets/adrive-questions/q200701051.webp"},{"id":200701101,"themeId":2,"group":2007011,"chapter":82,"chapters":[82],"q":"О чём предупреждает участников дорожного движения показанное на рисунке сочетание дорожных знаков?","a":["О приближении к участку дороги с неровностями на проезжей части (волны, наплывы, гребёнка) протяжённостью 100 метров.","О приближении к участку дороги с искусственными неровностями на проезжей части дороги с расстоянием между ними, равным 10 метрам.","О приближении к участку дороги с искусственными неровностями на проезжей части дороги, расположенными на протяжении 100 метров.","О приближении к участку дороги, на котором имеются неплавные сопряжения с проезжей частью дороги в виде наплыва (бугра), расположенные на расстоянии 100 метров друг от друга."],"c":0,"e":"<p>Показанное на рисунке сочетание дорожных знаков 1.16.2 «Неровная дорога» и 7.2.1 «Зона действия» предупреждает участников дорожного движения о приближении к участку дороги с неровностями на проезжей части (волны, наплывы, гребёнка) протяжённостью 100 метров.</p>","image":"assets/adrive-questions/q200701101.webp"},{"id":200701102,"themeId":2,"group":2007011,"chapter":82,"chapters":[82],"q":"Какой из показанных на рисунке дорожных знаков называется «Зона действия»?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":3,"e":"<p>На рисунке под номером 4 изображён дорожный знак 7.2.4 «Зона действия» .</p>","image":"assets/adrive-questions/q200701102.webp"},{"id":200701201,"themeId":2,"group":2007012,"chapter":82,"chapters":[82],"q":"Какое количество опасных поворотов может обозначать показанное на рисунке сочетание дорожных знаков?","a":["Два.","Три и более.","Любое количество."],"c":1,"e":"<p>Показанное на рисунке сочетание дорожных знаков 1.12.1 «Опасные повороты» и 7.2.1 «Зона действия» информирует водителя о трёх и более опасных поворотах, расположенных один за другим.</p>","image":"assets/adrive-questions/q200701201.webp"},{"id":200701202,"themeId":2,"group":2007012,"chapter":82,"chapters":[82],"q":"Показанная на рисунке табличка применяется с дорожным знаком «Опасные повороты» в случае, если:","a":["Поворотов на дороге больше, чем изображено на предупреждающем знаке.","Поворотов на дороге меньше, чем изображено на предупреждающем знаке.","Поворотов на дороге два, но расстояние между ними превышает 50 метров."],"c":0,"e":"<p>Показанное на рисунке сочетание дорожных знаков 1.12.1 «Опасные повороты» и 7.2.1 «Зона действия» применяется, когда количество поворотов на дороге больше, чем изображено на предупреждающем знаке (от трёх и более).</p>","image":"assets/adrive-questions/q200701202.webp"},{"id":200701301,"themeId":2,"group":2007013,"chapter":82,"chapters":[82],"q":"Показанная на рисунке табличка может указывать:","a":["Зону действия запрещающих дорожных знаков.","Зону действия предписывающих дорожных знаков.","Зону действия информационно-указательных дорожных знаков.","Протяжённость опасного участка дороги, обозначенного предупреждающими дорожными знаками.","Всё перечисленное."],"c":4,"e":"<p>Показанная на рисунке табличка 7.2.1 «Зона действия» указывает протяжённость опасного участка дороги, обозначенного предупреждающими дорожными знаками, или зону действия запрещающих, предписывающих либо информационно-указательных дорожных знаков.</p>","image":"assets/adrive-questions/q200701301.webp"},{"id":200701351,"themeId":2,"group":2007013,"chapter":82,"chapters":[82],"q":"Разрешено ли Вам совершить разворот на показанном участке дороги?","a":["Разрешено.","Разрешено только при отсутствии встречных транспортных средств.","Запрещено."],"c":2,"e":"<p>Табличка «7.2.1. Зона действия» устанавливает протяжённость участка дороги, на котором необходимо двигаться только прямо. Поэтому на показанном участке дороги разворот запрещён.</p>","image":"assets/adrive-questions/q200701351.webp"},{"id":200701401,"themeId":2,"group":2007014,"chapter":82,"chapters":[82],"q":"В каком из перечисленных мест разрешена остановка при таком сочетании дорожных знаков?","a":["После знака на расстоянии менее чем за 10 метров.","Перед знаком на расстоянии менее чем за 10 метров.","Разрешена в обоих перечисленных случаях."],"c":1,"e":"<p>При сочетании дорожных знаков 3.27 «Остановка запрещена» и 7.2.2 «Зона действия» запрещены остановка и стоянка после знака на расстоянии 10 метров.</p> <p>При остановке перед дорожным знаком необходимо учитывать, чтобы транспортное средство не закрыло дорожные знаки от других водителей.</p>","image":"assets/adrive-questions/q200701401.webp"},{"id":200701402,"themeId":2,"group":2007014,"chapter":82,"chapters":[82],"q":"При остановке в каком из перечисленных мест водитель не нарушит требования данного сочетания дорожных знаков?","a":["После дорожного знака на расстоянии более чем через 10 метров.","Перед дорожным знаком на расстоянии более чем за 10 метров.","Не нарушит в обоих перечисленных местах."],"c":2,"e":"<p>При сочетании дорожных знаков 3.27 «Остановка запрещена» и 7.2.2 «Зона действия» запрещены остановка и стоянка после знака на расстоянии 10 метров.</p>","image":"assets/adrive-questions/q200701402.webp"},{"id":200701501,"themeId":2,"group":2007015,"chapter":82,"chapters":[82],"q":"В каком из перечисленных мест разрешена остановка при таком сочетании дорожных знаков?","a":["После дорожного знака на расстоянии менее чем через 10 метров.","Перед дорожным знаком на расстоянии менее чем за 10 метров.","Разрешена в обоих перечисленных случаях."],"c":0,"e":"<p>При сочетании дорожных знаков 3.27 «Остановка запрещена» и 7.2.3 «Зона действия» остановка и стоянка запрещены перед знаком.</p>","image":"assets/adrive-questions/q200701501.webp"},{"id":200701502,"themeId":2,"group":2007015,"chapter":82,"chapters":[82],"q":"При остановке в каком из перечисленных мест водитель не нарушит требования данного сочетания дорожных знаков?","a":["Если совершит остановку после места установки дорожного знака.","Если совершит остановку перед местом установки дорожного знака.","Не нарушит в обоих перечисленных местах."],"c":0,"e":"<p>При сочетании дорожных знаков 3.27 «Остановка запрещена» и 7.2.3 «Зона действия» остановка и стоянка запрещены перед знаком.</p>","image":"assets/adrive-questions/q200701502.webp"},{"id":200701554,"themeId":2,"group":2007015,"chapter":82,"chapters":[82],"q":"Что из нижеперечисленного разрешено водителю в показанном стрелкой месте?","a":["Разрешена только остановка.","Разрешены остановка и стоянка.","Запрещено всё перечисленное."],"c":1,"e":"<p>Табличка «7.2.3 Зона действия» указывает на окончание зоны действия дорожного знака «3.27 Остановка запрещена». Поэтому в показанном месте разрешены и остановка, и стоянка.</p>","image":"assets/adrive-questions/q200701554.webp"},{"id":200701601,"themeId":2,"group":2007016,"chapter":82,"chapters":[82],"q":"Кто из водителей в показанной ситуации остановился в соответствии с Правилами дорожного движения?","a":["Водитель жёлтого автомобиля.","Водитель красного автомобиля.","Водители обоих автомобилей нарушили Правила дорожного движения.","Водители обоих автомобилей не нарушили Правила дорожного движения."],"c":2,"e":"<p>В показанной ситуации установленные дорожные знаки 3.27 «Остановка запрещена» и 7.2.4 «Зона действия» запрещают остановку и стоянку до и после установленных знаков.</p> <p>При этом их действие не распространяется на площадку, обозначенную дорожным знаком 5.15 «Место стоянки» .</p>","image":"assets/adrive-questions/q200701601.webp"},{"id":200701602,"themeId":2,"group":2007016,"chapter":82,"chapters":[82],"q":"Кто из водителей в показанной ситуации остановился в соответствии с Правилами дорожного движения?","a":["Водитель белого автомобиля.","Водитель жёлтого автомобиля.","Водители обоих автомобилей."],"c":0,"e":"<p>В показанной ситуации установленные дорожные знаки 3.27 «Остановка запрещена» и 7.2.4 «Зона действия» запрещают остановку и стоянку до и после установленных знаков.</p> <p>Дорожный знак действует на ту сторону дороги, у которой он установлен.</p>","image":"assets/adrive-questions/q200701602.webp"},{"id":200701701,"themeId":2,"group":2007017,"chapter":82,"chapters":[82],"q":"Кому из водителей в показанной ситуации разрешено повернуть в направлении, показанном стрелками?","a":["Мотоциклисту.","Водителю легкового автомобиля.","Разрешено обоим водителям.","Запрещено обоим водителям."],"c":2,"e":"<p>В показанной ситуации установленные дорожные знаки 3.7 «Движение с прицепом запрещено» и 7.3.1 «Направление действия» запрещают движение грузовых автомобилей, колёсных тракторов и самоходных машин с прицепами и полуприцепами любого типа, а также буксировку механических транспортных средств.</p>","image":"assets/adrive-questions/q200701701.webp"},{"id":200701702,"themeId":2,"group":2007017,"chapter":82,"chapters":[82],"q":"Разрешено ли в показанной ситуации водителям повернуть в направлении, показанном стрелками?","a":["Разрешено водителю легкового автомобиля, буксирующего другой легковой автомобиль.","Разрешено водителю легкового автомобиля, буксирующего мотоцикл с боковым прицепом.","Разрешено обоим водителям.","Запрещено обоим водителям."],"c":3,"e":"<p>В показанной ситуации установленные дорожные знаки 3.7 «Движение с прицепом запрещено» и 7.3.1 «Направление действия» запрещают буксировку механических транспортных средств.</p>","image":"assets/adrive-questions/q200701702.webp"},{"id":200701901,"themeId":2,"group":2007019,"chapter":82,"chapters":[82],"q":"В каком из перечисленных случаев водителю грузового автомобиля разрешено повернуть направо?","a":["Если масса перевозимого груза превышает 1.5 тонны.","Если фактическая масса превышает 1.5 тонны.","Если фактическая масса превышает 1.5 тонны при следовании к месту работы при отсутствии иных возможностей подъезда.","Разрешено во всех перечисленных случаях.","Запрещено во всех перечисленных случаях."],"c":2,"e":"<p>В показанной ситуации, установленные дорожные знаки 3.4 «Движение грузовых автомобилей запрещено» и 7.3.1 «Направление действия» запрещают движение направо грузовых автомобилей с фактической массой более 1.5 тонны, за исключением следования грузового автомобиля к месту работы при отсутствии иных возможностей подъезда.</p>","image":"assets/adrive-questions/q200701901.webp"},{"id":200701902,"themeId":2,"group":2007019,"chapter":82,"chapters":[82],"q":"В каких направлениях разрешено продолжить движение водителю грузового автомобиля с фактической массой 3.4 тонны?","a":["Только прямо.","Направо и налево.","Прямо и на разворот.","Направо, налево на разворот.","Во всех направлениях."],"c":2,"e":"<p>В показанной ситуации, установленные дорожные знаки 3.4 «Движение грузовых автомобилей запрещено» и 7.3.3 «Направление действия» запрещают движение направо и налево грузовых автомобилей с фактической массой более 1.5 тонны.</p>","image":"assets/adrive-questions/q200701902.webp"},{"id":200702001,"themeId":2,"group":2007020,"chapter":82,"chapters":[82],"q":"Показанное на рисунке сочетание дорожных знаков:","a":["Запрещает движение механических транспортных средств только в направлении, указанном стрелкой.","Рекомендует продолжать движение механическим транспортным средствам в направлении, указанном стрелкой.","Запрещает движение механическим транспортным средствам во всех направлениях, кроме направления, указанного стрелкой.","Запрещает движение механическим транспортным средствам в направлении, указанном стрелкой, и на разворот."],"c":0,"e":"<p>Показанное на рисунке сочетание дорожных знаков 3.3 «Движение механических транспортных средств запрещено» и 7.3.2 «Направление действия» запрещает движение механических транспортных средств только в направлении, указанном стрелкой.</p>","image":"assets/adrive-questions/q200702001.webp"},{"id":200702002,"themeId":2,"group":2007020,"chapter":82,"chapters":[82],"q":"В каких направлениях из перечисленных разрешено продолжить движение водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны?","a":["Только прямо.","Направо и налево.","Прямо и на разворот.","Во всех направлениях."],"c":2,"e":"<p>В показанной ситуации сочетание дорожных знаков 3.3 «Движение механических транспортных средств запрещено» и 7.3.3 «Направление действия» запрещает движение механических транспортных средств только направо и налево.</p> <p>Поэтому водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны разрешено продолжить движение прямо и на разворот.</p>","image":"assets/adrive-questions/q200702002.webp"},{"id":200702101,"themeId":2,"group":2007021,"chapter":82,"chapters":[82],"q":"Разрешено ли Вам, управляя легковым автомобилем, в показанной ситуации повернуть налево к месту работы при наличии иной возможности подъезда?","a":["Да, разрешено.","Нет, запрещено."],"c":1,"e":"<p>В показанной ситуации сочетание дорожных знаков 3.3 «Движение механических транспортных средств запрещено» и 7.3.2 «Направление действия» запрещает движение налево водителю легкового автомобиля для проезда к месту работы при наличии иной возможности подъезда.</p>","image":"assets/adrive-questions/q200702101.webp"},{"id":200702102,"themeId":2,"group":2007021,"chapter":82,"chapters":[82],"q":"Разрешено ли водителю легкового автомобиля, обозначенному опознавательным знаком «Инвалид», повернуть направо к месту его проживания при наличии иной возможности подъезда?","a":["Да, разрешено.","Нет, запрещено."],"c":0,"e":"<p>В показанной ситуации сочетание дорожных знаков «3.3 Движение механических транспортных средств запрещено» и «7.3.1 Направление действия» не запрещает водителю легкового автомобиля, обозначенному опознавательным знаком «Инвалид» , повернуть направо к месту его проживания при наличии иной возможности подъезда.</p>","image":"assets/adrive-questions/q200702102.webp"},{"id":200702161,"themeId":2,"group":2007021,"chapter":82,"chapters":[82],"q":"В каких направлениях Вам разрешено продолжить движение на показанном перекрёстке?","a":["Только прямо.","Прямо или на разворот.","Прямо, направо или на разворот.","Прямо, налево или на разворот.","Прямо, направо, налево или на разворот."],"c":1,"e":"<p>На показанном перекрёстке разрешёнными направлениями считаются движение <strong>на разворот</strong> (так как разворот не запрещён) и движение <strong>в прямом направлении</strong>.</p>","image":"assets/adrive-questions/q200702161.webp"},{"id":200702301,"themeId":2,"group":2007023,"chapter":82,"chapters":[82],"q":"Разрешается ли водителю легкового автомобиля поставить автомобиль на стоянку слева от дороги в показанной ситуации?","a":["Да, разрешается.","Нет, запрещается."],"c":1,"e":"<p>В показанной ситуации сочетание дорожных знаков 5.15 «Место стоянки» , 7.4.1 «Вид транспортного средства» и 7.3.2 «Направление действия» информирует водителей о том, что место для стоянки транспортных средств, расположенное слева от дороги, предназначено для грузовых автомобилей (в том числе и с прицепом) с технически допустимой общей массой более 3.5 т.</p> <p>Поэтому водителю легкового автомобиля поставить автомобиль на стоянку слева от дороги запрещено.</p>","image":"assets/adrive-questions/q200702301.webp"},{"id":200702302,"themeId":2,"group":2007023,"chapter":82,"chapters":[82],"q":"Разрешается ли водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны поставить автомобиль на стоянку слева от дороги в показанной ситуации?","a":["Да, разрешается.","Нет, запрещается."],"c":1,"e":"<p>В показанной ситуации сочетание дорожных знаков 5.15 «Место стоянки» , 7.4.1 «Вид транспортного средства» и 7.3.2 «Направление действия» информирует водителей о том, что место для стоянки транспортных средств, расположенное слева от дороги, предназначено для грузовых автомобилей (в том числе и с прицепом) с технически допустимой общей массой более 3.5 т.</p> <p>Поэтому водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны поставить автомобиль на стоянку слева от дороги запрещено.</p>","image":"assets/adrive-questions/q200702302.webp"},{"id":200702401,"themeId":2,"group":2007024,"chapter":82,"chapters":[82],"q":"Разрешается ли водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны поставить автомобиль на стоянку слева от дороги в показанной ситуации?","a":["Да, разрешается.","Нет, запрещается."],"c":0,"e":"<p>В показанной ситуации сочетание дорожных знаков «5.15 Место стоянки» , «7.4.3 Вид транспортного средства» и «7.3.2 Направление действия» информирует водителей о том, что место для стоянки транспортных средств, расположенное слева от дороги, предназначено для мотоциклов, легковых и грузовых автомобилей с технически допустимой общей массой до 3.5 т.</p> <p>Поэтому водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны поставить автомобиль на стоянку слева от дороги разрешено.</p>","image":"assets/adrive-questions/q200702401.webp"},{"id":200702432,"themeId":2,"group":2007024,"chapter":82,"chapters":[82],"q":"Разрешается ли водителю поставить мотоцикл  на стоянку слева от дороги в показанной ситуации?","a":["Да, разрешается.","Нет, запрещается."],"c":0,"e":"<p>Сочетание дорожных знаков 5.15 «Место стоянки» , 7.4.3 «Вид транспортного средства» и 7.3.2 «Направление действия» информирует водителей о том, что место для стоянки транспортных средств, расположенное слева от дороги, предназначено для мотоциклов, легковых и грузовых автомобилей с технически допустимой общей массой до 3.5 т.</p> <p>Поэтому водителю поставить мотоцикл на стоянку слева от дороги разрешено.</p>","image":"assets/adrive-questions/q200702432.webp"},{"id":200702441,"themeId":2,"group":2007024,"chapter":82,"chapters":[82],"q":"Нарушил ли Правила дорожного движения водитель, поставив на стоянку свой автомобиль с прицепом, в показанном месте?","a":["Да, нарушил.","Нет, не нарушил."],"c":0,"e":"<p>Показанное место стоянки предназначено для легковых автомобилей (без прицепа), мотоциклов, а также грузовых автомобилей с технически допустимой общей массой до 3.5 тонны включительно.</p>","image":"assets/adrive-questions/q200702441.webp"},{"id":200702461,"themeId":2,"group":2007024,"chapter":82,"chapters":[82],"q":"Каким транспортным средствам из перечисленных разрешена стоянка на площадке, обозначенной показанными дорожными знаками?","a":["Только легковым автомобилям (без прицепа) и мотоциклам.","Только легковым автомобилям (в том числе с прицепом).","Только легковым автомобилям (без прицепа) и грузовым автомобилям с технически допустимой общей массой до 3.5 тонны включительно.","Легковым автомобилям (без прицепа), мотоциклам, а также грузовым автомобилям с технически допустимой общей массой до 3.5 тонны включительно."],"c":3,"e":"<p>Показанная площадка обозначена табличкой «7.4.3 Вид транспортного средства», а это значит, что на ней могут совершить стоянку легковые автомобили (без прицепа), мотоциклы, а также грузовые автомобили с технически допустимой общей массой до 3.5 тонны включительно.</p>","image":"assets/adrive-questions/q200702461.webp"},{"id":200702501,"themeId":2,"group":2007025,"chapter":82,"chapters":[82],"q":"Какие из показанных дорожных знаков дополнительной информации называются «Вид транспортного средства»?","a":["Только дорожный знак 1.","Дорожные знаки 1 и 5.","Дорожные знаки 1, 4 и 5.","Дорожные знаки 1, 2 и 5.","Дорожные знаки 1, 3 и 5."],"c":1,"e":"<p>На рисунке под номерами 1 и 5 изображены дорожные знаки дополнительной информации 7.4.3, 7.4.7 «Вид транспортного средства» , которые указывают вид транспортного средства, на который распространяется действие дорожного знака, установленного с ними.</p>","image":"assets/adrive-questions/q200702501.webp"},{"id":200702502,"themeId":2,"group":2007025,"chapter":82,"chapters":[82],"q":"Разрешено ли водителю в показанной ситуации поставить легковой автомобиль на стоянку, расположенную справа от дороги?","a":["Да, разрешено.","Нет, запрещено.","Разрешено только для осмотра автомобиля."],"c":1,"e":"<p>В показанной ситуации сочетание дорожных знаков 5.15 «Место стоянки» , 7.4.1 «Вид транспортного средства» и 7.3.1 «Направление действия» информирует водителей о том, что место для стоянки транспортных средств, расположенное справа от дороги, предназначено для грузовых автомобилей (в том числе и с прицепом) с технически допустимой общей массой более 3.5 т.</p> <p>Поэтому водителю поставить легковой автомобиль на стоянку, расположенную справа от дороги, запрещено.</p>","image":"assets/adrive-questions/q200702502.webp"},{"id":200702541,"themeId":2,"group":2007025,"chapter":82,"chapters":[82],"q":"Разрешается ли Вам, управляя автомобилем, приводимым в движение двигателем внутреннего сгорания, остановиться справа за дорожным знаком для высадки пассажира?","a":["Да, разрешается.","Да, только если не будет создано препятствия для зарядки электромобилей.","Нет, не разрешается."],"c":2,"e":"<p>На показанном участке дороги остановка запрещена всем транспортным средствам, кроме электромобилей.</p>","image":"assets/adrive-questions/q200702541.webp"},{"id":200702602,"themeId":2,"group":2007026,"chapter":82,"chapters":[82],"q":"Нарушит ли Правила дорожного движения водитель грузового автомобиля с технически допустимой общей массой не более 3.5 тонны, двигаясь при таком сочетании дорожных знаков со скоростью 110 км/ч?","a":["Да, нарушит.","Нет, не нарушит."],"c":1,"e":"<p>Показанное на рисунке сочетание дорожных знаков:</p> <ul><li>3.24.1 «Ограничение максимальной скорости» и 7.4.3 «Вид транспортного средства» — действует на мотоциклы, легковые автомобили и грузовые с технически допустимой общей массой не более 3.5 тонны;</li> <li>3.24.1 «Ограничение максимальной скорости» и 7.4.1 «Вид транспортного средства» — действует на грузовые автомобили с технически допустимой общей массой более 3.5 тонны).</li></ul> <p>Поэтому водитель грузового автомобиля с технически допустимой общей массой не более 3.5 тонны, двигаясь при таком сочетании дорожных знаков со скоростью 110 км/ч, не нарушит Правила дорожного движения.</p>","image":"assets/adrive-questions/q200702602.webp"},{"id":200702631,"themeId":2,"group":2007026,"chapter":82,"chapters":[82],"q":"На какие транспортные средства из перечисленных действует показанное на рисунке сочетание дорожных знаков?","a":["Только на легковые автомобили.","Только на легковые автомобили и мотоциклы.","На легковые автомобили, мотоциклы и автобусы с технически допустимой общей массой не более 5 тонн.","На мотоциклы, легковые автомобили и грузовые с технически допустимой общей массой не более 3.5 тонны."],"c":3,"e":"<p>Показанная табличка с изображением легкового автомобиля 7.4.3 «Вид транспортного средства» указывает, что ограничение скорости действует на легковые автомобили (без прицепа), мотоциклы, а также на грузовые автомобили с технически допустимой общей массой до 3.5 тонны включительно.</p>","image":"assets/adrive-questions/q200702631.webp"},{"id":200702701,"themeId":2,"group":2007027,"chapter":82,"chapters":[82],"q":"При каких условиях из перечисленных ниже разрешено движение механическим транспортным средствам по дороге, обозначенной такими дорожными знаками?","a":["Только по выходным дням.","По субботним, воскресным и праздничным дням.","При наличии искусственного освещения в тёмное время суток.","По рабочим дням (кроме переноса рабочих дней на субботние дни)."],"c":3,"e":"<p>Показанное на рисунке сочетание дорожных знаков 3.3 «Движение механических транспортных средств запрещено» и 7.5.1 «Субботние, воскресные и праздничные дни» разрешает движение механическим транспортным средствам по дороге, обозначенной такими знаками, по рабочим дням (кроме переноса рабочих дней на выходные дни, утверждённого Советом Министров Республики Беларусь).</p>","image":"assets/adrive-questions/q200702701.webp"},{"id":200702702,"themeId":2,"group":2007027,"chapter":82,"chapters":[82],"q":"Разрешено ли водителю легкового автомобиля остановиться в зоне действия показанных дорожных знаков?","a":["Разрешено только по субботним, воскресным и праздничным дням.","Разрешено только по рабочим дням недели (кроме переноса рабочих дней на субботние дни).","Запрещено в любой день недели."],"c":1,"e":"<p>Показанное на рисунке сочетание дорожных знаков 3.27 «Остановка запрещена» и 7.5.1 «Субботние, воскресные и праздничные дни» разрешает водителю легкового автомобиля остановиться в зоне действия знаков только по рабочим дням недели (кроме переноса рабочих дней на выходные дни, утверждённого Советом Министров Республики Беларусь).</p>","image":"assets/adrive-questions/q200702702.webp"},{"id":200702801,"themeId":2,"group":2007028,"chapter":82,"chapters":[82],"q":"При каких условиях из перечисленных ниже разрешено движение механическим транспортным средствам по дороге, обозначенной такими дорожными знаками?","a":["По рабочим дням.","Только по выходным дням.","По субботним, воскресным и праздничным дням.","При наличии искусственного освещения в тёмное время суток."],"c":1,"e":"<p>Показанное на рисунке сочетание дорожных знаков 3.3 «Движение механических транспортных средств запрещено» и 7.5.2 «Рабочие дни» разрешает движение механическим транспортным средствам по дороге, обозначенной такими знаками, только по выходным дням.</p> <p>Выходной день может быть объявлен рабочим днём и наоборот в соответствии с Постановлением Совета Министров Республики Беларусь о переносе рабочих дней.</p>","image":"assets/adrive-questions/q200702801.webp"},{"id":200702802,"themeId":2,"group":2007028,"chapter":82,"chapters":[82],"q":"Разрешено ли водителю легкового автомобиля проехать показанный на рисунке перекрёсток в прямом направлении 1 мая в среду?","a":["Да, разрешено.","Нет, запрещено."],"c":0,"e":"<p>В показанной ситуации сочетание дорожных знаков 3.2 «Движение запрещено» и 7.5.2 «Рабочие дни» разрешает движение транспортным средствам по дороге, обозначенной такими знаками, только по выходным дням.</p> <p>Поэтому водителю легкового автомобиля проехать перекрёсток в прямом направлении 1 мая в среду разрешено.</p>","image":"assets/adrive-questions/q200702802.webp"},{"id":200702901,"themeId":2,"group":2007029,"chapter":82,"chapters":[82],"q":"Укажите наиболее правильное значение показанного на рисунке сочетания дорожных знаков:","a":["Въезд запрещён по рабочим дням недели.","Движение запрещено по рабочим дням недели.","Движение транспортных средств запрещено, кроме рабочих дней недели.","Движение механических транспортных средств запрещено по рабочим дням недели."],"c":1,"e":"<p>В показанной ситуации сочетание дорожных знаков 3.2 «Движение запрещено» и 7.5.2 «Рабочие дни» запрещает движение транспортным средствам по дороге, обозначенной такими знаками, по рабочим дням.</p>","image":"assets/adrive-questions/q200702901.webp"},{"id":200702902,"themeId":2,"group":2007029,"chapter":82,"chapters":[82],"q":"Показанное на рисунке сочетание дорожных знаков запрещает:","a":["Движение механических транспортных средств по рабочим дням недели.","Движение немеханических транспортных средств по рабочим дням недели.","Запрещает всё перечисленное."],"c":2,"e":"<p>На рисунке сочетание дорожных знаков 3.2 «Движение запрещено» и 7.5.2 «Рабочие дни» запрещает движение всем транспортным средствам по дороге, обозначенной такими знаками, по рабочим дням.</p>","image":"assets/adrive-questions/q200702902.webp"},{"id":200703001,"themeId":2,"group":2007030,"chapter":82,"chapters":[82],"q":"В каких направлениях Вам разрешено продолжить движение при управлении легковым автомобилем в показанной ситуации в воскресенье в 8 часов?","a":["Только прямо.","Прямо и направо.","Прямо, налево и на разворот.","Прямо, направо и на разворот.","Во всех направлениях."],"c":1,"e":"<p>В показанной ситуации сочетание дорожных знаков 4.1.4 «Движение прямо и направо» и 7.5.4 «Время действия» указывает время суток, в течение которого действует первый знак.</p> <p>Поэтому водителю разрешено продолжить движение в воскресенье в 8 часов только прямо и направо.</p>","image":"assets/adrive-questions/q200703001.webp"},{"id":200703002,"themeId":2,"group":2007030,"chapter":82,"chapters":[82],"q":"В каких направлениях разрешено продолжить движение водителю зелёного легкового автомобиля в воскресенье в 6 часов 30 минут?","a":["Только прямо.","Прямо и направо.","Прямо, налево и на разворот.","Прямо, направо и на разворот.","Во всех направлениях."],"c":4,"e":"<p>В показанной ситуации сочетание дорожных знаков 4.1.4 «Движение прямо и направо» и 7.5.4 «Время действия» указывает время суток, в течение которого действует первый знак.</p> <p>Поэтому водителю разрешено продолжить движение в воскресенье в 6 часов 30 минут во всех направлениях.</p>","image":"assets/adrive-questions/q200703002.webp"},{"id":200703101,"themeId":2,"group":2007031,"chapter":82,"chapters":[82],"q":"В каких направлениях разрешено продолжить движение водителю синего легкового автомобиля в субботу в 8 часов 30 минут?","a":["Только прямо.","Прямо и на разворот.","Прямо, налево и на разворот.","Прямо, направо и на разворот.","Во всех направлениях."],"c":4,"e":"<p>В показанной ситуации сочетание дорожных знаков 3.18.2 «Поворот налево запрещён» и 7.5.4 «Время действия» указывает время суток, в течение которого действует первый знак.</p> <p>Поэтому водителю разрешено продолжить движение в субботу в 8 часов 30 минут во всех направлениях.</p>","image":"assets/adrive-questions/q200703101.webp"},{"id":200703102,"themeId":2,"group":2007031,"chapter":82,"chapters":[82],"q":"В каких направлениях разрешено продолжить движение водителю синего легкового автомобиля в субботу в 18 часов 30 минут?","a":["Только прямо.","Прямо и на разворот.","Прямо, налево и на разворот.","Прямо, направо и на разворот.","Во всех направлениях."],"c":3,"e":"<p>В показанной ситуации сочетание дорожных знаков 3.18.2 «Поворот налево запрещён» (не запрещает разворот) и 7.5.4 «Время действия» указывает время суток, в течение которого действует первый знак.</p> <p>Поэтому водителю разрешено продолжить движение в субботу в 18 часов 30 минут прямо, направо и на разворот.</p>","image":"assets/adrive-questions/q200703102.webp"},{"id":200703201,"themeId":2,"group":2007032,"chapter":82,"chapters":[82],"q":"В каком из перечисленных случаев водитель красного автомобиля не нарушит Правила дорожного движения, совершив остановку в показанном на рисунке месте?","a":["Остановится во вторник 10 мая в 8 часов.","Остановится в субботу 30 апреля в 10 часов.","Остановится в воскресенье 1 мая в 16 часов.","Остановится в понедельник 9 мая в 14 часов.","Не нарушит во всех перечисленных случаях."],"c":0,"e":"<p>В показанной ситуации сочетание дорожных знаков 3.27 «Остановка запрещена» и 7.5.5 «Время действия» указывает, что остановка и стоянка запрещены в выходные и праздничные дни с 8:30 по 17:30.</p> <p>Поэтому водитель красного автомобиля не нарушит Правила дорожного движения, совершив остановку в показанном месте во вторник 10 мая в 8 часов.</p>","image":"assets/adrive-questions/q200703201.webp"},{"id":200703202,"themeId":2,"group":2007032,"chapter":82,"chapters":[82],"q":"В каком из перечисленных случаев водитель красного автомобиля нарушит Правила дорожного движения, совершив остановку в показанном на рисунке месте?","a":["Остановится во вторник 10 мая в 16 часов.","Остановится в субботу 30 апреля в 7 часов.","Остановится в воскресенье 1 мая в 14 часов.","Остановится в понедельник 9 мая в 18 часов.","Не нарушит во всех перечисленных случаях."],"c":2,"e":"<p>В показанной ситуации сочетание дорожных знаков 3.27 «Остановка запрещена» и 7.5.5 «Время действия» указывает, что остановка и стоянка запрещены в выходные и праздничные дни с 8:30 по 17:30.</p> <p>Поэтому водитель красного автомобиля нарушит Правила дорожного движения, совершив остановку в показанном месте в воскресенье 1 мая в 14 часов.</p>","image":"assets/adrive-questions/q200703202.webp"},{"id":200703301,"themeId":2,"group":2007033,"chapter":82,"chapters":[82],"q":"Разрешено ли водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны за дорожным знаком совершить остановку или стоянку в показанной ситуации?","a":["Разрешено остановиться показанным на табличке способом.","Разрешено остановиться у края проезжей части параллельно ему.","Разрешено остановиться и поставить автомобиль на стоянку у края проезжей части параллельно ему.","Разрешено остановиться и поставить автомобиль на стоянку только показанным на табличке способом.","Запрещено всё перечисленное."],"c":4,"e":"<p>В показанной ситуации сочетание дорожных знаков «5.15 Место стоянки» и «7.6.2 Способ постановки транспортного средства на стоянку» указывает способ постановки только легковых автомобилей, мопедов и мотоциклов на стоянку.</p> <p>Остановка и стоянка других транспортных средств запрещаются.</p> <p>Поэтому водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны запрещается остановка и стоянка в зоне действия показанных дорожных знаков.</p>","image":"assets/adrive-questions/q200703301.webp"},{"id":200703302,"themeId":2,"group":2007033,"chapter":82,"chapters":[82],"q":"Разрешено ли водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны за дорожным знаком совершить остановку или стоянку в показанной ситуации?","a":["Разрешено остановиться показанным на табличке способом.","Разрешено остановиться у края проезжей части параллельно ему.","Разрешено остановиться и поставить автомобиль на стоянку у края проезжей части параллельно ему.","Разрешено остановиться и поставить автомобиль на стоянку только показанным на табличке способом.","Запрещено всё перечисленное."],"c":4,"e":"<p>В показанной ситуации сочетание дорожных знаков «7.4.3 Вид транспортного средства» и «7.6.3 Способ постановки транспортного средства на стоянку» указывает способ постановки на стоянку только легковым автомобилям и мотоциклам.</p> <p>Остановка и стоянка других транспортных средств запрещаются.</p> <p>Поэтому водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны запрещается остановка и стоянка в зоне действия показанных дорожных знаков.</p>","image":"assets/adrive-questions/q200703302.webp"},{"id":200703431,"themeId":2,"group":2007034,"chapter":82,"chapters":[82],"q":"Каким транспортным средствам разрешена стоянка у края проезжей части дороги на участке, расположенном за таким сочетанием дорожных знаков?","a":["Только легковым автомобилям.","Только легковым автомобилям и мотоциклам.","Мотоциклам, легковым автомобилям и грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны.","Мотоциклам, легковым автомобилям, грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны и автобусам."],"c":2,"e":"<p>Показанный на рисунке дорожный знак 7.4.3 «Вид транспортного средства» разрешает стоянку легковым автомобилям (без прицепа), мотоциклам, а также грузовым автомобилям с технически допустимой общей массой до 3.5 тонны включительно.</p>","image":"assets/adrive-questions/q200703431.webp"},{"id":200703432,"themeId":2,"group":2007034,"chapter":82,"chapters":[82],"q":"Каким транспортным средствам разрешена стоянка показанным на рисунке способом на участке, расположенном за таким сочетанием дорожных знаков?","a":["Только легковым автомобилям.","Только легковым автомобилям и мотоциклам.","Мотоциклам, легковым автомобилям и грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны.","Всем перечисленным."],"c":1,"e":"<p>Показанное на рисунке сочетание дорожных знаков «5.15 Место стоянки» и «7.4.3 Вид транспортного средства» разрешает стоянку только мотоциклам, легковым автомобилям и грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны.</p> <p>Однако, дорожный знак «7.6.5 Способ постановки транспортного средства на стоянку» уточняет, что грузовым автомобилям остановка и стоянка запрещены.</p> <p>Следовательно, стоянка указанным способом разрешена только мотоциклам и легковым автомобилям.</p>","image":"assets/adrive-questions/q200703432.webp"},{"id":200703441,"themeId":2,"group":2007034,"chapter":82,"chapters":[82],"q":"Водители каких транспортных средств не нарушили Правила дорожного движения, поставив их на стоянку показанным способом?","a":["Только водитель легкового автомобиля.","Водители легкового автомобиля и мотоцикла.","Водители легкового автомобиля, мотоцикла и грузового автомобиля с технически допустимой общей массой не более 3.5 тонны."],"c":1,"e":"<p>Табличка «7.6.3 Способ постановки транспортного средства на стоянку» , установленная совместно со знаком «5.15 Место стоянки» , не только показывает способ постановки транспортного средства на стоянку, но и запрещает остановку и стоянку всех транспортных средств, кроме мопедов, мотоциклов и легковых автомобилей.</p>","image":"assets/adrive-questions/q200703441.webp"},{"id":200703501,"themeId":2,"group":2007035,"chapter":82,"chapters":[82],"q":"Разрешено ли мотоциклисту поставить мотоцикл на стоянку в зоне действия показанного на рисунке дорожного знака?","a":["Да, разрешено.","Нет, запрещено."],"c":0,"e":"<p>В показанной ситуации сочетание дорожных знаков «5.15 Место стоянки» и «7.6.2 Способ постановки транспортного средства на стоянку» разрешает мотоциклисту поставить мотоцикл на стоянку в зоне действия знака.</p> <p>Учитывая, что показанный мотцикл относится к одноколейным транспортным средствам, его разрешено поставить либо у края проезжей части дороги, либо у края тротуара.</p>","image":"assets/adrive-questions/q200703501.webp"},{"id":200703502,"themeId":2,"group":2007035,"chapter":82,"chapters":[82],"q":"Разрешено ли водителю поставить легковой автомобиль на стоянку у правого края проезжей части дороги параллельно ему, если показанным на табличке способом поставить транспортное средство невозможно из-за конструктивных особенностей автомобиля?","a":["Да, разрешено.","Нет, запрещено."],"c":1,"e":"<p>В показанной ситуации сочетание дорожных знаков «5.15 Место стоянки» и «7.6.2 Способ постановки транспортного средства на стоянку» запрещает водителю поставить легковой автомобиль на стоянку у правого края проезжей части дороги параллельно ему.</p> <p>Если показанным на табличке способом поставить транспортное средство невозможно из-за конструктивных особенностей автомобиля, следует найти иное место для стоянки.</p>","image":"assets/adrive-questions/q200703502.webp"},{"id":200703601,"themeId":2,"group":2007036,"chapter":82,"chapters":[82],"q":"Разрешено ли водителю в каком-либо из перечисленных случаев частично заехать на тротуар при постановке транспортного средства на стоянку в зоне действия показанного на рисунке сочетания дорожных знаков?","a":["Разрешено в случае постановки на стоянку легкового автомобиля или мотоцикла.","Разрешено в случае если транспортное средство не создаст препятствие для движения пешеходов и велосипедистов.","Разрешено в случае если транспортное средство из-за своих габаритов может создать препятствие для движения других транспортных средств.","Запрещено во всех перечисленных случаях."],"c":3,"e":"<p>На рисунке сочетание дорожных знаков 5.15 «Место стоянки» и 7.6.1 «Способ постановки транспортного средства на стоянку» указывает, что все транспортные средства должны быть поставлены на стоянку только показанным способом.</p>","image":"assets/adrive-questions/q200703601.webp"},{"id":200703602,"themeId":2,"group":2007036,"chapter":82,"chapters":[82],"q":"Нарушил ли водитель синего автомобиля Правила дорожного движения, поставив на стоянку автомобиль показанным на рисунке способом с целью улучшения обзорности при последующем выезде с места стоянки?","a":["Да, нарушил.","Нет, не нарушил."],"c":0,"e":"<p>В показанной ситуации сочетание дорожных знаков «5.15 Место стоянки» и «7.6.5 Способ постановки транспортного средства на стоянку» запрещает водителю синего автомобиля поставить автомобиль на стоянку показанным способом.</p>","image":"assets/adrive-questions/q200703602.webp"},{"id":200703701,"themeId":2,"group":2007037,"chapter":82,"chapters":[82],"q":"Какие из показанных на рисунке табличек указывают способы постановки на стоянку только легковых автомобилей, мопедов и мотоциклов?","a":["Только табличка 1.","Таблички 1 и 3.","Таблички 2, 4 и 5.","Таблички 2, 3, 4 и 5.","Все показанные на рисунке таблички."],"c":2,"e":"<p>На рисунке под номерами 2, 4 и 5 изображены таблички 7.6.2, 7.6.5, 7.6.7 «Способ постановки транспортного средства на стоянку» , которые указывают способы постановки на стоянку только легковых автомобилей, мопедов и мотоциклов.</p>","image":"assets/adrive-questions/q200703701.webp"},{"id":200703702,"themeId":2,"group":2007037,"chapter":82,"chapters":[82],"q":"Какие из показанных на рисунке табличек указывают способы постановки на стоянку легкового автомобиля?","a":["Только табличка 2.","Только табличка 3.","Таблички 1 и 3.","Таблички 2 и 3.","Все показанные."],"c":3,"e":"<p>На рисунке под номерами 2 и 3 изображены таблички 7.6.14, 7.6.11 «Способ постановки транспортного средства на стоянку» , которые указывают способы постановки на стоянку легкового автомобиля.</p>","image":"assets/adrive-questions/q200703702.webp"},{"id":200703762,"themeId":2,"group":2007037,"chapter":82,"chapters":[82],"q":"Каким транспортным средствам из перечисленных разрешена стоянка способом, показанным на табличке?","a":["Только легковым автомобилям.","Только легковым автомобилям, мопедам и мотоциклам.","Только легковым автомобилям, мотоциклам и грузовым автомобилям с технически допустимой общей массой не более 3.5 тонны.","Всем перечисленным транспортным средствам."],"c":1,"e":"<p>Табличка «7.6.3 Способ постановки транспортного средства на стоянку» указывает, как должны быть поставлены легковые автомобили, мопеды и мотоциклы. Остановка и стоянка других транспортных средств запрещаются.</p>","image":"assets/adrive-questions/q200703762.webp"},{"id":200703801,"themeId":2,"group":2007038,"chapter":82,"chapters":[82],"q":"Кто из водителей в показанной ситуации неправильно поставил автомобиль на стоянку?","a":["Только водитель чёрного автомобиля.","Водители чёрного и красного автомобилей.","Водители всех автомобилей.","Водители всех автомобилей не нарушили Правила дорожного движения при наличии свободных мест на стоянке."],"c":1,"e":"<p>В показанной ситуации сочетание дорожных знаков «5.15 Место стоянки» и «7.6.5 Способ постановки транспортного средства на стоянку» запрещает водителям чёрного и красного автомобилей ставить автомобили на стоянку таким образом.</p>","image":"assets/adrive-questions/q200703801.webp"},{"id":200703802,"themeId":2,"group":2007038,"chapter":82,"chapters":[82],"q":"Кто из водителей в показанной ситуации неправильно поставил автомобиль на стоянку?","a":["Только водитель грузового автомобиля.","Только водитель красного легкового автомобиля.","Водители грузового и красного легкового автомобилей.","Водители всех автомобилей.","Водители всех автомобилей не нарушили Правила дорожного движения при выполнении требований горизонтальной дорожной разметки, нанесённой на стоянке."],"c":2,"e":"<p>В показанной ситуации сочетание дорожных знаков «5.15 Место стоянки» и «7.6.5 Способ постановки транспортного средства на стоянку» запрещает водителям грузового и красного легкового автомобилей ставить автомобили на стоянку таким образом.</p>","image":"assets/adrive-questions/q200703802.webp"},{"id":200703901,"themeId":2,"group":2007039,"chapter":82,"chapters":[82],"q":"О чём информирует табличка, показанная на рисунке, при её применении с дорожным знаком «Опасные повороты»?","a":["О количестве опасных поворотов, расположенных один за другим.","О минимальной безопасной дистанции на обозначенном участке дороги.","О количестве попутных полос движения на обозначенном участке дороги.","О количестве дорожных знаков «Опасные повороты», расположенных на обозначенном участке дороги."],"c":0,"e":"<p>На рисунке изображено сочетание дорожных знаков 1.12.1 «Опасные повороты» и 7.7 «Количество опасных поворотов» , которые информируют об участке дороги с тремя опасными поворотами.</p>","image":"assets/adrive-questions/q200703901.webp"},{"id":200703902,"themeId":2,"group":2007039,"chapter":82,"chapters":[82],"q":"С каким дорожным знаком применяется табличка 7.7 «Количество опасных поворотов»?","a":["Совместно со знаком «Скользкая дорога».","Совместно со знаком «Опасный поворот».","Совместно со знаком «Опасные повороты».","Совместно со знаком «Направление поворота»."],"c":2,"e":"<p>На рисунке изображена табличка 7.7 «Количество опасных поворотов» , которая применяется совместно с дорожными знаками 1.12.1, 1.12.2 «Опасные повороты» .</p>","image":"assets/adrive-questions/q200703902.webp"},{"id":200704001,"themeId":2,"group":2007040,"chapter":82,"chapters":[82],"q":"Разрешено ли в каком-либо из перечисленных случаев водителю грузового автомобиля с фактической массой не более 3.5 тонны поставить автомобиль на парковку, расположенную слева от дороги?","a":["Разрешено при наличии свободных мест на парковке.","Разрешено в случае разрешения со стороны администрации парковки.","Разрешено в любом случае.","Запрещено в любом случае."],"c":3,"e":"<p>В показанной ситуации сочетание дорожных знаков 5.15 «Место стоянки» , 7.11 «Ограничение максимальной массы» и 7.3.2 «Направление действия» информирует водителей о том, что место для стоянки транспортных средств, расположенное слева от дороги, предназначено для транспортных средств с фактической массой более 15 тонн.</p> <p>Поэтому водителю грузового автомобиля с технически допустимой общей массой не более 3.5 тонны запрещено поставить автомобиль на парковку, расположенную слева от дороги.</p>","image":"assets/adrive-questions/q200704001.webp"},{"id":200704002,"themeId":2,"group":2007040,"chapter":82,"chapters":[82],"q":"Разрешено ли в каком-либо из перечисленных случаев водителю легкового автомобиля поставить автомобиль на парковку, расположенную слева от дороги?","a":["Разрешено при наличии свободных мест на парковке.","Разрешено в случае разрешения со стороны администрации парковки.","Разрешено при нахождении автомобиля вне парковочных мест, предусмотренных для большегрузных автомобилей, если не будет создано помех для их заезда (выезда).","Разрешено в любом случае.","Запрещено в любом случае."],"c":4,"e":"<p>В показанной ситуации сочетание дорожных знаков 5.15 «Место стоянки» , 7.11 «Ограничение максимальной массы» и 7.3.2 «Направление действия» информирует водителей о том, что место для стоянки транспортных средств, расположенное слева от дороги, предназначена для транспортных средств с фактической массой более 15 тонн.</p> <p>Поэтому водителю легкового автомобиля запрещено поставить автомобиль на парковку, расположенную слева от дороги.</p>","image":"assets/adrive-questions/q200704002.webp"},{"id":200704101,"themeId":2,"group":2007041,"chapter":82,"chapters":[82],"q":"Перед какими опасными участками дорог устанавливается такое сочетание дорожных знаков?","a":["Перед участками, на которых проводятся работы по установке дорожных знаков.","Перед участками, на которых проводятся работы по нанесению дорожной разметки.","Перед участками, на которых проводятся работы по ямочному ремонту дорожного покрытия.","Перед участками, на которых ввиду проведения дорожных работ уменьшено количество полос движения."],"c":1,"e":"<p>На рисунке изображено сочетание дорожных знаков 1.23 «Дорожные работы» и 7.12 «Нанесение разметки» , которые устанавливаются перед участками, на которых проводятся работы по нанесению дорожной разметки.</p>","image":"assets/adrive-questions/q200704101.webp"},{"id":200704102,"themeId":2,"group":2007041,"chapter":82,"chapters":[82],"q":"О чём предупреждает водителя показанное на рисунке сочетание дорожных знаков?","a":["О проведении дорожных работ по ремонту обочины.","О проведении дорожных работ по нанесению дорожной разметки.","О проведении дорожных работ по улучшению поверхности дорожного покрытия."],"c":1,"e":"<p>В показанной ситуации сочетание дорожных знаков 1.23 «Дорожные работы» и 7.12 «Нанесение разметки» информирует водителя о проведении дорожных работ по нанесению дорожной разметки.</p>","image":"assets/adrive-questions/q200704102.webp"},{"id":200704201,"themeId":2,"group":2007042,"chapter":82,"chapters":[82],"q":"Разрешено ли мотоциклисту двигаться по полосе движения, обозначенной таким сочетанием дорожных знаков?","a":["Разрешено.","Запрещено.","Разрешено только при управлении мотоциклом с боковым прицепом."],"c":0,"e":"<p>На рисунке изображено сочетание дорожных знаков 4.4 «Движение легковых автомобилей» и 7.14 «Полоса движения» , которое разрешает мотоциклисту двигаться по указанной полосе.</p>","image":"assets/adrive-questions/q200704201.webp"},{"id":200704202,"themeId":2,"group":2007042,"chapter":82,"chapters":[82],"q":"По какой полосе движения в населённом пункте разрешено двигаться легковому автомобилю при установке над проезжей частью дороги сочетания дорожных знаков, показанного на рисунке?","a":["Только по крайней левой полосе.","Только по крайней правой полосе.","По любой из попутных полос движения."],"c":2,"e":"<p>В показанной ситуации сочетание дорожных знаков 4.4 «Движение легковых автомобилей» и 7.14 «Полоса движения» разрешает двигаться легковому автомобилю по любой из попутных полос движения.</p>","image":"assets/adrive-questions/q200704202.webp"},{"id":200704301,"themeId":2,"group":2007043,"chapter":82,"chapters":[82],"q":"По какой полосе движения в населённом пункте разрешено двигаться грузовому автомобилю с технически допустимой общей массой не более 3.5 тонны при установке над проезжей частью дороги сочетания дорожных знаков, показанного на рисунке?","a":["Только по крайней левой полосе.","Только по крайней правой полосе.","По любой из попутных полос движения."],"c":1,"e":"<p>В показанной ситуации сочетание дорожных знаков 4.4 «Движение легковых автомобилей» и 7.14 «Полоса движения» запрещает грузовым автомобилям двигаться по полосе, над которой установлены данные знаки.</p> <p>Поэтому двигаться грузовому автомобилю с технически допустимой общей массой не более 3.5 тонны разрешено только по крайней правой полосе.</p>","image":"assets/adrive-questions/q200704301.webp"},{"id":200704302,"themeId":2,"group":2007043,"chapter":82,"chapters":[82],"q":"Разрешено ли в каком-либо из нижеперечисленных случаев осуществлять движение по полосе, обозначенной таким сочетанием дорожных знаков?","a":["Разрешено при выполнении обгона, если полоса встречная.","Разрешено при выполнении опережения, если полоса попутная.","Разрешено в обоих случаях.","Запрещено в обоих случаях."],"c":3,"e":"<p>На рисунке изображено сочетание дорожных знаков 3.1 «Въезд запрещён» и 7.14 «Полоса движения» , которое запрещает движение по полосе, над которой установлены данные знаки.</p>","image":"assets/adrive-questions/q200704302.webp"},{"id":200704401,"themeId":2,"group":2007044,"chapter":82,"chapters":[82],"q":"Разрешено ли водителю легкового автомобиля обогнать грузовой автомобиль, двигающийся со скоростью 35 км/ч, в показанной ситуации?","a":["Да, разрешено.","Нет, запрещено."],"c":1,"e":"<p>В показанной ситуации сочетание дорожных знаков 3.20.1 «Обгон запрещён» и 7.16 «Влажное покрытие» указывает, что обгон запрещён, когда покрытие влажное.</p> <p>Поэтому водителю легкового автомобиля обогнать грузовой автомобиль, двигающийся со скоростью 35 км/ч, запрещено, так как после проезда поливомоечного автомобиля покрытие дороги влажное.</p>","image":"assets/adrive-questions/q200704401.webp"},{"id":200704402,"themeId":2,"group":2007044,"chapter":82,"chapters":[82],"q":"При каких условиях из перечисленных ниже на показанном участке дороги может быть разрешён обгон?","a":["В конце дождя.","В начале дождя.","В тёмное время суток, если покрытие дороги сухое.","Запрещён во всех перечисленных условиях."],"c":2,"e":"<p>В показанной ситуации сочетание дорожных знаков 3.20.1 «Обгон запрещён» и 7.16 «Влажное покрытие» указывает, что обгон запрещён, когда покрытие влажное.</p> <p>Поэтому при сухом покрытии обгон на данном участке дороги разрешён.</p>","image":"assets/adrive-questions/q200704402.webp"},{"id":200704541,"themeId":2,"group":2007045,"chapter":82,"chapters":[82],"q":"В каком случае водитель не нарушит Правила дорожного движения, если на показанном участке дороги в населённом пункте он будет осуществлять движение со скоростью 70 км/ч?","a":["Двигаясь в светлое время суток.","Двигаясь в тёмное время суток.","Двигаясь с включённым светом фар (дневными ходовыми огнями, габаритными огнями) в любое время суток."],"c":0,"e":"<p>Ограничение скорости («повышающий» знак «3.24.1 Ограничение максимальной скорости» ) на показанном участке дороги действует только в светлое время суток (табличка «7.5.8 Светлое время суток» ).</p>","image":"assets/adrive-questions/q200704541.webp"},{"id":200704542,"themeId":2,"group":2007045,"chapter":82,"chapters":[82],"q":"Разрешается ли Вам поставить свой автомобиль на стоянку у правого края проезжей части дороги за знаком?","a":["Разрешается только на время до захода солнца.","Разрешается только после захода солнца."],"c":0,"e":"<p>У тротуара за знаком «3.28 Стоянка запрещена» стоянка запрещена только в тёмное время суток (табличка «7.5.9 Тёмное время суток» ).</p>","image":"assets/adrive-questions/q200704542.webp"},{"id":200704544,"themeId":2,"group":2007045,"chapter":82,"chapters":[82],"q":"Дорожный знак «Ограничение максимальной скорости» на показанном участке дороги действует:","a":["Только во время снегопада.","Только с 1 декабря по 28(29) февраля включительно.","Только с 1 ноября по 31 марта включительно."],"c":2,"e":"<p>Ограничение скорости на показанном участке дороги действует только в зимний период (с 1 ноября по 31 марта включительно) (табличка «7.5.10 Зимний период» ).</p>","image":"assets/adrive-questions/q200704544.webp"},{"id":200704701,"themeId":2,"group":2007047,"chapter":82,"chapters":[82],"q":"Что означает показанное на рисунке сочетание дорожных знаков?","a":["Остановка запрещена, кроме неисправных автомобилей, которым необходима эвакуация.","Стоянка запрещена, если будет создано препятствие для работы транспортных средств коммунальной службы. В этом случае транспортное средство может быть эвакуировано.","Остановка запрещена, возможна эвакуация (блокировка колёс) транспортного средства при отсутствии водителя в транспортном средстве или в непосредственной близости от него."],"c":2,"e":"<p>Показанное на рисунке сочетание дорожных знаков 3.27 «Остановка запрещена» и 7.20 «Эвакуатор» означает, что остановка запрещена, возможна эвакуация (блокировка колёс) транспортного средства при отсутствии водителя в транспортном средстве или в непосредственной близости от него.</p>","image":"assets/adrive-questions/q200704701.webp"},{"id":200704702,"themeId":2,"group":2007047,"chapter":82,"chapters":[82],"q":"В каком из перечисленных случаев транспортное средство может быть эвакуировано при его нахождении в зоне действия показанных на рисунке дорожных знаков?","a":["При наличии водителя в транспортном средстве или в непосредственной близости от него.","При отсутствии водителя в транспортном средстве или в непосредственной близости от него.","В обоих перечисленных случаях."],"c":1,"e":"<p>В показанной ситуации сочетание дорожных знаков 3.27 «Остановка запрещена» и 7.20 «Эвакуатор» запрещает остановку и стоянку, поэтому при отсутствии водителя в транспортном средстве или в непосредственной близости от него транспортное средство может быть эвакуировано.</p>","image":"assets/adrive-questions/q200704702.webp"},{"id":200704801,"themeId":2,"group":2007048,"chapter":82,"chapters":[82],"q":"Какой из показанных на рисунке дорожных знаков дополнительной информации информирует о возможном изменении коэффициента сцепления по ширине проезжей части дороги?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":2,"e":"<p>На рисунке под номером 3 изображён дорожный знак дополнительной информации 7.21 «Скользкая полоса наката» , который информирует о возможном изменении коэффициента сцепления по ширине проезжей части дороги.</p>","image":"assets/adrive-questions/q200704801.webp"},{"id":200704802,"themeId":2,"group":2007048,"chapter":82,"chapters":[82],"q":"Какой из показанных на рисунке дорожных знаков дополнительной информации информирует о возможном изменении коэффициента сцепления по ширине проезжей части дороги?","a":["Дорожный знак 1.","Дорожный знак 2.","Дорожный знак 3.","Дорожный знак 4.","Дорожный знак 5."],"c":3,"e":"<p>На рисунке под номером 4 изображён дорожный знак дополнительной информации 7.21 «Скользкая полоса наката» , который информирует о возможном изменении коэффициента сцепления по ширине проезжей части дороги.</p>","image":"assets/adrive-questions/q200704802.webp"},{"id":200704901,"themeId":2,"group":2007049,"chapter":82,"chapters":[82],"q":"О чём информирует участников дорожного движения показанное сочетание дорожных знаков?","a":["О наличии экстренной связи на дороге.","О наличии телефонов в местах для отдыха.","О необходимости вызвать скорую помощь пострадавшим при ДТП.","О необходимости сообщить в милицию о происшествиях на дороге."],"c":0,"e":"<p>В показанной ситуации сочетание дорожных знаков 6.6 «Телефон» и 7.23 «Экстренная помощь» информирует участников дорожного движения о наличии экстренной связи на дороге.</p>","image":"assets/adrive-questions/q200704901.webp"},{"id":200704902,"themeId":2,"group":2007049,"chapter":82,"chapters":[82],"q":"О чём информирует участников дорожного движения изображённая на рисунке табличка?","a":["О наличии экстренной связи на дороге.","О дорожно-транспортном происшествии.","О въезде в зону стихийного бедствия или техногенной катастрофы.","О въезде на территорию или объект, принадлежащий Министерству по чрезвычайным ситуациям."],"c":0,"e":"<p>На рисунке изображена табличка 7.23 «Экстренная помощь» , которая информирует участников дорожного движения о наличии экстренной связи на дороге.</p>","image":"assets/adrive-questions/q200704902.webp"},{"id":300200131,"themeId":2,"group":3002001,"chapter":84,"chapters":[84],"q":"В каких местах на проезжей части дороги применяются линии горизонтальной дорожной разметки жёлтого цвета?","a":["В местах, где запрещена стоянка или остановка.","В местах производства ремонтных и других работ на дороге.","В местах размещения остановочных пунктов маршрутных транспортных средств.","Во всех перечисленных местах."],"c":3,"e":"<p>Горизонтальная дорожная разметка жёлтого цвета может применяться во всех перечисленных местах.</p>","image":null},{"id":300200132,"themeId":2,"group":3002001,"chapter":84,"chapters":[84],"q":"Какого цвета используется горизонтальная дорожная разметка в местах производства ремонтных и других работ на дороге в случаях оперативного изменения в организации дорожного движения, связанного с обеспечением его безопасности или проведением специальных мероприятий?","a":["Жёлтого.","Красного.","Зелёного."],"c":0,"e":"<p>В местах производства ремонтных и других работ на дороге в случаях оперативного изменения в организации дорожного движения, связанного с обеспечением его безопасности или проведением специальных мероприятий используется временная горизонтальная дорожная разметка жёлтого цвета.</p>","image":null},{"id":300200141,"themeId":2,"group":3002001,"chapter":84,"chapters":[84],"q":"Каким цветом может дополнительно обозначаться зона парковки для транспортных средств с опознавательным знаком «Инвалид»?","a":["Зелёным цветом.","Синим цветом.","Жёлтым цветом."],"c":1,"e":"<p>Зона парковки для транспортных средств с опознавательным знаком «Инвалид» (обозначенная дорожной разметкой 1.28 или дорожным знаком «7.17 Инвалиды» ) может дополнительно обозначаться синим цветом.</p>","image":null},{"id":300200201,"themeId":2,"group":3002002,"chapter":84,"chapters":[84],"q":"Водитель какого автомобиля не нарушил Правила дорожного движения при постановке на стоянку в указанном месте?","a":["Водитель синего автомобиля.","Водитель красного автомобиля.","Оба водителя не нарушили.","Оба водителя нарушили."],"c":2,"e":"<p>В показанной ситуации сочетание дорожных знаков 5.15 «Место стоянки» и 7.6.4 «Способ постановки транспортного средства на стоянку» указывает, каким способом необходимо поставить ТС на стоянку.</p> <p>Нанесённая разметка 1.1 обозначает границы мест стоянки, в показанном месте её разрешается пересекать.</p> <p>Поэтому оба водителя не нарушили Правила дорожного движения при постановке автомобиля на стоянку в указанном месте.</p>","image":"assets/adrive-questions/q300200201.webp"},{"id":300200202,"themeId":2,"group":3002002,"chapter":84,"chapters":[84],"q":"Водитель какого автомобиля не нарушил Правила дорожного движения при постановке на стоянку в указанном месте?","a":["Водитель синего автомобиля.","Водитель красного автомобиля.","Оба водителя не нарушили.","Оба водителя нарушили."],"c":1,"e":"<p>В показанной ситуации сочетание дорожных знаков 5.15 «Место стоянки» и 7.6.4 «Способ постановки транспортного средства на стоянку» указывает, каким способом необходимо поставить ТС на стоянку.</p> <p>Нанесённая разметка 1.1 обозначает границы мест стоянки, в показанном месте её разрешается пересекать.</p> <p>Поэтому водитель красного автомобиля не нарушил Правила дорожного движения при постановке автомобиля на стоянку в указанном месте.</p>","image":"assets/adrive-questions/q300200202.webp"},{"id":300200203,"themeId":2,"group":3002002,"chapter":84,"chapters":[84],"q":"Разрешается ли в показанной ситуации водителю синего легкового автомобиля использовать направляющий островок для остановки?","a":["Да, разрешается.","Разрешается только для посадки (высадки) пассажиров.","Нет, не разрешается."],"c":2,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.16.2 .<br> Поэтому водителю синего легкового автомобиля использовать направляющий островок для остановки запрещено.</p>","image":"assets/adrive-questions/q300200203.webp"},{"id":300200301,"themeId":2,"group":3002003,"chapter":84,"chapters":[84],"q":"Разрешается ли водителю синего легкового автомобиля совершить обгон учебного автомобиля в показанном месте?","a":["Разрешается.","Запрещается.","Разрешается, если учебный автомобиль движется со скоростью менее 30 км/ч."],"c":2,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.1 , которая не запрещает водителю синего легкового автомобиля совершить обгон учебного автомобиля, если учебный автомобиль движется со скоростью менее 30 км/ч.</p>","image":"assets/adrive-questions/q300200301.webp"},{"id":300200302,"themeId":2,"group":3002003,"chapter":84,"chapters":[84],"q":"Разрешается ли Вам, управляя легковым автомобилем, совершить обгон самоходной машины, движущейся со скоростью 35 км/ч, в показанном месте?","a":["Разрешается.","Запрещается."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.1 , которая запрещает водителю легкового автомобиля совершить обгон самоходной машины, движущейся со скоростью 35 км/ч.</p>","image":"assets/adrive-questions/q300200302.webp"},{"id":300200501,"themeId":2,"group":3002005,"chapter":84,"chapters":[84],"q":"Водителям каких транспортных средств разрешено в показанной ситуации выполнить перестроение?","a":["Только водителю автомобиля «А».","Только водителю автомобиля «Б».","Водителям автомобилей «А» и «Б».","Водителям автомобилей «А» и «Б» в показанной ситуации перестроение запрещено."],"c":1,"e":"<p>Водитель автомобиля «Б» Правила дорожного движения не нарушает, пересекая линию горизонтальной дорожной разметки 1.6 .</p> <p>Водитель автомобиля «А» намерен пересечь сплошную линию горизонтальной дорожной разметки 1.1 , которую в показанной ситуации пересекать запрещено.</p>","image":"assets/adrive-questions/q300200501.webp"},{"id":300200502,"themeId":2,"group":3002005,"chapter":84,"chapters":[84],"q":"Разрешается ли водителю легкового автомобиля в показанной ситуации пересечь сплошную линию горизонтальной дорожной разметки, чтобы совершить объезд препятствия?","a":["Разрешается.","Запрещается."],"c":0,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.1 , которую не запрещается пересекать для объезда неподвижного препятствия на дороге.</p>","image":"assets/adrive-questions/q300200502.webp"},{"id":300200601,"themeId":2,"group":3002006,"chapter":84,"chapters":[84],"q":"В каком случае водитель красного легкового автомобиля не нарушит Правила дорожного движения?","a":["Если выполнит разворот по траектории «А».","Если выполнит обгон грузового автомобиля, движущегося со скоростью менее 30 км/ч, по траектории «Б».","Не нарушит в обоих случаях.","Нарушит в обоих случаях."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.1 , которую не запрещается пересекать для обгона грузового автомобиля, движущегося со скоростью менее 30 км/ч, по траектории «Б».</p>","image":"assets/adrive-questions/q300200601.webp"},{"id":300200602,"themeId":2,"group":3002006,"chapter":84,"chapters":[84],"q":"В каких случаях запрещено пересекать показанную сплошную линию горизонтальной дорожной разметки?","a":["Для разворота.","Для объезда неподвижного препятствия на дороге, создающего опасность для движения.","Для обгона одиночного транспортного средства, движущегося со скоростью менее 30 км/ч.","Запрещено во всех перечисленных случаях."],"c":0,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.1 , которую запрещается пересекать для разворота.</p>","image":"assets/adrive-questions/q300200602.webp"},{"id":300200603,"themeId":2,"group":3002006,"chapter":84,"chapters":[84],"q":"Разрешено ли водителю жёлтого легкового автомобиля повернуть направо по какой-либо из показанных траекторий для дальнейшего поворота налево на перекрёстке?","a":["Разрешено только по траектории «А».","Разрешено только по траектории «Б».","Разрешено как по траектории «А», так и по траектории «Б».","Запрещено по любой из показанных траекторий."],"c":3,"e":"<p>Сплошную линию горизонтальной дорожной разметки 1.1 запрещено пересекать, совершая поворот или перестроение.</p>","image":"assets/adrive-questions/q300200603.webp"},{"id":300200651,"themeId":2,"group":3002006,"chapter":84,"chapters":[84],"q":"По какой из показанных траекторий Вам разрешено выполнить разворот, управляя легковым автомобилем?","a":["Только по траектории «А».","Только по траектории «Б».","По траектории «А» и «Б»."],"c":2,"e":"<p>Дорожный знак 3.18.2 , запрещающий поворот налево на перекрёстке, не запрещает разворот. Также не запрещает разворот прерывистая линия дорожной разметки.</p> <p>Поэтому разворот не запрещён по обеим показанным траекториям.</p>","image":"assets/adrive-questions/q300200651.webp"},{"id":300200701,"themeId":2,"group":3002007,"chapter":84,"chapters":[84],"q":"Водитель какого автомобиля нарушил Правила дорожного движения, совершая разворот на показанном участке дороги?","a":["Только водитель грузового автомобиля.","Только водитель легкового автомобиля.","Нарушили водители обоих автомобилей."],"c":2,"e":"<p>На показанном участке дороги нанесена дорожная разметка 1.9 .<br> При включённых зелёных сигналах реверсивных светофоров линию 1.9 разрешается пересекать при перестроении на попутную полосу движения.<br> Пересекать линию разметки слева, отделяющую встречную полосу, запрещено, в том числе для разворота.</p>","image":"assets/adrive-questions/q300200701.webp"},{"id":300200702,"themeId":2,"group":3002007,"chapter":84,"chapters":[84],"q":"В каком случае, управляя легковым автомобилем, Вы нарушите Правила дорожного движения, перестроившись на соседнюю полосу движения?","a":["Если перестроитесь влево.","Если перестроитесь вправо.","Нарушите в обоих перечисленных случаях.","Не нарушите в обоих перечисленных случаях."],"c":0,"e":"<p>На показанном участке дороги нанесена дорожная разметка 1.9 .<br> При включённых зелёных сигналах реверсивных светофоров линию 1.9 разрешается пересекать при перестроении на попутную полосу движения.<br> Пересекать линию разметки слева, отделяющую встречную полосу, запрещено.</p>","image":"assets/adrive-questions/q300200702.webp"},{"id":300200801,"themeId":2,"group":3002008,"chapter":84,"chapters":[84],"q":"Нарушит ли Правила дорожного движения водитель легкового автомобиля, совершив обгон в показанной обстановке?","a":["Нарушит.","Не нарушит.","Не нарушит только в том случае, если скорость движения трактора менее 30 км/ч."],"c":2,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.1 , поэтому водитель легкового автомобиля, совершив обгон в показанной обстановке, не нарушит Правила дорожного движения только в том случае, если скорость движения трактора менее 30 км/ч.</p>","image":"assets/adrive-questions/q300200801.webp"},{"id":300200802,"themeId":2,"group":3002008,"chapter":84,"chapters":[84],"q":"Нарушит ли Правила дорожного движения водитель легкового автомобиля, совершив обгон в показанной обстановке?","a":["Нарушит.","Не нарушит.","Не нарушит только в том случае, если скорость движения тракторов менее 30 км/ч."],"c":0,"e":"<p>На показанном участке дороги нанесена дорожная разметка 1.11 , которую для выполнения обгона со стороны сплошной линии пересекать запрещено.</p>","image":"assets/adrive-questions/q300200802.webp"},{"id":300200901,"themeId":2,"group":3002009,"chapter":84,"chapters":[84],"q":"Нарушит ли Правила дорожного движения водитель легкового автомобиля, совершив обгон в показанной обстановке?","a":["Нарушит.","Не нарушит.","Не нарушит только в том случае, если скорость движения трактора менее 30 км/ч."],"c":1,"e":"<p>На показанном участке дороги нанесена дорожная разметка 1.6 , переходящая в разметку 1.11 .<br> Горизонтальную разметку 1.6 для выполнения обгона пересекать разрешено.<br> При завершении обгона разрешается пересекать линию 1.11.</p>","image":"assets/adrive-questions/q300200901.webp"},{"id":300200902,"themeId":2,"group":3002009,"chapter":84,"chapters":[84],"q":"Нарушит ли Правила дорожного движения водитель легкового автомобиля, совершив обгон в показанной обстановке?","a":["Нарушит.","Не нарушит.","Не нарушит только в том случае, если скорость движения трактора менее 30 км/ч."],"c":2,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.1 , поэтому водитель легкового автомобиля, совершив обгон в показанной обстановке, не нарушит Правила дорожного движения только в том случае, если скорость движения трактора менее 30 км/ч.</p>","image":"assets/adrive-questions/q300200902.webp"},{"id":300200903,"themeId":2,"group":3002009,"chapter":84,"chapters":[84],"q":"Нарушит ли Правила дорожного движения водитель легкового автомобиля, совершив обгон в показанной обстановке?","a":["Нарушит.","Не нарушит.","Не нарушит только в том случае, если скорость движения тракторов менее 30 км/ч."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.11 , которую для совершения обгона со стороны прерывистой линии пересекать разрешено.</p>","image":"assets/adrive-questions/q300200903.webp"},{"id":300200904,"themeId":2,"group":3002009,"chapter":84,"chapters":[84],"q":"Разрешает ли показанная линия горизонтальной дорожной разметки, разделяющая транспортные потоки противоположных направлений, выполнить обгон со стороны прерывистой линии?","a":["Да, разрешает.","Разрешает только обгон одиночного транспортного средства, движущегося со скоростью менее 30 км/ч.","Нет, не разрешает."],"c":0,"e":"<p>Показанная линия горизонтальной дорожной разметки 1.11 обозначает разделение транспортных потоков противоположных направлений на участках дорог, на которых перестроение разрешено только со стороны прерывистой линии, в том числе для выполнения обгона, когда это не запрещено иными положениями Правил дорожного движения и техническими средствами организации дорожного движения.</p>","image":"assets/adrive-questions/q300200904.webp"},{"id":300200951,"themeId":2,"group":3002009,"chapter":84,"chapters":[84],"q":"Разрешено ли пересекать показанную линию горизонтальной дорожной разметки со стороны сплошной линии?","a":["Разрешено в начале обгона.","Разрешено при повороте налево или развороте.","Разрешено при выезде с площадки для стоянки.","Разрешено при завершении объезда препятствия.","Запрещено во всех перечисленных случаях."],"c":3,"e":"<p>Со стороны сплошной линии разрешается пересекать показанную разметку только <strong>при завершении обгона или объезда препятствия</strong>.</p>","image":"assets/adrive-questions/q300200951.webp"},{"id":300201001,"themeId":2,"group":3002010,"chapter":84,"chapters":[84],"q":"Кто из водителей не нарушает Правила дорожного движения при выполнении маневрирования на перекрёстке так, как показано на рисунке?","a":["Водитель синего автомобиля.","Водитель красного автомобиля.","Водители обоих автомобилей не нарушают.","Водители обоих автомобилей нарушают."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.11 , которую пересекать разрешено в показанной ситуации только со стороны прерывистой линии.</p>","image":"assets/adrive-questions/q300201001.webp"},{"id":300201051,"themeId":2,"group":3002010,"chapter":84,"chapters":[84],"q":"Разрешено ли Вам выполнить разворот на показанном участке дороги?","a":["Разрешено только при видимости дороги в обоих направлениях движения не менее 100 метров.","Запрещено."],"c":0,"e":"<p>На показанном участке дороги транспортные потоки противоположных направлений разделяет линия разметки 1.11, которую разрешено пересекать со стороны прерывистой линии. На таком участке дороги разворот не запрещён. При этом выполнение разворота может быть разрешено только при условии, что видимость дороги в обоих направлениях составляет не менее 100 метров.</p>","image":"assets/adrive-questions/q300201051.webp"},{"id":300201101,"themeId":2,"group":3002011,"chapter":84,"chapters":[84],"q":"В каком направлении в показанной ситуации разрешено продолжить движение водителю синего легкового автомобиля?","a":["Только прямо.","Только налево.","Только на разворот.","Прямо и на разворот.","Налево и на разворот."],"c":2,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.18.3 и установлен дорожный знак 3.18.2 «Поворот налево запрещён» .</p> <p>В случае, если горизонтальная дорожная разметка противоречит дорожным знакам, водители должны руководствоваться дорожными знаками.</p> <p>Поэтому водителю синего легкового автомобиля разрешено продолжить движение только на разворот.</p>","image":"assets/adrive-questions/q300201101.webp"},{"id":300201102,"themeId":2,"group":3002011,"chapter":84,"chapters":[84],"q":"В каком направлении в показанной ситуации разрешено продолжить движение водителю синего легкового автомобиля?","a":["Только прямо.","Только налево.","Только на разворот.","Прямо и на разворот.","Налево и на разворот."],"c":0,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.18.3 и установлен дорожный знак 4.1.1 «Движение прямо» .</p> <p>В случае, если горизонтальная дорожная разметка противоречит дорожным знакам, водители должны руководствоваться дорожными знаками.</p> <p>Поэтому водителю синего легкового автомобиля разрешено продолжить движение только прямо.</p>","image":"assets/adrive-questions/q300201102.webp"},{"id":300201161,"themeId":2,"group":3002011,"chapter":84,"chapters":[84],"q":"Разрешено ли Вам повернуть направо в показанной ситуации?","a":["Разрешено.","Запрещено."],"c":1,"e":"<p>В показанной ситуации складывается впечатление, что разметка противоречит знаку \"3.18.1 Поворот направо запрещён\". В любом случае <strong>водитель обязан руководствоваться требованиями дорожного знака </strong>и не поворачивать направо по направлению, показанному стрелкой.</p> <p>На самом деле линии разметки указывают направление движения на следующем перекрёстке, и наносятся они дважды или трижды с расстояниями между стрелами от 20 до 30 метров.</p> <p>См. п. 6.2.22 СТБ 1300-2014.</p>","image":"assets/adrive-questions/q300201161.webp"},{"id":300201201,"themeId":2,"group":3002012,"chapter":84,"chapters":[84],"q":"Какое назначение может иметь показанная тонкая белая линия горизонтальной дорожной разметки?","a":["Разделение транспортных потоков противоположных направлений.","Обозначение границ проезжей части дороги, на которые въезд запрещён.","Любое из вышеперечисленных."],"c":2,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.1 , которая может разделять транспортные потоки противоположных направлений и обозначать границы проезжей части дороги, на которую въезд запрещён.</p>","image":"assets/adrive-questions/q300201201.webp"},{"id":300201203,"themeId":2,"group":3002012,"chapter":84,"chapters":[84],"q":"Какое назначение может иметь показанная тонкая белая линия горизонтальной дорожной разметки?","a":["Обозначение полос движения в пределах перекрёстка.","Обозначение границ полос движения на опасных участках дороги.","Обозначение границ полос движения, на которых осуществляется реверсивное регулирование.","Любое из вышеперечисленных."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.1 , которая может обозначать границы полос движения на опасных участках дороги.</p>","image":"assets/adrive-questions/q300201203.webp"},{"id":300201232,"themeId":2,"group":3002012,"chapter":84,"chapters":[84],"q":"Какое назначение может иметь показанная тонкая жёлтая временная линия горизонтальной дорожной разметки?","a":["Обозначение границ полос движения на опасных участках дороги.","Разделение транспортных потоков противоположных направлений.","Обозначение границ проезжей части дороги, на которые въезд запрещён.","Любое из вышеперечисленных."],"c":3,"e":"<p>Показанная временная линия горизонтальной дорожной разметки 1.1 жёлтого цвета может иметь назначение:</p> <ul><li> Разделение транспортных потоков противоположных направлений;</li> <li> Обозначение границ полос движения на опасных участках дороги;</li> <li> Обозначение границ проезжей части дороги, на которые въезд запрещён.</li></ul> <p>Следует также учитывать, что линии временной дорожной разметки могут противоречить линиям постоянной разметки белого цвета.</p>","image":"assets/adrive-questions/q300201232.webp"},{"id":300201401,"themeId":2,"group":3002014,"chapter":84,"chapters":[84],"q":"Какое назначение может иметь показанная двойная сплошная линия горизонтальной дорожной разметки?","a":["Обозначение полос движения в пределах перекрёстка.","Обозначение границ полос движения на опасных участках дороги.","Обозначение границ полос движения, на которых осуществляется реверсивное регулирование.","Разделение транспортных потоков противоположных направлений на дорогах без разделительной полосы."],"c":3,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.3 , которая может обозначать разделение транспортных потоков противоположных направлений на дорогах без разделительной полосы, имеющих три и более полосы движения.</p>","image":"assets/adrive-questions/q300201401.webp"},{"id":300201432,"themeId":2,"group":3002014,"chapter":84,"chapters":[84],"q":"В каком ответе наиболее правильно указано, какое общее количество полос движения может иметь проезжая часть дороги при применении двойной сплошной линии горизонтальной дорожной разметки?","a":["Две и более.","Три и более.","Четыре и более.","Любое количество."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.3 , которая применяется для разделения транспортных потоков противоположных направлений на дорогах без разделительной полосы, имеющих три и более полосы движения.</p>","image":"assets/adrive-questions/q300201432.webp"},{"id":300201501,"themeId":2,"group":3002015,"chapter":84,"chapters":[84],"q":"Какое назначение имеет жёлтая сплошная линия дорожной разметки, нанесённая по верху бордюра?","a":["Обозначение мест, где запрещена только стоянка транспортных средств.","Обозначение мест, где запрещены остановка и стоянка транспортных средств.","Обозначение остановочных пунктов маршрутных транспортных средств и стоянок такси."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.4 , которая обозначает места, где запрещены остановка и стоянка транспортных средств.</p>","image":"assets/adrive-questions/q300201501.webp"},{"id":300201502,"themeId":2,"group":3002015,"chapter":84,"chapters":[84],"q":"Какое назначение имеет жёлтая сплошная линия дорожной разметки, нанесённая у края проезжей части дороги?","a":["Обозначение мест, где запрещена только стоянка транспортных средств.","Обозначение мест, где запрещены остановка и стоянка транспортных средств.","Обозначение остановочных пунктов маршрутных транспортных средств и стоянок такси."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.4 , которая обозначает места, где запрещены остановка и стоянка транспортных средств.</p>","image":"assets/adrive-questions/q300201502.webp"},{"id":300201701,"themeId":2,"group":3002017,"chapter":84,"chapters":[84],"q":"Какое назначение имеет показанная прерывистая горизонтальная дорожная разметка, у которой длина штриха в три раза больше промежутка между штрихами?","a":["Обозначение полос движения в пределах перекрёстка.","Обозначение приближения к сплошной линии продольной разметки.","Обозначение границ полос движения, на которых осуществляется реверсивное движение.","Обозначение границы между полосой разгона или торможения и основной полосой проезжей части дороги."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.6 , которая обозначает приближение к сплошной линии продольной разметки.</p>","image":"assets/adrive-questions/q300201701.webp"},{"id":300201732,"themeId":2,"group":3002017,"chapter":84,"chapters":[84],"q":"Какое назначение имеет показанная временная жёлтая прерывистая горизонтальная дорожная разметка, у которой длина штриха в три раза больше промежутка между штрихами?","a":["Обозначение границ полос движения на опасных участках дороги.","Обозначение приближения к сплошной линии продольной разметки.","Обозначение границ проезжей части дороги, на которые въезд запрещён.","Разделение транспортных потоков противоположных направлений на дорогах без разделительной полосы, имеющих четыре и более полосы движения."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка, которая обозначает приближение к сплошной линии продольной разметки.</p>","image":"assets/adrive-questions/q300201732.webp"},{"id":300201901,"themeId":2,"group":3002019,"chapter":84,"chapters":[84],"q":"Какое назначение имеет жёлтая прерывистая линия дорожной разметки, нанесённая у края проезжей части дороги?","a":["Обозначение мест, где запрещена стоянка транспортных средств.","Обозначение мест, где запрещены остановка и стоянка транспортных средств.","Обозначение остановочных пунктов маршрутных транспортных средств и стоянок такси."],"c":0,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.10 , которая обозначает места, где запрещена стоянка транспортных средств.</p>","image":"assets/adrive-questions/q300201901.webp"},{"id":300201902,"themeId":2,"group":3002019,"chapter":84,"chapters":[84],"q":"Какое назначение имеет жёлтая прерывистая линия дорожной разметки, нанесённая по верху бордюра?","a":["Обозначение мест, где запрещена стоянка транспортных средств.","Обозначение мест, где запрещены остановка и стоянка транспортных средств.","Обозначение остановочных пунктов маршрутных транспортных средств и стоянок такси."],"c":0,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.10 , которая обозначает места, где запрещена стоянка транспортных средств.</p>","image":"assets/adrive-questions/q300201902.webp"},{"id":300202001,"themeId":2,"group":3002020,"chapter":84,"chapters":[84],"q":"Разрешается ли водителю белого легкового автомобиля произвести высадку пассажиров в показанном месте?","a":["Разрешается.","Запрещается.","Разрешается, только если это займёт не более 5 минут."],"c":0,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.10 , которая не запрещает водителю легкового автомобиля произвести высадку пассажиров (совершить остановку).</p>","image":"assets/adrive-questions/q300202001.webp"},{"id":300202002,"themeId":2,"group":3002020,"chapter":84,"chapters":[84],"q":"Разрешается ли водителю синего легкового автомобиля произвести высадку пассажиров в показанном на рисунке участке дороги?","a":["Разрешается только слева.","Разрешается только справа.","Разрешается как справа, так и слева.","Запрещается."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.10 у правого края проезжей части дороги и 1.4 у левого края проезжей части дороги, поэтому водителю легкового автомобиля произвести высадку пассажиров (совершить остановку) разрешается только справа.</p>","image":"assets/adrive-questions/q300202002.webp"},{"id":300202051,"themeId":2,"group":3002020,"chapter":84,"chapters":[84],"q":"Если у края проезжей части дороги нанесена жёлтая прерывистая линия горизонтальной дорожной разметки, то в указанном месте:","a":["Разрешена только остановка.","Разрешены остановка и стоянка.","Запрещены остановка и стоянка."],"c":0,"e":"<p>В показанном месте у края проезжей части дороги нанесена жёлтая прерывистая линия горизонтальной дорожной разметки 1.10, запрещающая стоянку транспортных средств. <strong>Остановка не запрещена</strong>.</p>","image":"assets/adrive-questions/q300202051.webp"},{"id":300202301,"themeId":2,"group":3002023,"chapter":84,"chapters":[84],"q":"Какое назначение имеет показанная надпись на проезжей части дороги?","a":["Приближение к разметке «стоп-линия».","Место обязательной остановки транспортных средств.","Обозначение полосы, выделенной для движения маршрутных транспортных средств.","Обозначение места, где водитель обязан уступить дорогу транспортным средствам, движущимся по пересекаемой дороге."],"c":0,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.21 , которая обозначает приближение к разметке «стоп-линия».</p>","image":"assets/adrive-questions/q300202301.webp"},{"id":300202302,"themeId":2,"group":3002023,"chapter":84,"chapters":[84],"q":"Обязан ли водитель остановиться в показанной ситуации?","a":["Не обязан.","Обязан перед надписью на проезжей части дороги."],"c":0,"e":"<p>На показанном участке дороги нанесена дорожная разметка 1.21 , которая обозначает приближение к разметке «стоп-линия».<br> Поэтому водитель не обязан останавливаться перед этой надписью на проезжей части дороги.</p>","image":"assets/adrive-questions/q300202302.webp"},{"id":300202501,"themeId":2,"group":3002025,"chapter":84,"chapters":[84],"q":"Укажите место, где водитель обязан уступить дорогу транспортным средствам, движущимся по пересекаемой дороге?","a":["В точке «А».","В точке «Б».","В точке «В».","В точке «Г»."],"c":2,"e":"<p>В месте, указанном буквой «В», нанесена дорожная разметка 1.13 , которая указывает место, где водитель обязан уступить дорогу транспортным средствам, движущимся по пересекаемой дороге, иным участникам дорожного движения, путь движения которых он пересекает.</p>","image":"assets/adrive-questions/q300202501.webp"},{"id":300202502,"themeId":2,"group":3002025,"chapter":84,"chapters":[84],"q":"Какой из показанных видов дорожной разметки применяется для обозначения места, где водитель обязан уступить дорогу транспортным средствам, движущимся по пересекаемой дороге, иным участникам дорожного движения, путь движения которых он пересекает?","a":["Разметка 1.","Разметка 2.","Разметка 3."],"c":2,"e":"<p>На рисунке под номером 3 изображена дорожная разметка 1.13 , которая указывает место, где водитель обязан уступить дорогу транспортным средствам, движущимся по пересекаемой дороге, иным участникам дорожного движения, путь движения которых он пересекает.</p>","image":"assets/adrive-questions/q300202502.webp"},{"id":300202533,"themeId":2,"group":3002025,"chapter":84,"chapters":[84],"q":"Какое назначение имеет показанная на рисунке дорожная разметка?","a":["Обозначение места остановки транспортных средств — «стоп-линия».","Обозначение границ зоны остановочного пункта трамвая, расположенного на одном уровне с проезжей частью дороги.","Обозначение места, где водитель обязан уступить дорогу транспортным средствам, движущимся по пересекаемой дороге, иным участникам дорожного движения, путь движения которых он пересекает."],"c":2,"e":"<p>На показанном участке дороги нанесена дорожная разметка 1.13 , которая обозначает место, где водитель обязан уступить дорогу транспортным средствам, движущимся по пересекаемой дороге, иным участникам дорожного движения, путь движения которых он пересекает.</p>","image":"assets/adrive-questions/q300202533.webp"},{"id":300202702,"themeId":2,"group":3002027,"chapter":84,"chapters":[84],"q":"Обязан ли водитель остановиться перед разметкой в показанной ситуации?","a":["Да, обязан.","Нет, не обязан."],"c":1,"e":"<p>Показанная на рисунке дорожная разметка 1.20 обозначает приближение к месту, где водитель обязан уступить дорогу транспортным средствам, движущимся по пересекаемой дороге, иным участникам дорожного движения, путь движения которых он пересекает.<br> Останавливаться в показанном месте нет никакой необходимости.</p>","image":"assets/adrive-questions/q300202702.webp"},{"id":300202731,"themeId":2,"group":3002027,"chapter":84,"chapters":[84],"q":"Какое назначение имеет показанная на рисунке дорожная разметка?","a":["Место обязательной остановки транспортных средств.","Обозначение приближения к месту установки дорожного знака «Движение без остановки запрещено».","Обозначение места, где водитель обязан уступить дорогу транспортным средствам, движущимся по пересекаемой дороге, иным участникам дорожного движения, путь движения которых он пересекает.","Обозначение приближения к месту, где водитель обязан уступить дорогу транспортным средствам, движущимся по пересекаемой дороге, иным участникам дорожного движения, путь движения которых он пересекает."],"c":3,"e":"<p>Показанная на рисунке дорожная разметка 1.20 обозначает приближение к месту, где водитель обязан уступить дорогу транспортным средствам, движущимся по пересекаемой дороге, иным участникам дорожного движения, путь движения которых он пересекает.</p>","image":"assets/adrive-questions/q300202731.webp"},{"id":300202801,"themeId":2,"group":3002028,"chapter":84,"chapters":[84],"q":"Какое назначение имеет показанная горизонтальная дорожная разметка?","a":["Обозначение искусственной неровности.","Обозначение пешеходного перехода в местах повышенной опасности.","Обозначение нерегулируемого пешеходного перехода, оборудованного искусственной неровностью."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.14.2 , которая обозначает нерегулируемый или регулируемый пешеходный переход в местах повышенной опасности.</p>","image":"assets/adrive-questions/q300202801.webp"},{"id":300202802,"themeId":2,"group":3002028,"chapter":84,"chapters":[84],"q":"Для обозначения каких пешеходных переходов применяется показанная дорожная разметка?","a":["Для обозначения пешеходных переходов с ограниченной обзорностью.","Для обозначения пешеходных переходов в местах повышенной опасности.","Для обозначения пешеходных переходов, совмещённых с велосипедной дорожкой.","Для обозначения пешеходных переходов, перед которыми установлены искусственные неровности."],"c":1,"e":"<p>Показанная дорожная разметка 1.14.2 обозначает нерегулируемый или регулируемый пешеходный переход в местах повышенной опасности.</p>","image":"assets/adrive-questions/q300202802.webp"},{"id":300202861,"themeId":2,"group":3002028,"chapter":84,"chapters":[84],"q":"Какое назначение может иметь показанная горизонтальная дорожная разметка (чередующиеся белые и жёлтые полосы)?","a":["Обозначение искусственной неровности.","Обозначение регулируемого и нерегулируемого пешеходного перехода, оборудованного искусственной неровностью.","Обозначение регулируемого и нерегулируемого пешеходного перехода, а также мест пересечения пешеходами велосипедной дорожки в местах повышенной опасности."],"c":2,"e":"<p>Показанная горизонтальная дорожная разметка в данном случае служит <strong>для обозначения регулируемого и нерегулируемого пешеходного перехода</strong> в месте повышенной опасности.</p>","image":"assets/adrive-questions/q300202861.webp"},{"id":300202901,"themeId":2,"group":3002029,"chapter":84,"chapters":[84],"q":"Какой из показанных видов дорожной разметки применяется только для обозначения пешеходного перехода, оборудованного дорожными светофорами?","a":["Разметка 1.","Разметка 2.","Разметка 3."],"c":1,"e":"<p>На рисунке под номером 2 изображена дорожная разметка 1.14.3 , которая применяется только для обозначения пешеходного перехода, оборудованного дорожными светофорами.</p>","image":"assets/adrive-questions/q300202901.webp"},{"id":300202902,"themeId":2,"group":3002029,"chapter":84,"chapters":[84],"q":"Какое назначение имеет дорожная разметка, к которой Вы приближаетесь в показанной ситуации?","a":["Обозначение нерегулируемого пешеходного перехода.","Обозначение пешеходного перехода, оборудованного дорожными светофорами.","Обозначение места, где велосипедная дорожка пересекает проезжую часть дороги.","Обозначение нерегулируемого пешеходного перехода в местах повышенной опасности."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.14.3 , которая применяется для обозначения пешеходного перехода, оборудованного дорожными светофорами.</p>","image":"assets/adrive-questions/q300202902.webp"},{"id":300203031,"themeId":2,"group":3002030,"chapter":84,"chapters":[84],"q":"Какой из показанных видов дорожной разметки применяется для обозначения велосипедного переезда?","a":["Разметка 1.","Разметка 2.","Разметка 3."],"c":2,"e":"<p>На рисунке под номером 3 изображена дорожная разметка 1.15 , которая применяется для обозначения велосипедного переезда. Зона велосипедного переезда может обозначаться зелёным цветом.</p>","image":"assets/adrive-questions/q300203031.webp"},{"id":300203032,"themeId":2,"group":3002030,"chapter":84,"chapters":[84],"q":"Какое назначение имеет дорожная разметка, к которой приближается легковой автомобиль?","a":["Обозначение нерегулируемого пешеходного перехода.","Обозначение пешеходного перехода, оборудованного дорожными светофорами.","Обозначение велосипедного переезда.","Обозначение пешеходного перехода в местах повышенной опасности."],"c":2,"e":"<p>На показанном рисунке изображена дорожная разметка 1.15 , которая применяется для обозначения велосипедного переезда. Зона велосипедного переезда может обозначаться зелёным цветом.</p>","image":"assets/adrive-questions/q300203032.webp"},{"id":300203101,"themeId":2,"group":3002031,"chapter":84,"chapters":[84],"q":"Нарушил ли Правила дорожного движения водитель легкового автомобиля, двигаясь, как показано на рисунке?","a":["Да, нарушил.","Нет, не нарушил."],"c":0,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.16.1 , которая разделяет транспортные потоки противоположных направлений.<br> Поэтому водитель легкового автомобиля, двигаясь, как показано на рисунке, нарушает Правила дорожного движения.</p>","image":"assets/adrive-questions/q300203101.webp"},{"id":300203102,"themeId":2,"group":3002031,"chapter":84,"chapters":[84],"q":"Нарушил ли Правила дорожного движения водитель легкового автомобиля, двигаясь, как показано на рисунке?","a":["Да, нарушил.","Нет, не нарушил."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.16.1 , которая разделяет транспортные потоки противоположных направлений.<br> Поэтому водитель легкового автомобиля, двигаясь, как показано на рисунке, не нарушает Правила дорожного движения.</p>","image":"assets/adrive-questions/q300203102.webp"},{"id":300203201,"themeId":2,"group":3002032,"chapter":84,"chapters":[84],"q":"Нарушил ли Правила дорожного движения водитель легкового автомобиля, двигаясь, как показано на рисунке?","a":["Да, нарушил.","Нет, не нарушил."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.16.2 , которая разделяет транспортные потоки одного направления.<br> Поэтому водитель легкового автомобиля, двигаясь, как показано на рисунке, не нарушает Правила дорожного движения.</p>","image":"assets/adrive-questions/q300203201.webp"},{"id":300203202,"themeId":2,"group":3002032,"chapter":84,"chapters":[84],"q":"Нарушил ли Правила дорожного движения водитель легкового автомобиля, двигаясь, как показано на рисунке?","a":["Да, нарушил.","Нет, не нарушил."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.16.2 , которая разделяет транспортные потоки одного направления.<br> Поэтому водитель легкового автомобиля, двигаясь, как показано на рисунке, не нарушает Правила дорожного движения.</p>","image":"assets/adrive-questions/q300203202.webp"},{"id":300203301,"themeId":2,"group":3002033,"chapter":84,"chapters":[84],"q":"Нарушает ли Правила дорожного движения водитель легкового автомобиля, двигаясь, как показано на рисунке?","a":["Да, нарушает.","Нет, не нарушает."],"c":0,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.16.3 , которая обозначает островки в местах слияния транспортных потоков.<br> Поэтому водитель легкового автомобиля, двигаясь, как показано на рисунке, нарушает Правила дорожного движения.</p>","image":"assets/adrive-questions/q300203301.webp"},{"id":300203302,"themeId":2,"group":3002033,"chapter":84,"chapters":[84],"q":"В каких местах применяется показанный на рисунке островок?","a":["В местах слияния транспортных потоков.","В местах разделения транспортных потоков одного направления.","В местах разделения транспортных потоков противоположных направлений."],"c":0,"e":"<p>На рисунке изображена дорожная разметка 1.16.3 , которая обозначает островки в местах слияния транспортных потоков.</p>","image":"assets/adrive-questions/q300203302.webp"},{"id":300203501,"themeId":2,"group":3002035,"chapter":84,"chapters":[84],"q":"Что обозначают показанной дорожной разметкой жёлтого цвета?","a":["Место проведения дорожных работ.","Место, где запрещена остановка транспортных средств.","Обозначение приближения к сужению проезжей части дороги.","Остановочный пункт маршрутных транспортных средств или стоянка такси."],"c":3,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.17.1 , которой обозначают остановочный пункт маршрутных транспортных средств или стоянку такси.</p>","image":"assets/adrive-questions/q300203501.webp"},{"id":300203502,"themeId":2,"group":3002035,"chapter":84,"chapters":[84],"q":"Что может обозначать показанная дорожная разметка жёлтого цвета?","a":["Только место стоянки такси.","Только остановочный пункт маршрутных транспортных средств.","Всё вышеперечисленное."],"c":2,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.17.1 , которой обозначают остановочный пункт маршрутных транспортных средств или стоянку такси.</p>","image":"assets/adrive-questions/q300203502.webp"},{"id":300203503,"themeId":2,"group":3002035,"chapter":84,"chapters":[84],"q":"Правильно ли легковые автомобили поставлены на стоянку в показанном месте?","a":["Да, правильно.","Нет, неправильно."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.17.1 , которой обозначают остановочный пункт маршрутных транспортных средств или стоянку такси.<br> Поэтому легковые автомобили поставлены на стоянку с нарушением Правил дорожного движения.</p>","image":"assets/adrive-questions/q300203503.webp"},{"id":300203701,"themeId":2,"group":3002037,"chapter":84,"chapters":[84],"q":"Какое назначение имеет показанная жёлтая дорожная разметка?","a":["Обозначение приближения к искусственной неровности.","Обозначение границ зоны остановочных пунктов маршрутных транспортных средств.","Обозначение границ зоны остановочного пункта трамвая, расположенного на одном уровне с проезжей частью дороги."],"c":2,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.17.2 , которой обозначают границы зоны остановочного пункта трамвая, расположенного на одном уровне с проезжей частью дороги.</p>","image":"assets/adrive-questions/q300203701.webp"},{"id":300203702,"themeId":2,"group":3002037,"chapter":84,"chapters":[84],"q":"Какое назначение имеет показанная жёлтая дорожная разметка?","a":["Обозначение границ зоны остановочного пункта трамвая, конструктивно выделенного над проезжей частью дороги.","Обозначение границ зоны остановочного пункта трамвая, расположенного на одном уровне с проезжей частью дороги.","Имеет оба вышеперечисленных назначения."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.17.2 , которой обозначают границы зоны остановочного пункта трамвая, расположенного на одном уровне с проезжей частью дороги.</p>","image":"assets/adrive-questions/q300203702.webp"},{"id":300203831,"themeId":2,"group":3002038,"chapter":84,"chapters":[84],"q":"Какое назначение может иметь дорожная разметка, показанная на рисунке?","a":["Обозначение направлений движения по полосам движения.","Обозначение приближения к участку дороги, на котором заканчивается данная полоса проезжей части.","Обозначение приближения к месту перестроения на другую проезжую часть дороги.","Обозначение приближения к повороту дороги малого радиуса закругления или с ограниченной обзорностью."],"c":1,"e":"<p>На рисунке изображена дорожная разметка 1.19.1 и 1.19.2 , которая может обозначать приближение к участку дороги, на котором заканчивается данная полоса проезжей части (с необходимостью перестроиться на соседнюю полосу справа или слева).</p>","image":"assets/adrive-questions/q300203831.webp"},{"id":300203832,"themeId":2,"group":3002038,"chapter":84,"chapters":[84],"q":"Какое назначение может иметь дорожная разметка, показанная на рисунке?","a":["Обозначение приближения к участку дороги, на котором заканчивается данная полоса проезжей части.","Обозначение приближения к участку дороги, где увеличивается количество полос движения в данном направлении.","Обозначение разрешённых направлений движения на прилегающей территории (автостоянках)."],"c":0,"e":"<p>На рисунке изображена дорожная разметка 1.19.1 и 1.19.2 , которая может обозначать приближение к участку дороги, на котором заканчивается данная полоса проезжей части (с необходимостью перестроиться на соседнюю полосу справа или слева).</p>","image":"assets/adrive-questions/q300203832.webp"},{"id":300203901,"themeId":2,"group":3002039,"chapter":84,"chapters":[84],"q":"Какое назначение имеет показанная на рисунке дорожная разметка?","a":["Обозначение номера дороги.","Обозначение парковочного места.","Расстояние до ближайшего места для стоянки."],"c":0,"e":"<p>Показанная на рисунке дорожная разметка 1.22 применяется для обозначения номера дороги.</p>","image":"assets/adrive-questions/q300203901.webp"},{"id":300204001,"themeId":2,"group":3002040,"chapter":84,"chapters":[84],"q":"Какое назначение имеет показанная на рисунке дорожная разметка?","a":["Обозначение полосы, выделенной для движения автобусов.","Обозначение полосы, выделенной для движения автомобилей.","Обозначение полосы, выделенной для движения маршрутных транспортных средств.","Обозначение полосы, выделенной для движения маршрутных транспортных средств и такси."],"c":2,"e":"<p>Показанная на рисунке дорожная разметка 1.23 применяется для обозначения полосы, выделенной для движения маршрутных транспортных средств.<br> Допускается движение по данной полосе электромобилей.</p>","image":"assets/adrive-questions/q300204001.webp"},{"id":300204003,"themeId":2,"group":3002040,"chapter":84,"chapters":[84],"q":"Что обозначают показанной горизонтальной дорожной разметкой в виде буквы «А»?","a":["Приближение к остановочному пункту маршрутных транспортных средств.","Полосу, выделенную для движения маршрутных транспортных средств.","Полосу, выделенную для движения маршрутных транспортных средств и автомобилей-такси."],"c":1,"e":"<p>Показанная горизонтальная дорожная разметка 1.23 применяется для обозначения полосы, выделенной для движения маршрутных транспортных средств.<br> Допускается движение по данной полосе электромобилей.</p>","image":"assets/adrive-questions/q300204003.webp"},{"id":300204101,"themeId":2,"group":3002041,"chapter":84,"chapters":[84],"q":"Какое назначение имеет показанная на рисунке дорожная разметка?","a":["Обозначение приближения к месту стоянки такси.","Обозначение приближения к искусственной неровности.","Обозначение границ зоны остановочного пункта трамвая.","Обозначение места, где велосипедная дорожка пересекает проезжую часть дороги."],"c":1,"e":"<p>Показанная на рисунке дорожная разметка 1.25 применяется для обозначения приближения к искусственной неровности.</p>","image":"assets/adrive-questions/q300204101.webp"},{"id":300204102,"themeId":2,"group":3002041,"chapter":84,"chapters":[84],"q":"Какое назначение имеет показанная дорожная разметка?","a":["Обозначение места стоянки такси.","Обозначение искусственной неровности.","Обозначение приближения к искусственной неровности.","Обозначение места остановки автобусов экспресс-маршрута."],"c":2,"e":"<p>Показанная на рисунке дорожная разметка 1.25 применяется для обозначения приближения к искусственной неровности.</p>","image":"assets/adrive-questions/q300204102.webp"},{"id":300204202,"themeId":2,"group":3002042,"chapter":84,"chapters":[84],"q":"Для чего применяется показанная на рисунке дорожная разметка?","a":["Для обозначения искусственной неровности.","Для обозначения нерегулируемого пешеходного перехода в местах повышенной опасности.","Может применяться в обоих перечисленных случаях."],"c":0,"e":"<p>Показанная на рисунке дорожная разметка 1.26 применяется для обозначения искусственной неровности.</p>","image":"assets/adrive-questions/q300204202.webp"},{"id":300204251,"themeId":2,"group":3002042,"chapter":84,"chapters":[84],"q":"Каково назначение показанной горизонтальной дорожной разметки жёлтого цвета?","a":["Обозначение велосипедного переезда.","Обозначение искусственной неровности.","Обозначение пешеходного перехода, оборудованного пешеходными светофорами.","Обозначение регулируемого и нерегулируемого пешеходного перехода в местах повышенной опасности."],"c":1,"e":"<p>Показанная дорожная разметка 1.26 применяется для обозначения искусственной неровности.</p>","image":"assets/adrive-questions/q300204251.webp"},{"id":300204301,"themeId":2,"group":3002043,"chapter":84,"chapters":[84],"q":"В каких направлениях Вам, находясь в показанной полосе движения, разрешено продолжить движение, управляя легковым автомобилем?","a":["Только налево.","Только на разворот.","Налево или на разворот.","Прямо, налево и на разворот."],"c":2,"e":"<p>В показанной ситуации дорожная разметка 1.18.3 , дорожный знак 5.8.1 «Направления движения по полосам» и разрешающий сигнал светофора не запрещают продолжить движение, управляя легковым автомобилем, налево или на разворот.</p>","image":"assets/adrive-questions/q300204301.webp"},{"id":300204302,"themeId":2,"group":3002043,"chapter":84,"chapters":[84],"q":"Нарушают ли Правила дорожного движения водители легковых автомобилей при выполнении разворота в ситуации, показанной на рисунке?","a":["Нарушают.","Нарушает только водитель зелёного автомобиля.","Не нарушают, если не создают помех движению транспортных средств по главной дороге."],"c":1,"e":"<p>В показанной ситуации на двух полосах нанесена дорожная разметка 1.18.3 , которая разрешает разворот только из крайней левой полосы движения.</p>","image":"assets/adrive-questions/q300204302.webp"},{"id":300204303,"themeId":2,"group":3002043,"chapter":84,"chapters":[84],"q":"Разрешено ли Вам, управляя легковым автомобилем, в показанной ситуации совершить разворот?","a":["Нет, запрещено.","Разрешено, уступив дорогу встречным транспортным средствам."],"c":0,"e":"<p>В показанной ситуации перед разрывом разделительной зоны нанесена горизонтальная дорожная разметка 1.18.1 , которая разрешает продолжить движение только прямо.</p> <p>Разворот в показанном месте запрещён.</p>","image":"assets/adrive-questions/q300204303.webp"},{"id":300204401,"themeId":2,"group":3002044,"chapter":84,"chapters":[84],"q":"В каких направлениях разрешено продолжить движение водителю зелёного автомобиля?","a":["Только налево.","Направо и налево.","Налево и на разворот.","Направо, налево и на разворот."],"c":3,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.18.6 , которая разрешает водителю зелёного автомобиля продолжить движение направо, налево и на разворот.</p>","image":"assets/adrive-questions/q300204401.webp"},{"id":300204402,"themeId":2,"group":3002044,"chapter":84,"chapters":[84],"q":"В каких направлениях разрешено продолжить движение водителю зелёного автомобиля?","a":["Только направо.","Направо и налево.","Направо, налево и на разворот."],"c":1,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.18.6 , которая разрешает водителю зелёного автомобиля продолжить движение направо и налево. Разворот может быть разрешён только из крайней левой полосы движения.</p>","image":"assets/adrive-questions/q300204402.webp"},{"id":300204801,"themeId":2,"group":3002048,"chapter":84,"chapters":[84],"q":"В каких направлениях разрешено продолжить движение водителю зелёного автомобиля?","a":["Только по направлению «А».","Только по направлению «Б».","Только по направлению «В».","По направлениям «А» и «В».","По направлениям «Б» и «В»."],"c":4,"e":"<p>В показанной ситуации нанесена дорожная разметка 1.18.10 , которая разрешает водителю зелёного автомобиля продолжить движение по направлениям «Б» и «В».</p> <p>Поворот налево на ближайшую проезжую часть дороги запрещён.</p>","image":"assets/adrive-questions/q300204801.webp"},{"id":300204802,"themeId":2,"group":3002048,"chapter":84,"chapters":[84],"q":"В каких направлениях разрешено продолжить движение водителю зелёного автомобиля?","a":["Только по направлению «А».","Только по направлению «Б».","По направлениям «А» и «Б»."],"c":1,"e":"<p>Перед перекрёстком в крайней правой полосе движения нанесена дорожная разметка 1.18.9 , которая разрешает водителю зелёного автомобиля продолжить движение только по направлению «Б».</p> <p>На ближайшую проезжую часть поворот направо запрещён.</p>","image":"assets/adrive-questions/q300204802.webp"},{"id":300204851,"themeId":2,"group":3002048,"chapter":84,"chapters":[84],"q":"В каких направлениях из перечисленных Вам разрешено продолжить движение в показанной ситуации из занимаемой полосы движения?","a":["На ближайшем пересечении — прямо, на следующем — прямо или налево.","На ближайшем пересечении — прямо или на разворот, на следующем — прямо или налево.","На ближайшем пересечении — прямо или налево, на следующем — прямо, налево или на разворот."],"c":0,"e":"<p>На ближайшем пересечении проезжих частей поворачивать налево (и разворачиваться) запрещено. На втором пересечении разрешено проехать прямо или повернуть налево. Разворот, находясь не в крайней левой полосе движения, выполнять не разрешается.</p>","image":"assets/adrive-questions/q300204851.webp"},{"id":300204941,"themeId":2,"group":3002049,"chapter":84,"chapters":[84],"q":"О чём информирует водителей показанная дорожная разметка, нанесённая на полосу движения?","a":["О приближении к достопримечательности.","Об осуществлении круглосуточного мониторинга дорожной обстановки на участке дороги.","Об осуществлении контроля соблюдения Правил дорожного движения с использованием технических средств в автоматическом режиме."],"c":2,"e":"<p>Показанная дорожная разметка 1.38 информирует об осуществлении контроля соблюдения Правил дорожного движения с использованием технических средств в автоматическом режиме.</p>","image":"assets/adrive-questions/q300204941.webp"},{"id":300205041,"themeId":2,"group":3002050,"chapter":84,"chapters":[84],"q":"О чём информирует водителей показанная дорожная разметка в виде надписи «МIЛIЦЫЯ», нанесённая на места для стоянки?","a":["Обозначает места, где разрешены остановка и стоянка только транспортных средств оперативного назначения органов внутренних дел.","Обозначает места, где разрешены остановка и стоянка только транспортных средств сотрудников правоохранительных органов.","Обозначает места, где запрещена стоянка транспортных средств, кроме транспортных средств оперативного назначения органов внутренних дел."],"c":0,"e":"<p>Показанная дорожная разметка 1.36 обозначает места, где разрешены остановка и стоянка только транспортных средств оперативного назначения органов внутренних дел.</p>","image":"assets/adrive-questions/q300205041.webp"},{"id":300300101,"themeId":2,"group":3003001,"chapter":85,"chapters":[85],"q":"Под каким номером на рисунке показана вертикальная дорожная разметка, предназначенная для обозначения элемента дорожного сооружения, который необходимо объезжать только слева?","a":["Под номером 1.","Под номером 2.","Под номером 3.","Под номером 4."],"c":0,"e":"<p>На рисунке под номером 1 показана вертикальная дорожная разметка 2.1.2 , предназначенная для обозначения элемента дорожного сооружения, который необходимо объезжать только слева.</p>","image":"assets/adrive-questions/q300300101.webp"},{"id":300300102,"themeId":2,"group":3003001,"chapter":85,"chapters":[85],"q":"С какой стороны необходимо объезжать вертикальный элемент дорожного сооружения, если он обозначен показанной на рисунке вертикальной дорожной разметкой?","a":["Только слева.","Только справа.","С любой стороны."],"c":0,"e":"<p>Показанная на рисунке вертикальная дорожная разметка 2.1.2 , предназначенная для обозначения элемента дорожного сооружения, который необходимо объезжать только слева.</p>","image":"assets/adrive-questions/q300300102.webp"},{"id":300300201,"themeId":2,"group":3003002,"chapter":85,"chapters":[85],"q":"Для чего применены щитки с вертикальной дорожной разметкой, закреплённые на мачтах освещения как показано на рисунке?","a":["Щитки означают, что пешеходы обязаны обходить их только слева.","Щитками обозначены для водителей вертикальные элементы дорожных сооружений, находящиеся в непосредственной близости от края проезжей части дороги."],"c":1,"e":"<p>В показанной ситуации щитки с вертикальной дорожной разметкой 2.1.2 , закреплённые на мачтах освещения, применены для обозначения для водителей вертикальных элементов дорожных сооружений, находящихся в непосредственной близости от края проезжей части дороги.</p>","image":"assets/adrive-questions/q300300201.webp"},{"id":300300202,"themeId":2,"group":3003002,"chapter":85,"chapters":[85],"q":"Под каким номером на рисунке показана вертикальная дорожная разметка, которая согласно Правилам дорожного движения предназначена для обозначения вертикальных элементов дорожных сооружений, если эти элементы представляют опасность для движения транспортных средств?","a":["Под номером 1.","Под номером 2.","Под номером 3.","Под номером 4."],"c":0,"e":"<p>На рисунке под номером 1 показана вертикальная дорожная разметка 2.1.3 , которая согласно Правилам дорожного движения предназначена для обозначения вертикальных элементов дорожных сооружений, если эти элементы представляют опасность для движения транспортных средств.</p> <p>Под номером 2 показана вертикальная дорожная разметка 2.3 , которая обозначает круглые тумбы, установленные на разделительных полосах или островках безопасности.</p> <p>Под номером 3 показана вертикальная дорожная разметка 2.4.3 , которая обозначает сигнальные щитки, установленные на барьерных ограждениях дорог.</p> <p>Под номером 4 показана вертикальная дорожная разметка 2.2 , которая обозначает нижний край пролётного строения мостов, путепроводов и эстакад.</p>","image":"assets/adrive-questions/q300300202.webp"},{"id":300300301,"themeId":2,"group":3003003,"chapter":85,"chapters":[85],"q":"Под каким номером на рисунке показана вертикальная дорожная разметка, предназначенная для обозначения элемента дорожного сооружения, который необходимо объезжать только справа?","a":["Под номером 1.","Под номером 2.","Под номером 3.","Под номером 4.","Под номером 5."],"c":2,"e":"<p>На рисунке под номером 3 показана вертикальная дорожная разметка 2.1.1 , предназначенная для обозначения элемента дорожного сооружения, который необходимо объезжать только справа.</p>","image":"assets/adrive-questions/q300300301.webp"},{"id":300300302,"themeId":2,"group":3003003,"chapter":85,"chapters":[85],"q":"С какой стороны необходимо объезжать вертикальный элемент дорожного сооружения, если он обозначен показанной на рисунке вертикальной дорожной разметкой?","a":["Только слева.","Только справа.","С любой стороны."],"c":1,"e":"<p>Показанная на рисунке вертикальная дорожная разметка 2.1.1 , предназначенная для обозначения элемента дорожного сооружения, который необходимо объезжать только справа.</p>","image":"assets/adrive-questions/q300300302.webp"},{"id":300300401,"themeId":2,"group":3003004,"chapter":85,"chapters":[85],"q":"Что обозначает вертикальная дорожная разметка, изображённая на рисунке?","a":["Нижний край пролетного строения мостов, путепроводов и эстакад.","Сигнальные щитки, установленные на барьерных ограждениях дорог.","Круглые тумбы, установленные на разделительных полосах или островках безопасности.","Вертикальные элементы дорожных сооружений, если эти элементы представляют опасность для движения транспортных средств."],"c":2,"e":"<p>Показанная на рисунке вертикальная дорожная разметка 2.3 применяется для обозначения круглых тумб, установленных на разделительных полосах или островках безопасности.</p>","image":"assets/adrive-questions/q300300401.webp"},{"id":300300402,"themeId":2,"group":3003004,"chapter":85,"chapters":[85],"q":"В каких местах на дороге устанавливаются круглые тумбы с вертикальной дорожной разметкой, изображённой на рисунке?","a":["В начале разделительных зон.","На тротуарах в месте расположения велопарковок.","На разделительных полосах или островках безопасности.","На обочинах на закруглениях дорог, имеющих высокий обрыв.","В местах для стоянки автомобилей как разделитель парковочных мест."],"c":2,"e":"<p>Показанная на рисунке вертикальная дорожная разметка 2.3 наносится на круглые тумбы, установленные на разделительных полосах или островках безопасности.</p>","image":"assets/adrive-questions/q300300402.webp"},{"id":300300501,"themeId":2,"group":3003005,"chapter":85,"chapters":[85],"q":"Что может обозначать вертикальная дорожная разметка, изображённая на рисунке?","a":["Только надолбы.","Только опоры ограждений.","Только сигнальные столбики.","Всё перечисленное."],"c":3,"e":"<p>Показанная на рисунке вертикальная дорожная разметка 2.4.1, 2.4.2 применяется для обозначения сигнальных столбиков, надолбов, опор ограждений и тому подобного.</p>","image":"assets/adrive-questions/q300300501.webp"},{"id":300300502,"themeId":2,"group":3003005,"chapter":85,"chapters":[85],"q":"С какой стороны от проезжей части дороги устанавливаются сигнальные столбики с показанной на рисунке вертикальной дорожной разметкой?","a":["Слева.","Справа.","Как справа, так и слева."],"c":1,"e":"<p>Показанная на рисунке вертикальная дорожная разметка 2.4.1 применяется справа от проезжей части дороги.</p>","image":"assets/adrive-questions/q300300502.webp"},{"id":300300601,"themeId":2,"group":3003006,"chapter":85,"chapters":[85],"q":"С какой стороны от проезжей части дороги устанавливаются сигнальные столбики с показанной на рисунке вертикальной дорожной разметкой?","a":["Слева.","Справа.","Как справа, так и слева."],"c":0,"e":"<p>Показанная на рисунке вертикальная дорожная разметка 2.4.2 применяется слева от проезжей части дороги.</p>","image":"assets/adrive-questions/q300300601.webp"},{"id":300300602,"themeId":2,"group":3003006,"chapter":85,"chapters":[85],"q":"Под каким номером на рисунке изображён сигнальный столбик?","a":["Под номером 1.","Под номером 2.","Под номером 3.","Под номером 4.","Под номером 5."],"c":1,"e":"<p>На рисунке под номером 2 изображён сигнальный столбик (вертикальная дорожная разметка 2.4.2 ).</p>","image":"assets/adrive-questions/q300300602.webp"},{"id":300300701,"themeId":2,"group":3003007,"chapter":85,"chapters":[85],"q":"Под каким номером на рисунке изображён сигнальный щиток, устанавливаемый на барьерном ограждении дороги?","a":["Под номером 1.","Под номером 2.","Под номером 3.","Под номером 4.","Под номером 5."],"c":2,"e":"<p>На рисунке под номером 3 изображён сигнальный щиток (вертикальная дорожная разметка 2.4.3 ), устанавливаемый на барьерном ограждении дороги.</p>","image":"assets/adrive-questions/q300300701.webp"},{"id":300300702,"themeId":2,"group":3003007,"chapter":85,"chapters":[85],"q":"Что обозначает показанная на рисунке вертикальная дорожная разметка?","a":["Сигнальные щитки, установленные на барьерных ограждениях дорог.","Сигнальные столбики, расположенные справа от проезжей части дороги.","Круглые тумбы, установленные на разделительных полосах или островках безопасности."],"c":0,"e":"<p>Показанная на рисунке вертикальная дорожная разметка 2.4.3 применяется для обозначения сигнальных щитков, установленных на барьерных ограждениях дорог.</p>","image":"assets/adrive-questions/q300300702.webp"},{"id":300300801,"themeId":2,"group":3003008,"chapter":85,"chapters":[85],"q":"Что обозначает вертикальная дорожная разметка, показанная на рисунке?","a":["Боковые поверхности дорожных ограждений на опасных участках дорог.","Боковые поверхности начальных и конечных участков дорожных ограждений.","Боковые поверхности дорожных ограждений в местах, где запрещена остановка.","Боковые поверхности дорожных ограждений на закруглениях дорог малого радиуса закругления."],"c":1,"e":"<p>Показанная на рисунке вертикальная дорожная разметка 2.5 применяется для обозначения боковых поверхностей начальных и конечных участков дорожных ограждений.</p>","image":"assets/adrive-questions/q300300801.webp"},{"id":300300802,"themeId":2,"group":3003008,"chapter":85,"chapters":[85],"q":"Что обозначает вертикальная дорожная разметка, нанесённая на боковую поверхность дорожного ограждения, показанная на рисунке?","a":["Только конечный участок дорожного ограждения.","Только начальный участок дорожного ограждения.","Начальный и конечный участки дорожного ограждения."],"c":2,"e":"<p>Показанная на рисунке вертикальная дорожная разметка 2.5 применяется для обозначения боковых поверхностей начальных и конечных участков дорожных ограждений.</p>","image":"assets/adrive-questions/q300300802.webp"},{"id":300300803,"themeId":2,"group":3003008,"chapter":85,"chapters":[85],"q":"Что обозначает показанная вертикальная дорожная разметка?","a":["Боковые поверхности дорожных ограждений на опасных участках дорог.","Боковые поверхности начальных и конечных участков дорожных ограждений.","Боковые поверхности дорожных ограждений в местах, где запрещена остановка транспортных средств."],"c":1,"e":"<p>Показанная вертикальная дорожная разметка 2.5 в виде чередующихся фрагментов чёрного и белого цвета применяется для обозначения боковых поверхностей начальных и конечных участков дорожных ограждений.</p>","image":"assets/adrive-questions/q300300803.webp"},{"id":300300901,"themeId":2,"group":3003009,"chapter":85,"chapters":[85],"q":"Что означает вертикальная дорожная разметка, показанная на рисунке?","a":["Место, где запрещена стоянка.","Место, где запрещена остановка.","Бордюр на опасном участке дороги."],"c":2,"e":"<p>Показанная на рисунке вертикальная дорожная разметка 2.6 применяется для обозначения бордюров на опасных участках дороги.</p>","image":"assets/adrive-questions/q300300901.webp"},{"id":300300902,"themeId":2,"group":3003009,"chapter":85,"chapters":[85],"q":"Показанная на рисунке вертикальная дорожная разметка наносится на бордюр:","a":["Только на опасных участках дороги.","Только на возвышающихся островках безопасности.","Во всех перечисленных местах."],"c":2,"e":"<p>Показанная на рисунке вертикальная дорожная разметка 2.6 наносится на бордюр на опасных участках дороги и на возвышающихся островках безопасности.</p>","image":"assets/adrive-questions/q300300902.webp"}];